// Apura a Boa Permanência de uma folha SALVA no fechamento (sem o formulário).
// Como a bonificação é BENEFÍCIO (pago no VR, fora do salário/impostos), só
// precisa setar o campo `bonificacao` — não mexe em totalBruto/INSS/IRRF/líquido.
// Retorna {bonificacao} a atualizar, ou null se não mudou. Usado no LOTE.
function _apurarBonusFolha(p, emp, cct){
  if(!p || !emp) return null;
  const sempreP = !!emp.bonificacaoSemprePagar;
  const faltas  = (p.faltasInjustificadas||0)+(p.faltasJustificadas||0);
  const bonusNew = (sempreP || faltas===0) ? ((cct && cct.bonificacao) || 0) : 0;
  if(Math.abs((p.bonificacao||0) - bonusNew) < 0.005) return null; // sem mudança
  return { bonificacao: bonusNew };
}

async function _executarFechamentoPeriodo(mes,ano,key,conf,automatico){
  const folhasAbertas=State.payrolls.filter(p=>p.mes==mes&&p.ano==ano&&p.status!=='fechada');
  const agora=new Date().toISOString();
  try{
    // Ao fechar, apura a Boa Permanência de cada folha (recompõe bruto/encargos/
    // líquido se o bônus mudou) e marca como fechada — tudo no mesmo merge.
    await Promise.all(folhasAbertas.map(p=>{
      const emp = State.employees.find(e=>e.id===p.employeeId);
      const upd = { status:'fechada', fechadoEm:agora };
      const recalc = (emp && !emp.isentoPonto) ? _apurarBonusFolha(p, emp, State.cct) : null;
      if(recalc) Object.assign(upd, recalc);
      return DB.merge('payrolls',p.id,upd).then(()=>{
        const s=State.payrolls.find(r=>r.id===p.id); if(s) Object.assign(s, upd);
      });
    }));
    const novaConf={...conf,fechado:true,fechadoEm:agora,updatedAt:agora};
    await DB.saveDoc('configuracoes',`fechamento_${key}`,novaConf,true);
    State.confFolha=State.confFolha||{};
    State.confFolha[key]=novaConf;
    const msg=automatico
      ? `Fechamento automático: ${folhasAbertas.length} folha(s) de ${MESES[mes]}/${ano} fechadas.`
      : `${folhasAbertas.length} folha(s) de ${MESES[mes]}/${ano} fechadas com sucesso.`;
    toast(msg);
    Auth.log('PAYROLL_PERIODO_FECHADO',null,`${MESES[mes]}/${ano} — ${folhasAbertas.length} folhas`);
    _updatePainelFechamento(mes,ano);
    // Atualizar status badge da folha atual se estiver carregada
    _updateFolhaStatusBadge();
    // Atalho 'Avançar pro próximo período' — só pergunta no fechamento MANUAL
    // (automático é silencioso); só faz sentido se a competência fechada é a
    // vigente OU histórica (não pergunta pra futura — não tem sentido avançar
    // pra mais futuro ainda).
    if(!automatico){
      const st = statusCompetencia(mes, ano);
      if(st !== 'futura'){
        let novoMes = mes + 1, novoAno = ano;
        if(novoMes > 12){ novoMes = 1; novoAno++; }
        // Pergunta após 500ms pra não competir com o toast
        setTimeout(() => {
          if(confirm(`✅ ${MESES[mes]}/${ano} foi fechada com sucesso!\n\nAvançar agora para a próxima competência (${MESES[novoMes]}/${novoAno})?`)){
            setVal('payroll-mes', String(novoMes));
            setVal('payroll-ano', String(novoAno));
            onPayrollPeriodoChange();
          }
        }, 500);
      }
    }
  }catch(e){ toast('Erro ao fechar período.','error'); console.error(e); }
}

async function fecharFolhaIndividual(){
  const empId=val('payroll-employee');
  const emp=State.employees.find(e=>e.id===empId);
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  if(!empId||!emp){ toast('Selecione um colaborador.','error'); return; }
  const p=State.payrolls.find(r=>r.employeeId===empId&&r.mes==mes&&r.ano==ano);
  if(!p){ toast('Salve o lançamento antes de fechar.','error'); return; }
  if(p.status==='fechada'){ toast('Esta folha já está fechada.','warning'); return; }
  if(!confirm(`Fechar a folha de ${emp.nome} — ${MESES[mes]}/${ano}?\n\nA folha ficará bloqueada para edição. Você poderá reabrir se necessário.`)) return;
  try{
    const agora=new Date().toISOString();
    // Apura a Boa Permanência NO FECHAMENTO: com o flag ligado, o recalculate
    // libera a bonificação (se sem faltas no mês) e o savePayroll persiste o
    // valor + totais. Só depois a folha é marcada como fechada.
    if(val('payroll-employee')===empId){
      _fechandoFolha = true;
      try { recalculate(); await savePayroll(); }
      finally { _fechandoFolha = false; }
    }
    await DB.merge('payrolls',p.id,{status:'fechada',fechadoEm:agora});
    const s=State.payrolls.find(r=>r.id===p.id); if(s){ s.status='fechada'; s.fechadoEm=agora; }
    Auth.log('PAYROLL_FECHADO_INDIVIDUAL',null,`${emp.nome} — ${MESES[mes]}/${ano}`);
    toast(`Folha de ${emp.nome} fechada.`);
    _updateFolhaStatusBadge();
  }catch(e){ toast('Erro ao fechar folha.','error'); console.error(e); }
}

async function reabrirFolha(){
  const empId=val('payroll-employee');
  const emp=State.employees.find(e=>e.id===empId);
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  if(!empId||!emp){ toast('Selecione um colaborador.','error'); return; }
  const p=State.payrolls.find(r=>r.employeeId===empId&&r.mes==mes&&r.ano==ano);
  if(!p){ toast('Folha não encontrada.','error'); return; }
  if(!confirm(`Reabrir a folha de ${emp.nome} — ${MESES[mes]}/${ano}?\n\nA folha voltará a ser editável. O período geral continuará fechado para os demais.`)) return;
  try{
    await DB.merge('payrolls',p.id,{status:'aberta',reabertoEm:new Date().toISOString()});
    const s=State.payrolls.find(r=>r.id===p.id); if(s) s.status='aberta';
    Auth.log('PAYROLL_REABERTO',null,`${emp.nome} — ${MESES[mes]}/${ano}`);
    toast(`Folha de ${emp.nome} reaberta para edição.`);
    _updateFolhaStatusBadge();
  }catch(e){ toast('Erro ao reabrir folha.','error'); }
}

// ============================================
// BACKFILL — preenche folhas do período com as horas previstas
// ============================================
// Ação ÚNICA usada na virada para o modelo de competência (fecha dia 25).
// Botão removido da UI em 2026-05-30 (migração já concluída). Função preservada
// caso precise restaurar o botão pra novo cliente no futuro.
async function backfillFolhasPeriodo(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o usuário master pode rodar o preenchimento do período.','error'); return; }
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  const per=_compPeriodo(mes,ano);
  const compDias=_compDias(mes,ano);
  const zp=n=>String(n).padStart(2,'0');
  const emps=_filtrarEmpsPorEscopo((State.employees||[]).filter(e=>(e.status||'ativo')==='ativo' && !e.isentoPonto));
  if(!emps.length){ toast('Nenhum colaborador ativo no escopo.','error'); return; }
  if(!confirm(`Preencher automaticamente as folhas de ${emps.length} colaborador(es) na competência ${MESES[mes]}/${ano} (${_compLabel(mes,ano)})?\n\n• Projeta as horas previstas (escala/cadastro) nos dias SEM ponto real, até a 1ª batida de cada colaborador.\n• Dias com ponto batido NÃO são tocados.\n• Recomendado: fazer backup antes.\n\nContinuar?`)) return;

  let nFolhas=0, nDias=0, nPulados=0;
  for(const emp of emps){
    if(_cadastroPendencias(emp).length){ nPulados++; continue; }
    const admISO=(emp.dataAdmissao||'').substring(0,10);
    if(admISO && admISO>per.ateISO){ nPulados++; continue; }          // admitido depois do período
    const effStartISO=(admISO && admISO>per.deISO) ? admISO : per.deISO;

    const reg=State.payrolls.find(p=>p.employeeId===emp.id&&p.mes==mes&&p.ano==ano);
    const dias=reg?.pontoManualDias ? [...reg.pontoManualDias] : [];

    // 1ª batida REAL (app/manual) — entradas de backfill anteriores não contam.
    let firstPunchISO=null;
    dias.forEach(d=>{
      if(!d||!d.entrada || (d.entrada_origem||'')==='backfill') return;
      const rd=_compRealDate(mes,ano,d.dia);
      const iso=`${rd.ano}-${zp(rd.mes)}-${zp(rd.dia)}`;
      if(!firstPunchISO || iso<firstPunchISO) firstPunchISO=iso;
    });

    let mudou=false;
    for(const cd of compDias){
      const iso=`${cd.ano}-${zp(cd.mes)}-${zp(cd.dia)}`;
      if(iso<effStartISO) continue;                       // antes da admissão / início do período
      if(firstPunchISO && iso>=firstPunchISO) continue;   // a partir da 1ª batida, vale o ponto real
      const ex=dias.find(x=>x.dia===cd.dia);
      if(ex && ex.entrada && (ex.entrada_origem||'')!=='backfill') continue; // não toca batida real
      const exp=_getExpectedDay(emp,cd.mes,cd.ano,cd.dia);
      if(!exp || exp.tipo==='folga' || !exp.entrada) continue;              // folga / sem expediente
      const novo={
        dia:cd.dia, diaSem:cd.diaSem,
        entrada:exp.entrada||'', saida:exp.saida||'',
        intIni:exp.intIni||'', intFim:exp.intFim||'',
        entrada_origem:'backfill', saida_origem:'backfill',
        intIni_origem:'backfill', intFim_origem:'backfill'
      };
      const ix=dias.findIndex(x=>x.dia===cd.dia);
      if(ix>=0) dias[ix]={...dias[ix], ...novo}; else dias.push(novo);
      mudou=true; nDias++;
    }
    if(!mudou) continue;

    // Recalcula totais básicos (dias/faltas/HE). Salário/benefícios são apurados
    // ao abrir/fechar a folha (recalculate) e pela tela de Benefícios a Pagar.
    const diasTrab=dias.filter(d=>d.entrada&&d.saida).length;
    const fam=escalaFamilia(emp.escala||'5x2A'); const is12=fam==='12x36';
    let faltas=0;
    for(const cd of compDias){
      const has=dias.find(x=>x.dia===cd.dia);
      if(has && has.entrada && has.saida) continue;
      const isWk=cd.diaSem===0||cd.diaSem===6;
      if(_diaEmBrancoEhFalta(emp,cd.mes,cd.ano,cd.dia,isWk,is12)) faltas++;
    }
    const heMin=_heMinFromDias(emp,mes,ano,dias);
    const base={ pontoManualDias:dias, diasTrabalhados:diasTrab,
      faltasInjustificadas:faltas, faltasJustificadas:(reg?.faltasJustificadas||0),
      horasExtrasTotal:(heMin>0?+(heMin/60).toFixed(2):0), updatedAt:new Date().toISOString() };
    const record = reg ? {...reg, ...base}
      : { id:genId(), employeeId:emp.id, mes, ano, createdAt:new Date().toISOString(), ...base };
    try{
      await DB.save('payrolls', _sanitizeForFirestore(record));
      const ix=State.payrolls.findIndex(p=>p.id===record.id);
      if(ix>=0) State.payrolls[ix]=record; else State.payrolls.push(record);
      nFolhas++;
    }catch(e){ console.error('backfill save', emp.nome, e); }
  }
  try{ Auth.log('BACKFILL_PERIODO', null, `${MESES[mes]}/${ano} — ${nFolhas} folha(s), ${nDias} dia(s)`); }catch(_){}
  toast(`Backfill concluído: ${nFolhas} folha(s), ${nDias} dia(s) projetado(s)${nPulados?` · ${nPulados} pulado(s) (cadastro incompleto ou admissão fora do período)`:''}.`, 'success');
  if(val('payroll-employee')) onPayrollEmployeeChange();
  try{ renderDashboard(); }catch(_){}
}

// ============================================
// LIMPAR DIAS DE BACKFILL — remove só os dias projetados (origem 'backfill')
// ============================================
// Desfaz o preenchimento automático: tira das folhas da competência os dias que
// são PURAMENTE projetados (todos os campos com origem 'backfill') e NÃO têm
// nenhuma batida real (app/manual). Preserva 100% das batidas reais. Use quando
// optar por preencher o ponto manualmente. Não toca folhas FECHADAS.
async function limparBackfillPeriodo(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o usuário master pode rodar a limpeza.','error'); return; }
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  const ehBackfill=d=>{
    const og=['entrada','saida','intIni','intFim'].map(k=>d[k+'_origem']).filter(Boolean);
    const temReal=og.some(o=>o==='app'||o==='manual');
    const temBack=og.some(o=>o==='backfill');
    return temBack && !temReal;     // só dias 100% projetados, sem batida real
  };
  const afetadas=(State.payrolls||[]).filter(p=>p.mes==mes&&p.ano==ano&&Array.isArray(p.pontoManualDias)&&p.pontoManualDias.some(ehBackfill));
  if(!afetadas.length){ toast('Nenhum dia de backfill encontrado nesta competência. Nada a limpar.','info'); return; }
  const fechadas=afetadas.filter(p=>p.status==='fechada');
  if(fechadas.length){ toast(`${fechadas.length} folha(s) FECHADA(s). Reabra antes de limpar o backfill.`,'error'); return; }
  const totalDias=afetadas.reduce((s,p)=>s+p.pontoManualDias.filter(ehBackfill).length,0);
  if(!confirm(`Remover ${totalDias} dia(s) projetado(s) pelo backfill de ${afetadas.length} folha(s) — ${MESES[mes]}/${ano}?\n\n• Remove SÓ os dias 100% projetados (origem 'backfill').\n• Batidas reais (app/manual) são preservadas.\n• Depois você preenche o ponto manualmente.\n\nContinuar?`)) return;
  let nF=0, nD=0;
  for(const p of afetadas){
    const emp=State.employees.find(e=>e.id===p.employeeId);
    if(!emp) continue;
    const dias=p.pontoManualDias.filter(d=>!ehBackfill(d));
    nD += (p.pontoManualDias.length - dias.length);
    // Recalcula totais com os dias restantes
    const diasTrab=dias.filter(d=>d.entrada&&d.saida).length;
    const fam=escalaFamilia(emp.escala||'5x2A'); const is12=fam==='12x36';
    let faltas=0;
    for(const cd of _compDias(mes,ano)){
      const has=dias.find(x=>x.dia===cd.dia);
      if(has && has.entrada && has.saida) continue;
      const isWk=cd.diaSem===0||cd.diaSem===6;
      if(_diaEmBrancoEhFalta(emp,cd.mes,cd.ano,cd.dia,isWk,is12)) faltas++;
    }
    const heMin=_heMinFromDias(emp,mes,ano,dias);
    const base={ pontoManualDias:dias, diasTrabalhados:diasTrab,
      faltasInjustificadas:faltas, faltasJustificadas:(p.faltasJustificadas||0),
      horasExtrasTotal:(heMin>0?+(heMin/60).toFixed(2):0), updatedAt:new Date().toISOString() };
    const record={...p, ...base};
    try{
      await DB.save('payrolls', _sanitizeForFirestore(record));
      const ix=State.payrolls.findIndex(r=>r.id===record.id);
      if(ix>=0) State.payrolls[ix]=record;
      nF++;
    }catch(e){ console.error('limpar backfill', emp.nome, e); }
  }
  try{ Auth.log('LIMPAR_BACKFILL', null, `${MESES[mes]}/${ano} — ${nF} folha(s), ${nD} dia(s)`); }catch(_){}
  toast(`Limpeza concluída: ${nD} dia(s) de backfill removido(s) de ${nF} folha(s). Pode preencher o ponto manualmente.`, 'success');
  if(val('payroll-employee')) onPayrollEmployeeChange();
  try{ renderDashboard(); }catch(_){}
}

// ============================================
// RECALCULAR FALTAS EM MASSA — corrige faltasInjustificadas inflado pelo
// backfill (especialmente 12x36 sem âncora antes do fix de 2026-05-30).
// Recomputa `faltasInjustificadas` baseado no estado ATUAL da folha:
//   - Para cada dia previsto de trabalho (escala) sem ponto batido,
//     conta como falta SE `_diaEmBrancoEhFalta` retornar true.
// Preserva `faltasJustificadas` (lançadas manualmente pelo usuário).
// Salva mesmo em folhas FECHADAS (admin-only, master-only).
// Reset visível no BP — quem ficou em 0+0 vira elegível na próxima leitura.
// ============================================
async function recalcularFaltasCompetencia(mesArg, anoArg){
  // Feedback IMEDIATO no clique — pra confirmar que a função foi chamada.
  // (antes ficava silencioso até o confirm, dando impressão de 'não funciona')
  toast('Iniciando recalculo de faltas...','info');
  console.log('[recalcularFaltasCompetencia] iniciado', { mesArg, anoArg, user: Auth.currentUser?.username, role: Auth.currentUser?.role });
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o usuário master pode rodar o recalculo.','error'); return; }
  // Aceita mes/ano via argumento OU lê dos inputs OU usa o currentMes/Ano.
  // Argumentos têm prioridade pra evitar bug quando chamado de fora da tela
  // de Folha de Ponto (Benefícios, p.ex.) onde os inputs não existem.
  let mes = parseInt(mesArg || val('payroll-mes') || currentMes());
  let ano = parseInt(anoArg || val('payroll-ano') || currentAno());
  console.log('[recalcularFaltasCompetencia] competência alvo:', mes, ano);
  const afetadas=(State.payrolls||[]).filter(p=>p.mes==mes&&p.ano==ano);
  console.log('[recalcularFaltasCompetencia] folhas encontradas:', afetadas.length);
  if(!afetadas.length){
    toast(`Nenhuma folha encontrada em ${MESES[mes]}/${ano}. Verifique se a competência tem folhas salvas.`,'warning');
    return;
  }
  if(!confirm(`Recalcular FALTAS INJUSTIFICADAS de ${afetadas.length} folha(s) da competência ${MESES[mes]}/${ano} (${_compLabel(mes,ano)})?\n\n• Recalcula com base no estado ATUAL da folha (dias batidos vs escala).\n• Preserva 'faltasJustificadas' (lançadas manualmente).\n• Roda mesmo em folhas FECHADAS.\n• Útil quando o backfill inflou as faltas (12x36 sem âncora, escala antiga errada etc.).\n\nDepois disso, quem tiver 0 falta volta a receber Boa Permanência.\n\nContinuar?`)) return;
  let nAlteradas=0, nMantidas=0, nReduziu=0;
  const compDias=_compDias(mes,ano);
  for(const p of afetadas){
    const emp=State.employees.find(e=>e.id===p.employeeId);
    if(!emp) continue;
    const dias = Array.isArray(p.pontoManualDias)? p.pontoManualDias : [];
    const fam=escalaFamilia(emp.escala||'5x2A'); const is12=fam==='12x36';
    let novasFaltas=0;
    for(const cd of compDias){
      const has=dias.find(x=>x.dia===cd.dia);
      if(has && has.entrada && has.saida) continue;  // dia batido → não conta
      const isWk=cd.diaSem===0||cd.diaSem===6;
      if(_diaEmBrancoEhFalta(emp,cd.mes,cd.ano,cd.dia,isWk,is12)) novasFaltas++;
    }
    const antigas = p.faltasInjustificadas||0;
    if(novasFaltas === antigas){ nMantidas++; continue; }
    if(novasFaltas < antigas) nReduziu++;
    const record={...p, faltasInjustificadas:novasFaltas, updatedAt:new Date().toISOString()};
    try{
      await DB.save('payrolls', _sanitizeForFirestore(record));
      const ix=State.payrolls.findIndex(r=>r.id===record.id);
      if(ix>=0) State.payrolls[ix]=record;
      nAlteradas++;
    }catch(e){ console.error('recalc faltas', emp.nome, e); }
  }
  try{ Auth.log('RECALC_FALTAS', null, `${MESES[mes]}/${ano} — ${nAlteradas} folha(s) alterada(s), ${nReduziu} com redução, ${nMantidas} sem mudança`); }catch(_){}
  toast(`Recalculo concluído: ${nAlteradas} folha(s) alterada(s) (${nReduziu} com redução de faltas) · ${nMantidas} sem mudança. Reabra a tela de Benefícios pra ver o efeito na Boa Permanência.`, 'success');
  if(val('payroll-employee')) onPayrollEmployeeChange();
  try{ renderDashboard(); }catch(_){}
}

// ============================================
// REPROJETAR DIAS MIGRADOS (26-31) — correção em lote da virada
// ============================================
// Ação ÚNICA da virada: a migração trouxe os dias 26-31 do mês anterior com o
// horário ANTIGO (ex.: 08-17 de uma projeção antiga). Esta função REESCREVE só os
// dias 26-31 de todas as folhas da competência usando a escala ATUAL de cada
// colaborador (5x2→08-17, 12x36→07-19 etc.). Os dias 1-25 (batidas reais do mês)
// NÃO são tocados. Reversível via backup.
async function reprojetarDiasMigrados(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o usuário master pode rodar.','error'); return; }
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  const compDias=_compDias(mes,ano);
  const emps=_filtrarEmpsPorEscopo((State.employees||[]).filter(e=>(e.status||'ativo')==='ativo' && !e.isentoPonto));
  const afetadas=(State.payrolls||[]).filter(p=>p.mes==mes&&p.ano==ano&&Array.isArray(p.pontoManualDias)&&p.pontoManualDias.some(d=>parseInt(d.dia)>=26)&&emps.some(e=>e.id===p.employeeId));
  if(!afetadas.length){ toast('Nenhuma folha com dias 26-31 nesta competência. Nada a reprojetar.','info'); return; }
  const fechadas=afetadas.filter(p=>p.status==='fechada');
  if(fechadas.length){ toast(`${fechadas.length} folha(s) FECHADA(s). Use "Reabrir Todas as Folhas" antes de reprojetar.`,'error'); return; }
  if(!confirm(`Reprojetar os dias 26-31 (vindos do mês anterior pela migração) de ${afetadas.length} folha(s) — ${MESES[mes]}/${ano}?\n\n• Esses dias serão REESCRITOS com a escala atual de cada colaborador (5x2 → 08-17, 12x36 → 07-19 etc.).\n• Os dias 1-25 (batidas reais do mês) NÃO são tocados.\n• Ação de virada (use uma vez). Faça backup antes.\n\nContinuar?`)) return;
  let nF=0, nD=0;
  for(const p of afetadas){
    const emp=emps.find(e=>e.id===p.employeeId);
    if(!emp || _cadastroPendencias(emp).length) continue;
    // Mantém dias 1-25 (batidas reais); reprojeta os dias 26-31 pela escala atual.
    const dias=p.pontoManualDias.filter(d=>parseInt(d.dia)<26);
    for(const cd of compDias){
      if(cd.dia<26) continue;
      const exp=_getExpectedDay(emp,cd.mes,cd.ano,cd.dia);
      if(!exp || exp.tipo==='folga' || !exp.entrada) continue; // folga / sem expediente
      dias.push({ dia:cd.dia, diaSem:cd.diaSem,
        entrada:exp.entrada||'', saida:exp.saida||'',
        intIni:exp.intIni||'', intFim:exp.intFim||'',
        entrada_origem:'backfill', saida_origem:'backfill',
        intIni_origem:'backfill', intFim_origem:'backfill' });
      nD++;
    }
    const diasTrab=dias.filter(d=>d.entrada&&d.saida).length;
    const fam=escalaFamilia(emp.escala||'5x2A'); const is12=fam==='12x36';
    let faltas=0;
    for(const cd of compDias){
      const has=dias.find(x=>x.dia===cd.dia);
      if(has && has.entrada && has.saida) continue;
      const isWk=cd.diaSem===0||cd.diaSem===6;
      if(_diaEmBrancoEhFalta(emp,cd.mes,cd.ano,cd.dia,isWk,is12)) faltas++;
    }
    const heMin=_heMinFromDias(emp,mes,ano,dias);
    const base={ pontoManualDias:dias, diasTrabalhados:diasTrab,
      faltasInjustificadas:faltas, faltasJustificadas:(p.faltasJustificadas||0),
      horasExtrasTotal:(heMin>0?+(heMin/60).toFixed(2):0), updatedAt:new Date().toISOString() };
    const record={...p, ...base};
    try{
      await DB.save('payrolls', _sanitizeForFirestore(record));
      const ix=State.payrolls.findIndex(r=>r.id===record.id);
      if(ix>=0) State.payrolls[ix]=record;
      nF++;
    }catch(e){ console.error('reprojetar migrados', emp.nome, e); }
  }
  try{ Auth.log('REPROJETAR_DIAS_MIGRADOS', null, `${MESES[mes]}/${ano} — ${nF} folha(s), ${nD} dia(s)`); }catch(_){}
  toast(`Reprojeção concluída: ${nF} folha(s), ${nD} dia(s) 26-31 reescritos com a escala correta. Confira alguns 12x36.`, 'success');
  if(val('payroll-employee')) onPayrollEmployeeChange();
  try{ renderDashboard(); }catch(_){}
}

// ============================================
// MIGRAÇÃO ÚNICA — calendário → competência (fecha dia 25)
// ============================================
// Antes do modelo de competência as batidas eram gravadas por MÊS DE CALENDÁRIO
// ({mes,ano}=mês do calendário, dia=dia do mês). No novo modelo {mes,ano} é o
// RÓTULO da competência e os dias 26-31 pertencem ao mês ANTERIOR. Logo os dias
// 26-31 já gravados precisam migrar para a folha da competência do mês SEGUINTE
// (ex.: maio 26-31, hoje em {mes:5}, vão para a competência junho {mes:6}).
// Roda UMA vez (marcador em configuracoes/migracao_competencia). Reversível via
// backup. NÃO altera folhas FECHADAS — aborta e pede reabertura.
async function migrarParaCompetencia(){
  if(Auth.currentUser?.role!=='master'){ toast('Apenas o usuário master pode rodar a migração.','error'); return; }
  const GKEY='migracao_competencia';
  try{
    const g=await DB.getDoc('configuracoes', GKEY);
    if(g && g.feitoEm){ toast(`Migração já realizada em ${new Date(g.feitoEm).toLocaleDateString('pt-BR')}. Não rode de novo — bagunçaria os dados.`,'warning'); return; }
  }catch(e){ console.warn('guard migração', e); }

  const zp=n=>String(n).padStart(2,'0');
  const hojeISO=new Date().toISOString().substring(0,10);
  // Snapshot imutável: clona os dias de cada folha ANTES de qualquer escrita.
  const snap=(State.payrolls||[]).filter(p=>Array.isArray(p.pontoManualDias))
    .map(p=>({employeeId:p.employeeId, mes:parseInt(p.mes), ano:parseInt(p.ano),
              dias:p.pontoManualDias.map(d=>({...d}))}));
  const snapDe=(eId,m,a)=>snap.find(s=>s.employeeId===eId&&s.mes===m&&s.ano===a);

  const comDias2631=snap.filter(s=>s.dias.some(d=>d && parseInt(d.dia)>=26));
  if(!comDias2631.length){ toast('Nenhuma folha com dias 26-31. Nada a migrar.','info'); return; }

  // Folhas que serão recompostas: as próprias fontes (perdem 26-31) + a
  // competência do mês seguinte de cada uma (recebe 26-31).
  const alvos=new Map();
  const addAlvo=(eId,m,a)=>alvos.set(`${eId}|${m}|${a}`, {employeeId:eId, mes:m, ano:a});
  for(const s of comDias2631){
    addAlvo(s.employeeId, s.mes, s.ano);
    let dm=s.mes+1, da=s.ano; if(dm>12){ dm=1; da=s.ano+1; }
    addAlvo(s.employeeId, dm, da);
  }

  // Segurança: nenhuma folha afetada pode estar FECHADA.
  const fechadas=[];
  for(const {employeeId,mes,ano} of alvos.values()){
    const d=(State.payrolls||[]).find(p=>p.employeeId===employeeId&&p.mes==mes&&p.ano==ano);
    if(d && d.status==='fechada') fechadas.push(d);
  }
  if(fechadas.length){
    const lista=fechadas.map(p=>{const e=State.employees.find(x=>x.id===p.employeeId);return `${e?e.nome:p.employeeId} ${MESES[p.mes]}/${p.ano}`;}).slice(0,8).join(', ');
    toast(`Migração abortada: ${fechadas.length} folha(s) FECHADA(s) precisariam mudar (${lista}${fechadas.length>8?'…':''}). Reabra-as antes.`,'error');
    return;
  }

  if(!confirm(`Migrar para o modelo de competência (fecha dia 25)?\n\n• ${comDias2631.length} folha(s) têm dias 26-31, que irão para a competência do mês SEGUINTE.\n• Os dias 1-25 permanecem onde estão.\n• Esta ação roda UMA única vez. Faça backup antes.\n\nContinuar?`)) return;

  let nFolhas=0, nMovidos=0;
  for(const {employeeId,mes,ano} of alvos.values()){
    const emp=State.employees.find(e=>e.id===employeeId);
    // Novos dias = (1-25 da própria competência) + (26-31 do mês anterior).
    let pm=mes-1, pa=ano; if(pm<1){ pm=12; pa=ano-1; }
    const own=snapDe(employeeId,mes,ano);
    const prev=snapDe(employeeId,pm,pa);
    const dias1_25=(own?.dias||[]).filter(d=>d && parseInt(d.dia)<=25);
    const dias26_31=(prev?.dias||[]).filter(d=>d && parseInt(d.dia)>=26);
    nMovidos+=dias26_31.length;
    const novosDias=[...dias1_25, ...dias26_31];

    const reg=(State.payrolls||[]).find(p=>p.employeeId===employeeId&&p.mes==mes&&p.ano==ano);

    // Recalcula totais básicos sobre a competência (faltas só até hoje, pra não
    // inflar competências ainda em andamento). Salário/benefícios são apurados
    // ao abrir/fechar a folha.
    const diasTrab=novosDias.filter(d=>d.entrada&&d.saida).length;
    let faltas=0;
    if(emp){
      const fam=escalaFamilia(emp.escala||'5x2A'); const is12=fam==='12x36';
      for(const cd of _compDias(mes,ano)){
        const isoCd=`${cd.ano}-${zp(cd.mes)}-${zp(cd.dia)}`;
        if(isoCd>hojeISO) continue;
        const has=novosDias.find(x=>x.dia===cd.dia);
        if(has && has.entrada && has.saida) continue;
        const isWk=cd.diaSem===0||cd.diaSem===6;
        if(_diaEmBrancoEhFalta(emp,cd.mes,cd.ano,cd.dia,isWk,is12)) faltas++;
      }
    }
    const heMin=emp?_heMinFromDias(emp,mes,ano,novosDias):0;
    const base={ pontoManualDias:novosDias, diasTrabalhados:diasTrab,
      faltasInjustificadas:faltas, faltasJustificadas:(reg?.faltasJustificadas||0),
      horasExtrasTotal:(heMin>0?+(heMin/60).toFixed(2):0), updatedAt:new Date().toISOString() };
    const record = reg ? {...reg, ...base}
      : { id:genId(), employeeId, mes, ano, status:'aberta', createdAt:new Date().toISOString(), ...base };
    try{
      await DB.save('payrolls', _sanitizeForFirestore(record));
      const ix=State.payrolls.findIndex(p=>p.id===record.id);
      if(ix>=0) State.payrolls[ix]=record; else State.payrolls.push(record);
      nFolhas++;
    }catch(e){ console.error('migração save', emp?.nome, e); }
  }

  try{ await DB.saveDoc('configuracoes', GKEY, {feitoEm:new Date().toISOString(), nFolhas, nMovidos, por:Auth.currentUser?.username||'master'}, true); }catch(e){ console.warn('marcar migração', e); }
  try{ Auth.log('MIGRACAO_COMPETENCIA', null, `${nFolhas} folha(s), ${nMovidos} dia(s) 26-31 movidos`); }catch(_){}
  toast(`Migração concluída: ${nFolhas} folha(s) recompostas, ${nMovidos} dia(s) (26-31) movidos para a competência seguinte.`, 'success');
  if(val('payroll-employee')) onPayrollEmployeeChange();
  try{ renderDashboard(); }catch(_){}
}

// ============================================
// ASAAS — PAGAMENTO DE COLABORADORES VIA PIX
// ============================================

// Utilitários de chamada ao Worker
async function _asaasReq(method, path, body) {
  const opts = { method, headers: { 'Content-Type': 'application/json' } };
  if (body) opts.body = JSON.stringify(body);
  const r = await fetch(ASAAS_WORKER + path, opts);
  const data = await r.json().catch(() => ({}));
  if (!r.ok) {
    const msg = data.errors?.[0]?.description || data.description || data.error || r.statusText;
    throw new Error(msg);
  }
  return data;
}
const _asaasPost = (path, body) => _asaasReq('POST', path, body);

// Detecta tipo da chave PIX automaticamente
function detectPixKeyType(key) {
  if (!key) return 'CPF';
  const s = String(key);
  if (s.includes('@')) return 'EMAIL';
  const clean = s.replace(/\D/g, '');
  if (clean.length === 14) return 'CNPJ';
  if (clean.length === 10) return 'PHONE';
  if (clean.length === 11) {
    // 11 dígitos é ambíguo (CPF ou celular). Celular BR = DDD 11-99 com
    // '9' no 1º dígito do número. Casou esse padrão → telefone; senão CPF.
    const ddd = parseInt(clean.slice(0, 2), 10);
    return (ddd >= 11 && ddd <= 99 && clean[2] === '9') ? 'PHONE' : 'CPF';
  }
  return 'EVP';
}

// Formata a chave PIX no padrão que o Asaas espera, conforme o tipo:
// CPF/CNPJ → só dígitos; Celular → +55 + DDD + número; e-mail/aleatória → como está.
function _pixKeyParaAsaas(key, tipo){
  const k = String(key || '').trim();
  if (tipo === 'CPF' || tipo === 'CNPJ') return k.replace(/\D/g, '');
  if (tipo === 'PHONE') {
    if (k.startsWith('+')) return k.replace(/[^\d+]/g, '');
    const d = k.replace(/\D/g, '');
    return (d.length === 10 || d.length === 11) ? '+55' + d : k;
  }
  return k;
}

// Auto-sugere o tipo da chave PIX no cadastro quando ainda não foi escolhido.
function onEmpPixInput(){
  const sel = document.getElementById('emp-pix-tipo');
  if (sel && !sel.value) sel.value = detectPixKeyType(val('emp-pix'));
}

// Abre modal de pagamento para o colaborador atual
function openPagarColaborador() {
  const empId = val('payroll-employee');
  const emp   = State.employees.find(e => e.id === empId);
  if (!emp) { toast('Selecione um colaborador.', 'warning'); return; }

  const mes = parseInt(val('payroll-mes') || currentMes());
  const ano = parseInt(val('payroll-ano') || currentAno());
  const p   = State.payrolls.find(r => r.employeeId === empId && r.mes == mes && r.ano == ano);

  if (!p || p.status !== 'fechada') {
    toast('Feche a folha antes de efetuar o pagamento.', 'warning');
    return;
  }

  const liquido   = p.totalLiquidoFinal || p.totalLiquido || 0;
  const adiant    = p.adiantamento || 0;
  const restante  = Math.max(0, liquido - adiant);
  const pixKey    = emp.chavePix || '';

  // Preenche info
  setEl('asaas-pagar-nome',     emp.nome);
  setEl('asaas-pagar-pix',      pixKey || '(sem chave PIX cadastrada)');
  setEl('asaas-pagar-mes',      `${String(mes).padStart(2,'0')}/${ano}`);
  setEl('asaas-pagar-liquido',  fmtMoney(liquido));
  setEl('asaas-pagar-adiant',   fmtMoney(adiant));
  setEl('asaas-pagar-restante', fmtMoney(restante));

  setVal('asaas-pagar-empid',     empId);
  setVal('asaas-pagar-payrollid', p.id || '');

  // Opções de valor
  const sel = document.getElementById('asaas-pagar-tipo');
  sel.innerHTML = '';
  if (adiant > 0 && adiant !== liquido)
    sel.innerHTML += `<option value="${adiant}">Adiantamento: ${fmtMoney(adiant)}</option>`;
  if (restante > 0)
    sel.innerHTML += `<option value="${restante}" selected>Restante a pagar: ${fmtMoney(restante)}</option>`;
  if (liquido > 0)
    sel.innerHTML += `<option value="${liquido}">Total líquido: ${fmtMoney(liquido)}</option>`;
  sel.innerHTML += `<option value="custom">Outro valor...</option>`;
  onAsaasTipoChange();

  // Data: hoje
  setVal('asaas-pagar-data', new Date().toISOString().split('T')[0]);

  // Tipo de chave
  setVal('asaas-pagar-keytype', emp.chavePixTipo || detectPixKeyType(pixKey));

  // Reset resultado
  const resEl = document.getElementById('asaas-pagar-resultado');
  resEl.innerHTML = '';
  resEl.style.display = 'none';

  const btn = document.getElementById('btn-executar-pagamento');
  btn.style.display = 'inline-flex';
  btn.disabled = !pixKey;
  if (!pixKey) toast('Colaborador sem chave PIX — cadastre em Colaboradores → Benefícios.', 'warning');

  // Já existe solicitação pendente para esta folha?
  const solPend = (State.solicitacoes || []).find(s => s.payrollId === (p.id||'') && s.status === 'pendente');
  if (solPend) {
    btn.style.display = 'none';
    resEl.style.display = 'block';
    resEl.innerHTML = `<div style="background:#FFF8E1;border:1px solid #FFE082;border-radius:8px;padding:12px;font-size:12px;color:#6D4C41">
      <i class="fa-solid fa-hourglass-half"></i> <strong>Solicitação pendente:</strong>
      ${fmtMoney(solPend.valor)} aguardando aprovação em <strong>Aprovações de Pagamentos</strong>.
    </div>`;
    document.getElementById('modal-asaas-pagar').classList.remove('hidden');
    return;
  }

  // Mostrar pagamento anterior se houver
  if (p.pagamentoAsaas) {
    const pag = p.pagamentoAsaas;
    resEl.style.display = 'block';
    resEl.innerHTML = `<div style="background:#FFF8E1;border:1px solid #FFE082;border-radius:8px;padding:12px;font-size:12px;color:#6D4C41">
      <i class="fa-solid fa-circle-info"></i> <strong>Pagamento anterior registrado:</strong>
      ${fmtMoney(pag.asaasValor)} em ${(pag.asaasData||'').split('-').reverse().join('/')} — Status: ${pag.asaasStatus} — ID: ${pag.asaasTransferId}
    </div>`;
  }

  document.getElementById('modal-asaas-pagar').classList.remove('hidden');
}

function onAsaasTipoChange() {
  const sel = document.getElementById('asaas-pagar-tipo'); if (!sel) return;
  const row = document.getElementById('asaas-pagar-custom-row');
  if (row) row.style.display = sel.value === 'custom' ? 'block' : 'none';
}

// Cria uma solicitação de pagamento (status 'pendente'). Nada vai pro Asaas
// aqui — só ao ser aprovada na tela "Aprovações de Pagamentos" (com 2FA).
async function _criarSolicitacaoPagamento(d){
  const u = Auth.currentUser || {};
  const sol = {
    id:            genId(),
    employeeId:    d.employeeId || '',
    employeeNome:  d.employeeNome || '',
    payrollId:     d.payrollId || '',
    valor:         d.valor || 0,
    pixKey:        d.pixKey || '',
    keyType:       d.keyType || 'CPF',
    descricao:     d.descricao || '',
    scheduleDate:  d.scheduleDate || '',
    competencia:   d.competencia || '',
    origem:        d.origem || 'avulso',
    status:        'pendente',
    criadoPor:     u.username || u.id || '',
    criadoPorNome: u.username || '',
    criadoEm:      new Date().toISOString(),
    aprovadoPor:'', aprovadoPorNome:'', aprovadoEm:'',
    asaasTransferId:'', asaasStatus:'', motivoRecusa:'', erro:'',
  };
  await DB.save('solicitacoesPagamento', sol);
  return sol;
}

// ============================================
// PAGAMENTO AVULSO — prêmios, obrigações fora do hall legal e valores
// de rescisões feitas fora do sistema. Gera uma solicitação PIX que vai
// para Aprovações (com 2FA), origem 'avulso'. NÃO entra no cálculo da
// folha CLT — é um pagamento à parte.
// ============================================
function openPagamentoAvulsoModal(empId){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para lançar pagamentos.','error'); return;
  }
  const m=document.getElementById('modal-pagamento-avulso'); if(!m) return;
  const sel=document.getElementById('pag-avulso-emp');
  if(sel){
    const emps=[...(State.employees||[])].sort((a,b)=>(a.nome||'').localeCompare(b.nome||'','pt-BR'));
    sel.innerHTML='<option value="">— selecione —</option>'+emps.map(e=>{
      const st=(e.status||'ativo')!=='ativo'?` (${e.status})`:'';
      return `<option value="${e.id}">${(e.nome||'—')}${st}</option>`;
    }).join('');
    sel.value=empId||'';
  }
  setVal('pag-avulso-desc','');
  setVal('pag-avulso-valor','');
  setVal('pag-avulso-data', new Date().toISOString().substring(0,10));
  onPagAvulsoEmpChange();
  m.classList.remove('hidden');
}

function onPagAvulsoEmpChange(){
  const emp=State.employees.find(e=>e.id===val('pag-avulso-emp'));
  setVal('pag-avulso-pix', emp?.chavePix||'');
  setVal('pag-avulso-pix-tipo', (emp&&emp.chavePixTipo) || detectPixKeyType(emp?.chavePix||''));
}

async function confirmarPagamentoAvulso(){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para lançar pagamentos.','error'); return;
  }
  const emp=State.employees.find(e=>e.id===val('pag-avulso-emp'));
  if(!emp){ toast('Selecione um colaborador.','error'); return; }
  const desc=(val('pag-avulso-desc')||'').trim();
  if(!desc){ toast('Informe a descrição do pagamento (ex.: Prêmio, Saldo de rescisão).','error'); return; }
  const valor=numVal('pag-avulso-valor');
  if(!(valor>0)){ toast('Informe um valor válido.','error'); return; }
  const pixKey=(val('pag-avulso-pix')||'').trim();
  if(!pixKey){ toast('Chave PIX não informada — cadastre no colaborador ou digite aqui.','error'); return; }
  const pixTipo=val('pag-avulso-pix-tipo')||detectPixKeyType(pixKey);
  const data=val('pag-avulso-data')||new Date().toISOString().substring(0,10);
  const btn=document.getElementById('pag-avulso-confirm');
  if(btn) setBtnLoading(btn,true,'');
  try{
    const sol=await _criarSolicitacaoPagamento({
      employeeId:emp.id, employeeNome:emp.nome, payrollId:'',
      valor, pixKey:_pixKeyParaAsaas(pixKey,pixTipo), keyType:pixTipo,
      descricao:`Avulso — ${desc}`,
      scheduleDate:data, origem:'avulso',
    });
    Auth.log('PAGAMENTO_SOLICITADO', null, `Avulso | ${emp.nome} | R$ ${valor.toFixed(2)} | ${desc} | sol ${sol.id}`);
    toast('Pagamento avulso enviado para Aprovações — precisa ser aprovado com 2FA.','success');
    closeModal('modal-pagamento-avulso');
  }catch(e){
    console.error(e);
    toast('Erro ao criar a solicitação: '+(e.message||e),'error');
  }finally{
    if(btn) setBtnLoading(btn,false,'<i class="fa-solid fa-paper-plane"></i> Enviar para aprovação');
  }
}

async function executarPagamentoAsaas() {
  if (!getUserModules(Auth.currentUser).pagamentosLancar) {
    toast('Você não tem permissão para lançar pagamentos.', 'error'); return;
  }
  const empId     = val('asaas-pagar-empid');
  const payrollId = val('asaas-pagar-payrollid');
  const emp       = State.employees.find(e => e.id === empId);
  if (!emp) return;

  const sel   = document.getElementById('asaas-pagar-tipo');
  const valor = sel.value === 'custom'
    ? parseFloat((document.getElementById('asaas-pagar-custom')?.value || '0').replace(',', '.')) || 0
    : parseFloat(sel.value) || 0;

  if (valor <= 0) { toast('Valor inválido.', 'warning'); return; }

  if (payrollId && (State.solicitacoes || []).some(s => s.payrollId === payrollId && s.status === 'pendente')) {
    toast('Já existe uma solicitação pendente para esta folha.', 'warning'); return;
  }

  const keyType = emp.chavePixTipo || val('asaas-pagar-keytype') || detectPixKeyType(emp.chavePix||'');
  const pixKey  = _pixKeyParaAsaas(emp.chavePix || '', keyType);
  const data    = val('asaas-pagar-data') || new Date().toISOString().split('T')[0];
  const mes     = document.getElementById('asaas-pagar-mes')?.textContent || '';

  const btn = document.getElementById('btn-executar-pagamento');
  btn.disabled = true;
  btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Lançando...';

  const resEl = document.getElementById('asaas-pagar-resultado');
  resEl.style.display = 'none';

  try {
    const sol = await _criarSolicitacaoPagamento({
      employeeId: empId, employeeNome: emp.nome, payrollId,
      valor, pixKey, keyType,
      descricao: `Salário ${mes} — ${emp.nome}`,
      scheduleDate: data, competencia: mes, origem: 'folha',
    });
    Auth.log('PAGAMENTO_SOLICITADO', null,
      `${emp.nome} | R$ ${valor.toFixed(2)} | PIX ${pixKey} | ${data} | sol ${sol.id}`);

    resEl.style.display = 'block';
    resEl.innerHTML = `
      <div style="background:#FFF8E1;border:1px solid #FFE082;border-radius:9px;padding:16px;font-size:13px;color:#6D4C41">
        <div style="font-weight:700;color:#E65100;margin-bottom:8px">
          <i class="fa-solid fa-hourglass-half"></i> Solicitação de pagamento criada!
        </div>
        <div style="margin-bottom:4px"><strong>Valor:</strong> ${fmtMoney(valor)} → <i class="fa-brands fa-pix" style="color:#00695C"></i> ${pixKey}</div>
        <div style="margin-top:6px">A transferência só será disparada após <strong>aprovação</strong> na tela <strong>Aprovações de Pagamentos</strong> (exige o código 2FA do aprovador).</div>
      </div>`;

    btn.style.display = 'none';
    toast('Solicitação criada — aguardando aprovação.', 'success');

  } catch(e) {
    resEl.style.display = 'block';
    resEl.innerHTML = `<div style="background:#fce4e4;border:1px solid #ef9a9a;border-radius:9px;padding:14px;font-size:13px;color:#c62828">
      <i class="fa-solid fa-triangle-exclamation"></i> <strong>Erro:</strong> ${e.message}
    </div>`;
    btn.disabled = false;
    btn.innerHTML = '<i class="fa-solid fa-paper-plane"></i> Tentar Novamente';
  }
}

// Helper para setar textContent com segurança
function setEl(id, txt) {
  const el = document.getElementById(id); if (el) el.textContent = txt;
}

// ============================================
// ASAAS — PAGAMENTO EM LOTE
// ============================================

// Dados do lote (preenchidos ao abrir o modal)
let _loteData = []; // [{emp, payroll, valor, pixKey, keyType, selecionado}]

function openPagarEmLote() {
  const mes = parseInt(val('pag-mes') || currentMes());
  const ano = parseInt(val('pag-ano') || currentAno());

  // Coleta colaboradores com folha FECHADA no período
  const emps = State.employees.filter(e => (e.status || 'ativo') === 'ativo');
  _loteData = [];

  emps.forEach(emp => {
    const p = State.payrolls.find(r => r.employeeId === emp.id && r.mes == mes && r.ano == ano);
    if (!p || p.status !== 'fechada') return; // só folhas fechadas

    const liquido  = p.totalLiquidoFinal || p.totalLiquido || 0;
    const adiant   = p.adiantamento || 0;
    const restante = Math.max(0, liquido - adiant);
    const pixKey   = emp.chavePix || '';
    const jaPago   = !!(p.pagamentoAsaas);
    const jaSolicitado = (State.solicitacoes || []).some(s => s.payrollId === p.id && s.status === 'pendente');

    _loteData.push({
      empId:    emp.id,
      nome:     emp.nome,
      registro: emp.registro,
      payrollId:p.id,
      liquido, adiant, restante,
      pixKey,
      keyType:  detectPixKeyType(pixKey),
      semPix:   !pixKey,
      jaPago,
      jaSolicitado,
      status:   jaPago ? 'pago' : (jaSolicitado ? 'solicitado' : (!pixKey ? 'sem-pix' : 'pendente')),
      selecionado: !jaPago && !jaSolicitado && !!pixKey, // pré-seleciona só os elegíveis
    });
  });

  if (_loteData.length === 0) {
    toast('Nenhuma folha fechada encontrada para este período. Feche as folhas antes de pagar.', 'warning');
    return;
  }

  // Data padrão: hoje
  setVal('lote-data', new Date().toISOString().split('T')[0]);
  setVal('lote-tipo-valor', 'restante');

  // Reset progresso
  document.getElementById('lote-progresso').style.display = 'none';
  document.getElementById('lote-progress-log').innerHTML  = '';
  document.getElementById('lote-progress-bar').style.width = '0%';

  const btn = document.getElementById('btn-executar-lote');
  btn.disabled = false;
  btn.onclick  = executarPagamentoLote;
  btn.innerHTML = '<i class="fa-solid fa-paper-plane"></i> Lançar Solicitações Selecionadas';

  refreshLoteTabela();
  document.getElementById('modal-pagar-lote').classList.remove('hidden');
}

function _loteValorPara(item) {
  const tipo = val('lote-tipo-valor') || 'restante';
  if (tipo === 'liquido')      return item.liquido;
  if (tipo === 'adiantamento') return item.adiant;
  return item.restante; // restante (padrão)
}

function refreshLoteTabela() {
  const tbody = document.getElementById('lote-tbody');
  if (!tbody) return;

  let totalSel = 0, totalVal = 0, semPix = 0, jaPagos = 0;

  tbody.innerHTML = _loteData.map((item, idx) => {
    const valor  = _loteValorPara(item);
    const rowBg  = idx % 2 === 0 ? '#fff' : '#f9fafb';
    const disabled = item.semPix || item.jaPago || item.jaSolicitado;

    if (item.jaPago) { jaPagos++; }
    else if (item.semPix) { semPix++; }
    else if (item.selecionado) { totalSel++; totalVal += valor; }

    // Badge de status
    let statusBadge;
    if (item.jaPago) {
      statusBadge = `<span style="background:#E0F2F1;color:#00695C;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600">✓ Pago</span>`;
    } else if (item.jaSolicitado) {
      statusBadge = `<span style="background:#FFF8E1;color:#E65100;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600">Solicitado</span>`;
    } else if (item.semPix) {
      statusBadge = `<span style="background:#FFF3E0;color:#E65100;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600">Sem PIX</span>`;
    } else {
      statusBadge = `<span style="background:#E8F5E9;color:#2e7d32;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600">Pendente</span>`;
    }

    const matr = item.registro ? String(item.registro).padStart(4,'0') : '—';
    const pixDisplay = item.pixKey
      ? `<span style="font-family:monospace;font-size:11px;color:#00695C">${item.pixKey}</span>`
      : `<span style="color:#bbb;font-size:11px">—</span>`;

    return `<tr style="background:${rowBg};opacity:${disabled ? .55 : 1}">
      <td style="padding:8px 12px;text-align:center">
        <input type="checkbox" data-idx="${idx}" ${item.selecionado ? 'checked' : ''} ${disabled ? 'disabled' : ''}
          onchange="_loteData[${idx}].selecionado=this.checked; refreshLoteResumo()">
      </td>
      <td style="padding:8px 12px"><strong>${item.nome}</strong> <span style="font-size:11px;color:#aaa">${matr}</span></td>
      <td style="padding:8px 12px;text-align:right">${fmtMoney(item.liquido)}</td>
      <td style="padding:8px 12px;text-align:right;color:#e65100">${item.adiant > 0 ? fmtMoney(item.adiant) : '—'}</td>
      <td style="padding:8px 12px;text-align:right;font-weight:700;color:#00695C">${valor > 0 ? fmtMoney(valor) : '<span style="color:#ccc">—</span>'}</td>
      <td style="padding:8px 12px">${pixDisplay}</td>
      <td style="padding:8px 12px;text-align:center">${statusBadge}</td>
    </tr>`;
  }).join('');

  refreshLoteResumo();
}

function refreshLoteResumo() {
  let totalSel = 0, totalVal = 0;
  _loteData.forEach(item => {
    if (item.selecionado && !item.semPix && !item.jaPago) {
      totalSel++;
      totalVal += _loteValorPara(item);
    }
  });

  const semPix  = _loteData.filter(i => i.semPix).length;
  const jaPagos = _loteData.filter(i => i.jaPago).length;

  document.getElementById('lote-counter').textContent =
    `${totalSel} selecionado(s) · Total: ${fmtMoney(totalVal)}`;

  let resumoHtml = `<strong>${totalSel}</strong> colaborador(es) selecionados · Total a pagar: <strong style="color:#00695C">${fmtMoney(totalVal)}</strong>`;
  if (semPix  > 0) resumoHtml += ` &nbsp;|&nbsp; <span style="color:#e65100">${semPix} sem chave PIX (não serão pagos)</span>`;
  if (jaPagos > 0) resumoHtml += ` &nbsp;|&nbsp; <span style="color:#00695C">${jaPagos} já pagos</span>`;
  document.getElementById('lote-resumo').innerHTML = resumoHtml;

  // Atualiza checkbox geral
  const elegíveis = _loteData.filter(i => !i.semPix && !i.jaPago && !i.jaSolicitado);
  const chkAll = document.getElementById('lote-chk-all');
  if (chkAll) {
    chkAll.checked       = elegíveis.length > 0 && elegíveis.every(i => i.selecionado);
    chkAll.indeterminate = elegíveis.some(i => i.selecionado) && !chkAll.checked;
  }
}

function loteSelectAll(checked) {
  _loteData.forEach(item => {
    if (!item.semPix && !item.jaPago && !item.jaSolicitado) item.selecionado = checked;
  });
  const chkAll = document.getElementById('lote-chk-all');
  if (chkAll) chkAll.checked = checked;
  refreshLoteTabela();
}

function _loteLog(msg, cor = '#81d4fa') {
  const el = document.getElementById('lote-progress-log'); if (!el) return;
  const ts = new Date().toLocaleTimeString('pt-BR');
  el.innerHTML += `<span style="color:#aaa">[${ts}]</span> <span style="color:${cor}">${msg}</span>\n`;
  el.scrollTop = el.scrollHeight;
}

async function executarPagamentoLote() {
  if (!getUserModules(Auth.currentUser).pagamentosLancar) {
    toast('Você não tem permissão para lançar pagamentos.', 'error'); return;
  }
  const selecionados = _loteData.filter(i => i.selecionado && !i.semPix && !i.jaPago && !i.jaSolicitado);

  if (selecionados.length === 0) {
    toast('Nenhum colaborador selecionado para pagamento.', 'warning');
    return;
  }

  const data      = val('lote-data') || new Date().toISOString().split('T')[0];
  const dataLabel = data.split('-').reverse().join('/');
  const mes = parseInt(val('pag-mes') || currentMes());
  const ano = parseInt(val('pag-ano') || currentAno());
  const mesLabel = `${String(mes).padStart(2,'0')}/${ano}`;
  const totalSel = selecionados.reduce((s,i) => s + _loteValorPara(i), 0);

  if (!confirm(`Lançar ${selecionados.length} solicitação(ões) de pagamento PIX (data ${dataLabel})?\n`
      + `Total: ${fmtMoney(totalSel)}\n\n`
      + `Nada será transferido agora — as solicitações vão para a tela "Aprovações de Pagamentos".`)) return;

  // UI: início
  const btn = document.getElementById('btn-executar-lote');
  btn.disabled = true;
  btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Lançando...';
  document.getElementById('lote-progresso').style.display = 'block';
  document.getElementById('lote-progress-log').innerHTML  = '';
  document.getElementById('lote-progress-bar').style.width = '0%';

  _loteLog(`Criando ${selecionados.length} solicitação(ões) de pagamento...`, '#fff176');

  let ok = 0, erros = 0;

  for (let i = 0; i < selecionados.length; i++) {
    const item  = selecionados[i];
    const valor = _loteValorPara(item);

    if (valor <= 0) {
      _loteLog(`⚠ ${item.nome}: valor zero — pulado`, '#ffcc02');
      continue;
    }
    if ((State.solicitacoes || []).some(s => s.payrollId === item.payrollId && s.status === 'pendente')) {
      _loteLog(`⚠ ${item.nome}: já tem solicitação pendente — pulado`, '#ffcc02');
      continue;
    }

    try {
      const sol = await _criarSolicitacaoPagamento({
        employeeId: item.empId, employeeNome: item.nome, payrollId: item.payrollId,
        valor, pixKey: item.pixKey, keyType: item.keyType,
        descricao: `Salário ${mesLabel} — ${item.nome}`,
        scheduleDate: data, competencia: mesLabel, origem: 'lote',
      });
      item.jaSolicitado = true;
      item.selecionado  = false;

      ok++;
      _loteLog(`✓ ${item.nome}: ${fmtMoney(valor)} solicitado (sol ${sol.id})`, '#a5d6a7');
      Auth.log('PAGAMENTO_SOLICITADO', null,
        `${item.nome} | R$ ${valor.toFixed(2)} | PIX ${item.pixKey} | ${data} | sol ${sol.id}`);

    } catch(e) {
      erros++;
      _loteLog(`✗ ${item.nome}: ERRO — ${e.message}`, '#ef9a9a');
    }

    document.getElementById('lote-progress-bar').style.width =
      `${Math.round(((i + 1) / selecionados.length) * 100)}%`;
  }

  // Resultado final
  const corFinal = erros === 0 ? '#fff176' : '#ffcc02';
  _loteLog(`\nConcluído: ${ok} solicitação(ões) criada(s)${erros > 0 ? `, ${erros} com erro` : '.'}`, corFinal);

  btn.disabled = false;
  if (erros === 0) {
    btn.innerHTML = '<i class="fa-solid fa-check"></i> Concluído';
    btn.onclick = () => closeModal('modal-pagar-lote');
    toast(`${ok} solicitação(ões) criada(s) — aguardando aprovação.`, 'success');
  } else {
    btn.innerHTML = '<i class="fa-solid fa-paper-plane"></i> Tentar Novamente (com erros)';
    btn.onclick = executarPagamentoLote;
    toast(`${ok} criadas, ${erros} com erro. Verifique o log.`, 'warning');
  }

  // Atualiza tabela para refletir os solicitados
  refreshLoteTabela();
}

// ============================================
// APROVAÇÕES DE PAGAMENTOS (Etapa 4d)
// ============================================
function _aprovacaoStatusBadge(st){
  const map={
    pendente:  ['#FFF3E0','#E65100','Pendente'],
    pago:      ['#E8F5E9','#2e7d32','Pago'],
    recusado:  ['#FCE4EC','#c62828','Recusado'],
    erro:      ['#fce4e4','#c62828','Erro'],
    estornado: ['#FFF3E0','#E65100','Estornado'],
  };
  const m=map[st]||['#eee','#777',st||'—'];
  return `<span style="background:${m[0]};color:${m[1]};padding:2px 9px;border-radius:10px;font-size:11px;font-weight:600">${m[2]}</span>`;
}

// ============================================
// ADIANTAMENTOS — lista e pagamento (reaproveita o fluxo de Aprovações)
// ============================================
function _adiantMesAno(){
  const mes=parseInt(val('adiant-mes'))||(new Date().getMonth()+1);
  const ano=parseInt(val('adiant-ano'))||(new Date().getFullYear());
  return {mes,ano,comp:String(mes).padStart(2,'0')+'/'+ano};
}

function renderAdiantamentos(){
  const tbody=document.getElementById('adiant-tbody'); if(!tbody) return;
  const selAno=document.getElementById('adiant-ano');
  if(selAno && !selAno.options.length){
    const ya=new Date().getFullYear();
    for(let y=ya-1;y<=ya+1;y++){
      const o=document.createElement('option'); o.value=y; o.textContent=y;
      if(y===ya) o.selected=true;
      selAno.appendChild(o);
    }
  }
  const selMes=document.getElementById('adiant-mes');
  // <select> sempre tem .value (a primeira opção, "1" = Janeiro), então o
  // !selMes.value antigo nunca era verdadeiro e nunca corrigia para o mês
  // atual. Usa um flag de inicialização: na 1ª render aplica o mês atual,
  // depois respeita a escolha do operador.
  if(selMes && !selMes.dataset.inicializado){
    selMes.value=new Date().getMonth()+1;
    selMes.dataset.inicializado='1';
  }
  const {mes,ano,comp}=_adiantMesAno();

  // Vencimento: dia limite configurado em Configurações da Empresa (default 15).
  // Passou do dia E nada foi pago (nem PIX via sistema nem registro "pago fora")
  // ⇒ status "VENCIDO". Útil para o gestor não esquecer adiantamentos atrasados.
  const diaLimite=Math.min(28,Math.max(1,parseInt(State.empresa?.diaLimiteAdiantamento)||15));
  const cutoff=new Date(ano,mes-1,diaLimite,23,59,59,999);
  const passouDoDia=new Date()>cutoff;

  const lista=(State.payrolls||[])
    .filter(p=>p.mes==mes && p.ano==ano && p.adiantamentoAtivo && (p.adiantamentoValor||0)>0)
    .map(p=>{
      const emp=State.employees.find(e=>e.id===p.employeeId)||{};
      const sol=(State.solicitacoes||[]).find(s=>s.origem==='adiantamento' && s.employeeId===p.employeeId
        && s.competencia===comp && (s.status==='pendente'||s.status==='pago'));
      const pagoExterno=p.adiantamentoPagoExterno||null;
      const naoPago=!sol && !pagoExterno;
      return {emp, valor:p.adiantamentoValor||0, sol, pagoExterno, vencido:naoPago && passouDoDia};
    })
    .filter(x=>x.emp.id)
    .sort((a,b)=>(a.emp.nome||'').localeCompare(b.emp.nome||''));

  const cnt=document.getElementById('adiant-contador');
  if(cnt){
    const total=lista.reduce((s,x)=>s+x.valor,0);
    const aPagar  =lista.filter(x=>!x.sol && !x.pagoExterno && !x.vencido).length;
    const vencidos=lista.filter(x=>x.vencido).length;
    const pagosExt=lista.filter(x=>x.pagoExterno).length;
    const partes=[];
    if(aPagar>0)   partes.push(`<strong style="color:#1565C0">${aPagar}</strong> a pagar`);
    if(vencidos>0) partes.push(`<strong style="color:#c62828">${vencidos}</strong> vencido(s)`);
    if(pagosExt>0) partes.push(`<strong style="color:#00695C">${pagosExt}</strong> pago(s) fora`);
    cnt.innerHTML=lista.length
      ? `<strong>${lista.length}</strong> adiantamento(s) em ${comp} &middot; Total ${fmtMoney(total)}${partes.length?' &middot; '+partes.join(' &middot; '):''}`
      : `<span style="color:#999">Nenhum adiantamento lançado em ${comp}</span>`;
  }

  // Diagnóstico — colaboradores marcados como "Recebe adiantamento" no
  // cadastro mas que NÃO aparecem aqui (folha não lançada OU folha lançada
  // sem adiantamento ativo). Sem nenhum marcado, mostra uma dica leve.
  const _empsAtivos=(State.employees||[]).filter(e=>(e.status||'ativo')==='ativo');
  const _marcados=_empsAtivos.filter(e=>e.recebeAdiantamento);
  const _semFolha=[], _semAdiantNaFolha=[], _semValor=[];
  _marcados.forEach(e=>{
    const p=(State.payrolls||[]).find(pp=>pp.employeeId===e.id&&pp.mes==mes&&pp.ano==ano);
    if(!p) _semFolha.push(e);
    else if(!p.adiantamentoAtivo) _semAdiantNaFolha.push(e);
    else if(!((p.adiantamentoValor||0)>0)) _semValor.push(e);
  });
  const _diagEl=document.getElementById('adiant-diagnostico');
  if(_diagEl){
    if(!_marcados.length){
      _diagEl.innerHTML=`<div style="font-size:12px;color:#64748b;padding:8px 12px;background:#F8FAFC;border:1px dashed #CBD5E1;border-radius:8px">
        <i class="fa-solid fa-circle-info"></i> Para um colaborador aparecer aqui, abra a Folha de Ponto do mês, marque <strong>"Aderiu ao adiantamento? Sim"</strong> e salve.
        <br><span style="color:#94A3B8">Dica: marque <strong>"Recebe adiantamento quinzenal"</strong> no cadastro do colaborador para que a folha já venha marcada automaticamente.</span>
      </div>`;
    } else if(!_semFolha.length && !_semAdiantNaFolha.length && !_semValor.length){
      _diagEl.innerHTML='';
    } else {
      const _li=e=>`<li style="margin:3px 0"><a onclick="_abrirFolhaColaborador('${e.id}')" style="color:#1565C0;cursor:pointer;text-decoration:underline">${e.nome||'—'}</a></li>`;
      const _parts=[];
      if(_semFolha.length) _parts.push(`<div style="margin-top:6px"><strong style="color:#E65100"><i class="fa-solid fa-triangle-exclamation"></i> ${_semFolha.length} colaborador(es) marcado(s) ainda sem folha de ${comp}:</strong><ul style="margin:4px 0 0 22px;padding:0">${_semFolha.map(_li).join('')}</ul></div>`);
      if(_semAdiantNaFolha.length) _parts.push(`<div style="margin-top:8px"><strong style="color:#E65100"><i class="fa-solid fa-triangle-exclamation"></i> ${_semAdiantNaFolha.length} folha(s) de ${comp} lançada(s) sem adiantamento ativo:</strong><ul style="margin:4px 0 0 22px;padding:0">${_semAdiantNaFolha.map(_li).join('')}</ul></div>`);
      if(_semValor.length){
        const _liRecalc=e=>`<li style="margin:4px 0;display:flex;align-items:center;gap:8px;flex-wrap:wrap"><a onclick="_abrirFolhaColaborador('${e.id}')" style="color:#1565C0;cursor:pointer;text-decoration:underline">${e.nome||'—'}</a><button onclick="_recalcAdiantamento('${e.id}',${mes},${ano})" title="Atualiza o valor do adiantamento direto, sem abrir a folha" style="background:#00695C;color:#fff;border:none;border-radius:6px;padding:3px 10px;font-size:11px;font-weight:700;cursor:pointer"><i class="fa-solid fa-rotate"></i> Recalcular agora</button></li>`;
        _parts.push(`<div style="margin-top:8px"><strong style="color:#E65100"><i class="fa-solid fa-triangle-exclamation"></i> ${_semValor.length} folha(s) de ${comp} com adiantamento ativo mas valor ZERADO (salva antes da regra atual):</strong><ul style="margin:4px 0 0 22px;padding:0">${_semValor.map(_liRecalc).join('')}</ul><div style="margin-top:6px;font-size:11px;color:#7C5500">Clique em <strong>"Recalcular agora"</strong> para corrigir num clique. Ou clique no nome para abrir a folha e revisar (o valor já vem certo na tela — basta rolar até o final e clicar em <strong>"Salvar Folha"</strong>).</div></div>`);
      }
      _diagEl.innerHTML=`<div style="padding:10px 14px;background:#FFF3E0;border:1px solid #FFB74D;border-radius:8px;font-size:13px">
        <div><strong>Faltando alguém aqui?</strong> Estes colaboradores estão marcados como "Recebe adiantamento quinzenal" no cadastro, mas não aparecem na lista:</div>
        ${_parts.join('')}
        <div style="margin-top:8px;font-size:11px;color:#7C5500">Clique no nome para abrir a Folha de Ponto.</div>
      </div>`;
    }
  }

  if(!lista.length){
    tbody.innerHTML=`<tr><td colspan="6" style="padding:26px;text-align:center;color:#999">Nenhum colaborador com adiantamento lançado em ${comp}.</td></tr>`;
    return;
  }
  tbody.innerHTML=lista.map((x,idx)=>{
    let bg=idx%2?'#f9fafb':'#fff';
    let statusHtml, acao, podeSelec=false;
    const _btnPagar=`<button class="btn btn-sm" style="background:#00695C;color:#fff;border-color:#00695C;font-size:11px;padding:4px 9px" onclick="event.stopPropagation();pagarAdiantamento('${x.emp.id}')"><i class="fa-brands fa-pix"></i> Pagar</button>`;
    const _btnPagoFora=`<button class="btn btn-sm" style="background:#fff;color:#00695C;border:1px solid #00695C;font-size:11px;padding:4px 9px" onclick="event.stopPropagation();openPagoExternoModal('${x.emp.id}',${mes},${ano})" title="Marca como pago fora do sistema (você pagou via app do banco, em espécie etc.)"><i class="fa-solid fa-circle-check"></i> Pago fora</button>`;

    if(x.pagoExterno){
      const _dt=formatDateBr(x.pagoExterno.data)||'—';
      const _obs=(x.pagoExterno.obs||'').replace(/"/g,'&quot;');
      statusHtml=`<span style="background:#E0F2F1;color:#00695C;padding:3px 9px;border-radius:10px;font-size:11px;font-weight:700" title="Pago fora do sistema em ${_dt}${_obs?' — '+_obs:''}"><i class="fa-solid fa-circle-check"></i> Pago fora</span>`;
      acao=`<button class="btn btn-sm" style="background:#fff;color:#c62828;border:1px solid #c62828;font-size:11px;padding:4px 9px" onclick="event.stopPropagation();desfazerPagoExterno('${x.emp.id}',${mes},${ano})" title="Desfaz a marcação de pago externo"><i class="fa-solid fa-rotate-left"></i> Desfazer</button>`;
    } else if(x.sol?.status==='pendente'){
      statusHtml='<span style="background:#FFF3E0;color:#E65100;padding:3px 9px;border-radius:10px;font-size:11px;font-weight:700">Solicitado</span>';
      acao='<span style="font-size:11px;color:#999">aguardando aprovação</span>';
    } else if(x.sol?.status==='pago'){
      statusHtml='<span style="background:#E8F5E9;color:#2e7d32;padding:3px 9px;border-radius:10px;font-size:11px;font-weight:700">Pago</span>';
      acao=`<span style="font-size:11px;color:#00695C">ID ${x.sol.asaasTransferId||'—'}</span>`;
    } else if(x.vencido){
      bg='#FFEBEE'; // fundo vermelho claro para destacar
      statusHtml='<span style="background:#fff;color:#c62828;padding:3px 9px;border-radius:10px;font-size:11px;font-weight:700;border:1px solid #EF9A9A"><i class="fa-solid fa-triangle-exclamation"></i> VENCIDO</span>';
      acao=`<div style="display:flex;gap:6px;flex-wrap:wrap">${_btnPagar}${_btnPagoFora}</div>`;
      podeSelec=true;
    } else {
      statusHtml='<span style="background:#E3F2FD;color:#1565C0;padding:3px 9px;border-radius:10px;font-size:11px;font-weight:700">A pagar</span>';
      acao=`<div style="display:flex;gap:6px;flex-wrap:wrap">${_btnPagar}${_btnPagoFora}</div>`;
      podeSelec=true;
    }
    const semPix=!x.emp.chavePix;
    const chk=(podeSelec && !semPix)
      ? `<input type="checkbox" class="adiant-check" data-emp="${x.emp.id}" onclick="event.stopPropagation()">`
      : '';
    const pix=semPix?'<span style="color:#c62828">sem chave PIX</span>':`<span style="font-family:monospace;font-size:11px">${x.emp.chavePix}</span>`;
    return `<tr style="background:${bg};cursor:pointer" onclick="_abrirFolhaColaborador('${x.emp.id}')" title="Abrir a folha de ${(x.emp.nome||'').replace(/"/g,'')}">
      <td style="padding:9px 10px;text-align:center">${chk}</td>
      <td style="padding:9px 10px"><strong>${x.emp.nome||'—'}</strong></td>
      <td style="padding:9px 10px;text-align:right;font-weight:700;color:#00695C">${fmtMoney(x.valor)}</td>
      <td style="padding:9px 10px">${pix}</td>
      <td style="padding:9px 10px;text-align:center">${statusHtml}</td>
      <td style="padding:9px 10px">${acao}</td>
    </tr>`;
  }).join('');
  const chkAll=document.getElementById('adiant-check-all'); if(chkAll) chkAll.checked=false;
}

function _adiantToggleAll(master){
  document.querySelectorAll('#adiant-tbody .adiant-check').forEach(c=>{ c.checked=master.checked; });
}

function _abrirFolhaColaborador(empId){
  if(!empId) return;
  showSection('payroll');
  // Garante que a opção do colaborador-alvo está no select ANTES de selecionar:
  // alinha o filtro de posto, inclui demitidos/afastados se for o caso e injeta
  // a opção se mesmo assim faltar. Sem isso, sel.value=empId falhava silenciosa
  // e a folha do colaborador não carregava (o nome era clicável mas "não ia").
  try { _ensurePayrollEmployeeOption(empId); } catch(e){ console.warn('_abrirFolhaColaborador', e); }
  const sel=document.getElementById('payroll-employee');
  if(sel){
    sel.value=empId;
    if(typeof onPayrollEmployeeChange==='function') onPayrollEmployeeChange();
  }
}

// Recalcula o valor do adiantamento de uma folha já salva (salário base ×
// percentual) e salva direto, sem precisar abrir a Folha de Ponto. Usado
// pelo botão "Recalcular agora" no diagnóstico de Adiantamentos.
async function _recalcAdiantamento(empId, mes, ano){
  const emp=State.employees.find(e=>e.id===empId);
  const p=(State.payrolls||[]).find(pp=>pp.employeeId===empId && pp.mes==mes && pp.ano==ano);
  if(!emp || !p){ toast('Folha do colaborador não encontrada.','error'); return; }
  const salBase=+emp.salarioBase||0;
  if(salBase<=0){ toast('Salário base do colaborador não está cadastrado.','error'); return; }
  const perc=parseInt(p.adiantamentoPerc||40);
  const novoValor=+(salBase*perc/100).toFixed(2);
  const updated={...p, adiantamentoValor:novoValor, updatedAt:new Date().toISOString()};
  try {
    await DB.save('payrolls', updated);
    const ix=State.payrolls.findIndex(x=>x.id===p.id);
    if(ix>=0) State.payrolls[ix]=updated;
    toast(`${emp.nome}: adiantamento recalculado para ${fmtMoney(novoValor)}.`,'success');
    renderAdiantamentos();
  } catch(e){
    console.error(e);
    toast('Erro ao salvar a folha. Tente abrir manualmente.','error');
  }
}

// "Pago fora do sistema" — registra que o adiantamento foi pago por fora
// (app do banco, espécie etc.). Tira o item da lista de pendência e marca
// como pago externo. O fluxo PIX via Aprovações continua disponível
// normalmente; isso é só para casos em que a pressa fala mais alto.
let _pagoExtCtx = null;
function openPagoExternoModal(empId, mes, ano){
  const emp=State.employees.find(e=>e.id===empId);
  const p=(State.payrolls||[]).find(pp=>pp.employeeId===empId && pp.mes==mes && pp.ano==ano);
  if(!emp || !p){ toast('Folha do colaborador não encontrada.','error'); return; }
  if((State.solicitacoes||[]).some(s=>s.origem==='adiantamento' && s.employeeId===empId
      && s.competencia===String(mes).padStart(2,'0')+'/'+ano && s.status==='pendente')){
    toast('Já existe uma solicitação PIX pendente. Cancele primeiro em Aprovações antes de marcar como pago fora.','warning');
    return;
  }
  _pagoExtCtx = {empId, mes, ano};
  setVal('pago-ext-nome', emp.nome||'—');
  setVal('pago-ext-valor', fmtMoney(p.adiantamentoValor||0));
  setVal('pago-ext-comp', String(mes).padStart(2,'0')+'/'+ano);
  setVal('pago-ext-data', new Date().toISOString().substring(0,10));
  setVal('pago-ext-obs','');
  document.getElementById('modal-pago-externo')?.classList.remove('hidden');
}

// Abre o modal de "pago fora" em modo LOTE para todos os selecionados.
async function marcarPagoExternoLote(){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para lançar pagamentos.','error'); return;
  }
  const checks=[...document.querySelectorAll('#adiant-tbody .adiant-check:checked')];
  if(!checks.length){ toast('Selecione ao menos um colaborador (marque as caixas).','warning'); return; }
  const {mes,ano} = _adiantMesAno();
  _pagoExtCtx = { lote:true, ids: checks.map(c=>c.dataset.emp), mes, ano };
  setVal('pago-ext-data', new Date().toISOString().substring(0,10));
  setVal('pago-ext-obs','');
  document.getElementById('modal-pago-externo')?.classList.remove('hidden');
}

async function confirmarPagoExterno(){
  if(!_pagoExtCtx){ toast('Contexto perdido — reabra o modal.','error'); return; }
  const data=val('pago-ext-data')||new Date().toISOString().substring(0,10);
  const obs=(val('pago-ext-obs')||'').trim();

  // Modo LOTE — aplica a mesma data/obs a todos os colaboradores selecionados.
  if(_pagoExtCtx.lote){
    const {ids, mes:mL, ano:aL} = _pagoExtCtx;
    let ok=0, erros=0;
    for(const empId of ids){
      const p=(State.payrolls||[]).find(pp=>pp.employeeId===empId && pp.mes==mL && pp.ano==aL);
      if(!p){ erros++; continue; }
      const emp=State.employees.find(e=>e.id===empId);
      const updated={...p,
        adiantamentoPagoExterno:{
          data, obs,
          registradoEm:new Date().toISOString(),
          registradoPor:Auth.currentUser?.username || Auth.currentUser?.nome || '—'
        },
        updatedAt:new Date().toISOString()
      };
      try{
        await DB.save('payrolls', updated);
        const ix=State.payrolls.findIndex(x=>x.id===p.id);
        if(ix>=0) State.payrolls[ix]=updated;
        Auth.log('ADIANT_PAGO_EXTERNO', null, `${emp?.nome||'—'} | ${String(mL).padStart(2,'0')}/${aL} | R$ ${(p.adiantamentoValor||0).toFixed(2)}${obs?' | '+obs:''}`);
        ok++;
      }catch(e){ console.error('lote pago fora', e); erros++; }
    }
    toast(`${ok} marcado(s) como pago fora${erros?` · ${erros} erro(s)`:''}.`, erros?'warning':'success');
    closeModal('modal-pago-externo');
    _pagoExtCtx=null;
    renderAdiantamentos();
    if(typeof renderDashboard==='function' && State.currentSection==='dashboard') renderDashboard();
    return;
  }

  // Modo INDIVIDUAL (mantém o comportamento original).
  const {empId, mes, ano} = _pagoExtCtx;
  const p=(State.payrolls||[]).find(pp=>pp.employeeId===empId && pp.mes==mes && pp.ano==ano);
  if(!p){ toast('Folha não encontrada.','error'); return; }
  const emp=State.employees.find(e=>e.id===empId);
  const updated={
    ...p,
    adiantamentoPagoExterno:{
      data,
      obs,
      registradoEm:new Date().toISOString(),
      registradoPor:Auth.currentUser?.username || Auth.currentUser?.nome || '—'
    },
    updatedAt:new Date().toISOString()
  };
  try{
    await DB.save('payrolls', updated);
    const ix=State.payrolls.findIndex(x=>x.id===p.id);
    if(ix>=0) State.payrolls[ix]=updated;
    Auth.log('ADIANT_PAGO_EXTERNO', null, `${emp?.nome||'—'} | ${String(mes).padStart(2,'0')}/${ano} | R$ ${(p.adiantamentoValor||0).toFixed(2)}${obs?' | '+obs:''}`);
    toast(`${emp?.nome||'—'}: marcado como pago fora do sistema.`,'success');
    closeModal('modal-pago-externo');
    _pagoExtCtx=null;
    renderAdiantamentos();
    if(typeof renderDashboard==='function' && State.currentSection==='dashboard') renderDashboard();
  }catch(e){
    console.error(e);
    toast('Erro ao salvar.','error');
  }
}

async function desfazerPagoExterno(empId, mes, ano){
  const emp=State.employees.find(e=>e.id===empId);
  if(!confirm(`Desfazer a marcação de "pago fora" do adiantamento de ${emp?.nome||'esse colaborador'}? O item volta para a lista de pendências.`)) return;
  const p=(State.payrolls||[]).find(pp=>pp.employeeId===empId && pp.mes==mes && pp.ano==ano);
  if(!p){ toast('Folha não encontrada.','error'); return; }
  const updated={...p, updatedAt:new Date().toISOString()};
  delete updated.adiantamentoPagoExterno;
  try{
    await DB.save('payrolls', updated);
    const ix=State.payrolls.findIndex(x=>x.id===p.id);
    if(ix>=0) State.payrolls[ix]=updated;
    Auth.log('ADIANT_PAGO_EXTERNO_DESFEITO', null, `${emp?.nome||'—'} | ${String(mes).padStart(2,'0')}/${ano}`);
    toast('Marcação desfeita.','success');
    renderAdiantamentos();
    if(typeof renderDashboard==='function' && State.currentSection==='dashboard') renderDashboard();
  }catch(e){ console.error(e); toast('Erro ao salvar.','error'); }
}

// Cria a solicitação de pagamento de um adiantamento — reaproveita _criarSolicitacaoPagamento.
async function _criarSolicAdiantamento(emp, valor, comp){
  if(!(valor>0)) throw new Error('valor do adiantamento inválido');
  const pixKey=emp.chavePix||'';
  if(!pixKey) throw new Error('colaborador sem chave PIX cadastrada');
  const pixTipo=emp.chavePixTipo||detectPixKeyType(pixKey);
  const jaPend=(State.solicitacoes||[]).some(s=>s.origem==='adiantamento' && s.employeeId===emp.id
    && s.competencia===comp && s.status==='pendente');
  if(jaPend) throw new Error('já existe uma solicitação pendente para este adiantamento');
  return _criarSolicitacaoPagamento({
    employeeId:emp.id, employeeNome:emp.nome, payrollId:'',
    valor, pixKey:_pixKeyParaAsaas(pixKey,pixTipo), keyType:pixTipo,
    descricao:`Adiantamento ${comp} — ${emp.nome}`,
    scheduleDate:new Date().toISOString().split('T')[0],
    competencia:comp, origem:'adiantamento',
  });
}

async function pagarAdiantamento(empId){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para lançar pagamentos.','error'); return;
  }
  const {mes,ano,comp}=_adiantMesAno();
  const p=(State.payrolls||[]).find(x=>x.employeeId===empId && x.mes==mes && x.ano==ano);
  const emp=State.employees.find(e=>e.id===empId);
  if(!p||!emp||!p.adiantamentoAtivo){ toast('Adiantamento não encontrado.','error'); return; }
  try{
    const sol=await _criarSolicAdiantamento(emp, p.adiantamentoValor||0, comp);
    Auth.log('PAGAMENTO_SOLICITADO', null, `Adiantamento ${comp} | ${emp.nome} | R$ ${(p.adiantamentoValor||0).toFixed(2)} | sol ${sol.id}`);
    toast(`Adiantamento de ${emp.nome}: solicitação criada — aguardando aprovação.`,'success');
    renderAdiantamentos();
  }catch(e){
    toast('Não foi possível: '+(e.message||e),'error');
  }
}

async function pagarAdiantamentosLote(){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para lançar pagamentos.','error'); return;
  }
  const checks=[...document.querySelectorAll('#adiant-tbody .adiant-check:checked')];
  if(!checks.length){ toast('Selecione ao menos um colaborador (marque as caixas).','warning'); return; }
  const {mes,ano,comp}=_adiantMesAno();
  let ok=0, erros=0;
  for(const c of checks){
    const empId=c.dataset.emp;
    const p=(State.payrolls||[]).find(x=>x.employeeId===empId && x.mes==mes && x.ano==ano);
    const emp=State.employees.find(e=>e.id===empId);
    if(!p||!emp){ erros++; continue; }
    try{
      const sol=await _criarSolicAdiantamento(emp, p.adiantamentoValor||0, comp);
      Auth.log('PAGAMENTO_SOLICITADO', null, `Adiantamento ${comp} | ${emp.nome} | R$ ${(p.adiantamentoValor||0).toFixed(2)} | sol ${sol.id}`);
      ok++;
    }catch(e){ erros++; }
  }
  toast(`${ok} solicitação(ões) de adiantamento criada(s)${erros?` · ${erros} pulada(s)/com erro`:''}.`, erros?'warning':'success');
  renderAdiantamentos();
}

// ── Comprovante (recibo) do PIX ──────────────────────────────
// Solicitações cujo comprovante já foi buscado nesta sessão e trava de
// concorrência — para a busca automática não repetir nem rodar 2x junto.
const _comprovantesBuscados = new Set();
let   _autoComprovBusy = false;

// Abre o comprovante do PIX de uma solicitação paga. Se ainda não está
// salvo, busca a transferência no Asaas, guarda o link na solicitação e
// abre. O comprovante só existe depois que o PIX é concluído pelo banco.
async function verComprovante(solId, btnEl){
  const sol=(State.solicitacoes||[]).find(s=>s.id===solId);
  if(sol && sol.asaasComprovante){ window.open(sol.asaasComprovante,'_blank','noopener'); return; }
  if(!sol || !sol.asaasTransferId){ toast('Esta solicitação ainda não tem transferência no Asaas.','warning'); return; }
  const _html=btnEl?btnEl.innerHTML:'';
  if(btnEl){ btnEl.disabled=true; btnEl.innerHTML='<i class="fa-solid fa-spinner fa-spin"></i> Buscando...'; }
  try{
    const t=await _asaasReq('GET','/transfers/'+encodeURIComponent(sol.asaasTransferId));
    const url=(t&&t.transactionReceiptUrl)||'';
    if(url){
      sol.asaasComprovante=url; if(t.status) sol.asaasStatus=t.status;
      try{ await DB.merge('solicitacoesPagamento',solId,{asaasComprovante:url,asaasStatus:t.status||''}); }catch(_){}
      const w=window.open(url,'_blank','noopener');
      _refreshComprovanteViews();
      if(!w) toast('Comprovante pronto — clique no botão verde para abrir.','success');
    } else {
      toast('Comprovante ainda sendo gerado pelo banco. Tente de novo em instantes.','warning');
      if(btnEl){ btnEl.disabled=false; btnEl.innerHTML=_html; }
    }
  }catch(e){
    toast('Não foi possível obter o comprovante: '+(e.message||e),'error');
    if(btnEl){ btnEl.disabled=false; btnEl.innerHTML=_html; }
  }
}

// Em 2º plano, busca os comprovantes das solicitações pagas que ainda não
// têm o link salvo — assim o botão "Comprovante" já aparece pronto.
async function _autoBuscarComprovantes(){
  if(_autoComprovBusy) return;
  const pend=(State.solicitacoes||[]).filter(s=>
    s.status==='pago' && s.asaasTransferId && !s.asaasComprovante && !_comprovantesBuscados.has(s.id));
  if(!pend.length) return;
  _autoComprovBusy=true;
  let achou=false;
  try{
    for(const s of pend){
      _comprovantesBuscados.add(s.id);
      try{
        const t=await _asaasReq('GET','/transfers/'+encodeURIComponent(s.asaasTransferId));
        const url=(t&&t.transactionReceiptUrl)||'';
        if(url){
          s.asaasComprovante=url; if(t.status) s.asaasStatus=t.status;
          try{ await DB.merge('solicitacoesPagamento',s.id,{asaasComprovante:url,asaasStatus:t.status||''}); }catch(_){}
          achou=true;
        }
      }catch(_){ /* silencioso */ }
    }
  }finally{ _autoComprovBusy=false; }
  if(achou) _refreshComprovanteViews();
}

// Re-renderiza as telas que mostram comprovante: Aprovações e a aba
// Pagamentos do cadastro (se o modal do colaborador estiver aberto).
function _refreshComprovanteViews(){
  renderAprovacoes();
  const m=document.getElementById('modal-employee');
  if(m && !m.classList.contains('hidden')){
    const eid=val('emp-id'); if(eid) renderEmpPagamentos(eid);
  }
}

// Aba "Pagamentos" do cadastro — lista os pagamentos PIX feitos ao
// colaborador (coleção solicitacoesPagamento): data, descrição, valor,
// status e o link do comprovante oficial.
let _empPagFiltro  = 'pago';   // filtro de status da aba: 'pago' | 'todos'
let _empPagAtualId = null;     // colaborador exibido na aba (para re-render)

// Troca do filtro de status — re-renderiza a aba.
function _empPagSetFiltro(sel){ _empPagFiltro = sel.value; renderEmpPagamentos(_empPagAtualId); }

// Marca/desmarca todas as caixas de seleção da lista.
function _empPagToggleAll(chk){
  document.querySelectorAll('#emp-pagamentos-list .emp-pag-chk').forEach(c=>{ c.checked = chk.checked; });
}

// Abre, cada um em uma aba, os comprovantes das linhas selecionadas.
function _empPagAbrirSelecionados(){
  const chks=[...document.querySelectorAll('#emp-pagamentos-list .emp-pag-chk:checked')];
  if(!chks.length){ toast('Selecione ao menos um comprovante (caixas à esquerda).','warning'); return; }
  let n=0;
  chks.forEach(c=>{ const u=c.dataset.comp; if(u){ window.open(u,'_blank','noopener'); n++; } });
  toast(n+' comprovante(s) aberto(s) — baixe o PDF em cada aba.', n?'success':'warning');
}

function renderEmpPagamentos(empId){
  const box=document.getElementById('emp-pagamentos-list'); if(!box) return;
  _empPagAtualId = empId || null;
  const todas=(State.solicitacoes||[])
    .filter(s=>empId && s.employeeId===empId)
    .sort((a,b)=>new Date(b.criadoEm||0)-new Date(a.criadoEm||0));
  if(!todas.length){
    box.innerHTML=`<div class="empty-state small"><i class="fa-solid fa-money-bill-wave"></i><p>Nenhum pagamento registrado</p></div>`;
    return;
  }
  _autoBuscarComprovantes();   // garante os comprovantes que ainda faltam
  const lista = _empPagFiltro==='pago' ? todas.filter(s=>s.status==='pago') : todas;
  const totalPago=todas.filter(s=>s.status==='pago').reduce((t,s)=>t+(s.valor||0),0);
  const barra=`<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;margin-bottom:10px">
    <label style="font-size:12px;color:#666">Mostrar:</label>
    <select id="emp-pag-filtro" onchange="_empPagSetFiltro(this)" style="padding:5px 9px;font-size:12px;border:1px solid var(--border);border-radius:6px">
      <option value="pago"${_empPagFiltro==='pago'?' selected':''}>Somente pagos</option>
      <option value="todos"${_empPagFiltro==='todos'?' selected':''}>Todos</option>
    </select>
    <button class="btn btn-sm btn-outline" style="color:#00695C;border-color:#00695C;font-size:12px" onclick="_empPagAbrirSelecionados()">
      <i class="fa-solid fa-up-right-from-square"></i> Abrir comprovantes selecionados
    </button>
  </div>`;
  if(!lista.length){
    box.innerHTML=barra+`<div class="empty-state small"><i class="fa-solid fa-money-bill-wave"></i><p>Nenhum pagamento com esse filtro</p></div>`;
    return;
  }
  const linhas=lista.map(s=>{
    const dt=((s.scheduleDate||s.criadoEm||'')+'').substring(0,10).split('-').reverse().join('/');
    let comp='<span style="color:#bbb">—</span>', chk='';
    if(s.status==='pago'){
      if(s.asaasComprovante){
        comp=`<a href="${s.asaasComprovante}" target="_blank" rel="noopener" style="color:#00695C;font-weight:600;text-decoration:none;white-space:nowrap"><i class="fa-solid fa-receipt"></i> Ver comprovante</a>`;
        chk=`<input type="checkbox" class="emp-pag-chk" data-comp="${s.asaasComprovante}">`;
      } else if(s.asaasTransferId){
        comp=`<button class="btn btn-sm btn-outline" style="color:#00695C;border-color:#00695C;font-size:11px;padding:3px 9px" onclick="verComprovante('${s.id}',this)"><i class="fa-solid fa-receipt"></i> Comprovante</button>`;
      } else {
        comp='<span style="font-size:11px;color:#999">pago</span>';
      }
    } else if(s.status==='recusado'){
      comp=`<span style="font-size:11px;color:#c62828">${s.motivoRecusa||'recusado'}</span>`;
    } else if(s.status==='erro'){
      comp=`<span style="font-size:11px;color:#c62828">${s.erro||'erro'}</span>`;
    } else if(s.status==='estornado'){
      comp=`<span style="font-size:11px;color:#E65100">${s.motivoEstorno||'estornado'}</span>`;
    }
    return `<tr style="border-bottom:1px solid var(--border)">
      <td style="padding:8px 6px;text-align:center;width:30px">${chk}</td>
      <td style="padding:8px 10px;font-size:12px;white-space:nowrap">${dt||'—'}</td>
      <td style="padding:8px 10px;font-size:12px">${s.descricao||s.origem||'—'}</td>
      <td style="padding:8px 10px;text-align:right;font-weight:700;color:#00695C;white-space:nowrap">${fmtMoney(s.valor||0)}</td>
      <td style="padding:8px 10px;text-align:center">${_aprovacaoStatusBadge(s.status)}</td>
      <td style="padding:8px 10px">${comp}</td>
    </tr>`;
  }).join('');
  box.innerHTML=barra+`
    <table style="width:100%;border-collapse:collapse">
      <thead><tr style="background:#f5f5f5">
        <th style="padding:7px 6px;text-align:center;width:30px"><input type="checkbox" onclick="_empPagToggleAll(this)" title="Selecionar todos"></th>
        <th style="padding:7px 10px;text-align:left;font-size:11px;color:#666">Data</th>
        <th style="padding:7px 10px;text-align:left;font-size:11px;color:#666">Descrição</th>
        <th style="padding:7px 10px;text-align:right;font-size:11px;color:#666">Valor</th>
        <th style="padding:7px 10px;text-align:center;font-size:11px;color:#666">Status</th>
        <th style="padding:7px 10px;text-align:left;font-size:11px;color:#666">Comprovante</th>
      </tr></thead>
      <tbody>${linhas}</tbody>
    </table>
    <div style="margin-top:10px;padding:8px 12px;background:#E8F5E9;border-radius:6px;font-size:13px;text-align:right">
      Total pago a este colaborador: <strong style="color:#00695C">${fmtMoney(totalPago)}</strong>
    </div>`;
}

// ============================================
// COMUNICAÇÕES — mensagens do gestor para o colaborador (Fase C)
// ============================================

// Utilitario: SHA-256 hex de um Blob/File ou string. Usa Web Crypto API
// (nativo no navegador, sem dependencia externa). Retorna sempre maiusculo.
// Usado para garantir integridade do anexo e da mensagem disciplinar —
// se o conteudo muda 1 byte, o hash muda completamente.
async function _sha256Hex(blobOrString){
  let buf;
  if(typeof blobOrString === 'string'){
    buf = new TextEncoder().encode(blobOrString);
  } else if(blobOrString instanceof Blob){
    buf = await blobOrString.arrayBuffer();
  } else {
    throw new Error('Tipo invalido para _sha256Hex');
  }
  const hash = await crypto.subtle.digest('SHA-256', buf);
  return Array.from(new Uint8Array(hash)).map(b => b.toString(16).padStart(2,'0')).join('').toUpperCase();
}

// Formata um hash hex em blocos de 4 caracteres para leitura humana
// (ex.: ABCD-1234-EF56-7890 ...) — usado nos recibos impressos.
function _formatHashLegivel(hex){
  return (hex||'').match(/.{1,4}/g)?.join('-') || hex || '';
}

let _comuDestinatarios     = [];
let _comuMensagensCache    = {};   // msgId → mensagem (para reenviar/editar)
let _comuAnexoHerdado      = null; // anexo da mensagem original (no Reenviar/Editar)
let _comuEditandoId        = null; // id da mensagem em edição (null = novo envio)

function openComunicarModal(empIdOrNull){
  const _mods=getUserModules(Auth.currentUser);
  if(!_mods.comunicacao && !_mods.employees && Auth.currentUser?.role!=='master'){
    toast('Você não tem permissão para enviar mensagens.','error'); return;
  }
  _comuDestinatarios = [];
  if(empIdOrNull){
    const emp=State.employees.find(e=>e.id===empIdOrNull);
    if(emp) _comuDestinatarios.push(emp.id);
  }
  const sel=document.getElementById('comu-add-emp');
  if(sel){
    sel.innerHTML='<option value="">— selecionar colaborador —</option>';
    State.employees
      .filter(e=>(e.status||'ativo')==='ativo')
      .sort((a,b)=>(a.nome||'').localeCompare(b.nome||'','pt-BR'))
      .forEach(e=>{
        const o=document.createElement('option');
        o.value=e.id; o.textContent=e.nome;
        sel.appendChild(o);
      });
  }
  setVal('comu-assunto','');
  setVal('comu-corpo','');
  setVal('comu-tipo','normal');
  setVal('comu-disc-motivo','');
  setVal('comu-disc-dias','');
  setVal('comu-disc-artigo','');
  const fi=document.getElementById('comu-anexo'); if(fi) fi.value='';
  _comuAnexoHerdado = null;
  _comuEditandoId   = null;
  // restaura o modal para o modo "Novo envio" (caso tenha sido aberto para edição antes)
  const _tituloEl = document.querySelector('#modal-comunicar .modal-header h3');
  if(_tituloEl) _tituloEl.innerHTML = '<i class="fa-solid fa-envelope" style="color:#1976D2"></i> Comunicar Colaborador';
  const _btnEnv = document.getElementById('comu-enviar');
  if(_btnEnv) _btnEnv.innerHTML = '<i class="fa-solid fa-paper-plane"></i> Enviar';
  const _addRow = document.getElementById('comu-add-emp')?.closest('.form-row');
  if(_addRow) _addRow.style.display = '';
  _comuRenderAnexoHerdado();
  _comuRenderDest();
  _comuOnTipoChange(); // garante que o painel de disciplina esta escondido
  document.getElementById('modal-comunicar').classList.remove('hidden');
}

// Quando o tipo de mensagem muda, mostra/esconde o painel de disciplina
// (motivo + dias de suspensao + artigo CLT) e ajusta visual do modal.
function _comuOnTipoChange(){
  const tipo  = (val('comu-tipo')||'normal').toLowerCase();
  const painel = document.getElementById('comu-disciplina-painel');
  const rowDias = document.getElementById('comu-disc-dias-row');
  const hint   = document.getElementById('comu-disc-hint');
  if(painel) painel.style.display = (tipo==='advertencia'||tipo==='suspensao') ? '' : 'none';
  if(rowDias) rowDias.style.display = (tipo==='suspensao') ? '' : 'none';
  // Borda colorida no modal pra reforcar visualmente que e' um documento disciplinar
  const dlg = document.querySelector('#modal-comunicar .modal-dialog');
  if(dlg){
    dlg.style.borderTop = (tipo==='advertencia') ? '4px solid #E65100'
                        : (tipo==='suspensao')   ? '4px solid #c62828'
                        : '';
  }
  if(hint){
    if(tipo==='advertencia'){
      hint.style.display = '';
      hint.style.color = '#E65100';
      hint.innerHTML = '⚠ <strong>Advertência:</strong> o anexo é obrigatório (PDF do documento assinado ou carta). O sistema vai calcular o SHA-256 do arquivo, criar Recibo de Envio e arquivar tudo na aba <strong>Disciplina</strong> do colaborador.';
    } else if(tipo==='suspensao'){
      hint.style.display = '';
      hint.style.color = '#c62828';
      hint.innerHTML = '⛔ <strong>Suspensão:</strong> informe os dias de afastamento. O anexo é obrigatório. O sistema cria Recibo de Envio com SHA-256 e arquiva na aba <strong>Disciplina</strong>.';
    } else {
      hint.style.display = 'none';
    }
  }
}

// Editar uma mensagem ja enviada: abre o composer pre-preenchido,
// trava o destinatario no original e salva por cima (DB.merge).
function editarMensagem(msgId){
  if(!getUserModules(Auth.currentUser).employees && Auth.currentUser?.role!=='master'){
    toast('Sem permissão para editar mensagens.','error'); return;
  }
  const m = _comuMensagensCache[msgId];
  if(!m){ toast('Mensagem não encontrada — recarregue a aba.','error'); return; }
  openComunicarModal();
  _comuEditandoId   = msgId;
  _comuDestinatarios = m.employeeId ? [m.employeeId] : [];
  setVal('comu-assunto', m.assunto||'');
  setVal('comu-corpo',   m.corpo||'');
  if(m.anexoUrl){
    _comuAnexoHerdado = { url:m.anexoUrl, nome:m.anexoNome||'anexo', tipo:m.anexoTipo||'' };
  }
  // Trava a UI de adicionar destinatários (edição mantém o mesmo recebedor)
  const addRow = document.getElementById('comu-add-emp')?.closest('.form-row');
  if(addRow) addRow.style.display = 'none';
  // Muda titulo + botao
  const titleEl = document.querySelector('#modal-comunicar .modal-header h3');
  if(titleEl) titleEl.innerHTML = '<i class="fa-solid fa-pen" style="color:#E65100"></i> Editar Mensagem';
  const btn = document.getElementById('comu-enviar');
  if(btn) btn.innerHTML = '<i class="fa-solid fa-floppy-disk"></i> Salvar alterações';
  _comuRenderAnexoHerdado();
  _comuRenderDest();
}

// Reenviar uma mensagem já enviada: abre o composer com assunto + corpo
// já preenchidos. O usuário escolhe os novos destinatários. Se a mensagem
// tinha anexo, ele é herdado (mesmo arquivo) — pode ser substituído por
// outro upload ou removido pelo link "remover".
function reenviarMensagem(msgId){
  const m = _comuMensagensCache[msgId];
  if(!m){ toast('Mensagem não encontrada — recarregue a aba.','error'); return; }
  openComunicarModal();
  setVal('comu-assunto', m.assunto||'');
  setVal('comu-corpo',   m.corpo||'');
  if(m.anexoUrl){
    _comuAnexoHerdado = { url:m.anexoUrl, nome:m.anexoNome||'anexo', tipo:m.anexoTipo||'' };
  }
  _comuRenderAnexoHerdado();
}

function _comuRenderAnexoHerdado(){
  const el = document.getElementById('comu-anexo-herdado'); if(!el) return;
  if(_comuAnexoHerdado){
    el.style.display='';
    el.innerHTML = `<i class="fa-solid fa-paperclip"></i> Anexo da mensagem original: <strong>${_comuAnexoHerdado.nome}</strong> — será reaproveitado se você não enviar outro arquivo. <button type="button" onclick="_comuLimparAnexoHerdado()" style="background:none;border:none;color:#c62828;cursor:pointer;font-size:11px;margin-left:6px;text-decoration:underline">remover</button>`;
  } else {
    el.style.display='none';
    el.innerHTML='';
  }
}
function _comuLimparAnexoHerdado(){ _comuAnexoHerdado=null; _comuRenderAnexoHerdado(); }

// ===========================================================================
// DISCIPLINA — advertencias e suspensoes (com cadeia de custodia SHA-256)
// ===========================================================================

// Gera o HTML do Recibo de Envio — documento que comprova que a empresa
// enviou advertencia/suspensao com hash do anexo e timestamp do servidor.
// O HTML e' arquivado no Storage e pode ser aberto/impressovia URL.
function _gerarReciboEnvioHTML(d){
  const dtBr = new Date(d.criadoEm).toLocaleString('pt-BR');
  const tipoLabel = d.tipo==='advertencia' ? 'ADVERTÊNCIA ESCRITA'
                  : d.tipo==='suspensao'   ? 'SUSPENSÃO DISCIPLINAR'
                  : 'COMUNICADO';
  const corTipo = d.tipo==='advertencia' ? '#E65100' : '#c62828';
  const esc = s => (s||'').toString().replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  const corpoEsc = esc(d.corpo).replace(/\n/g,'<br>');
  const motivoEsc = esc(d.motivoDisc).replace(/\n/g,'<br>');
  const hashAnexoFmt = _formatHashLegivel(d.anexoHash||'');
  const hashMsgFmt   = _formatHashLegivel(d.mensagemHash||'');
  return `<!DOCTYPE html><html lang="pt-BR"><head>
<meta charset="UTF-8"><title>Recibo de Envio — ${tipoLabel} — ${esc(d.empNome)}</title>
<style>
  @page{size:A4;margin:18mm 16mm}
  *{box-sizing:border-box;margin:0;padding:0}
  body{font-family:Arial,sans-serif;font-size:11px;color:#222;line-height:1.5}
  .header{display:flex;align-items:center;gap:14px;border-bottom:3px solid ${corTipo};padding-bottom:10px;margin-bottom:18px}
  .header h1{color:${corTipo};font-size:18px;letter-spacing:.5px}
  .header .empresa{color:#666;font-size:11px;margin-top:2px}
  .header .meta{margin-left:auto;text-align:right;font-size:9px;color:#888}
  .tipo-badge{display:inline-block;background:${corTipo};color:#fff;padding:4px 12px;border-radius:4px;font-size:11px;font-weight:700;letter-spacing:.5px;margin-bottom:14px}
  h2{font-size:12px;color:${corTipo};margin:18px 0 8px;text-transform:uppercase;letter-spacing:.5px;border-bottom:1px solid #eee;padding-bottom:3px}
  table{width:100%;border-collapse:collapse;margin-bottom:12px;font-size:11px}
  td{padding:5px 8px;border-bottom:1px solid #eee;vertical-align:top}
  td.l{font-weight:700;color:#475569;width:140px;background:#f8fafc}
  .corpo-box{background:#fafafa;border-left:4px solid ${corTipo};padding:10px 14px;margin:6px 0;font-size:11px;white-space:pre-wrap;line-height:1.5}
  .hash-box{background:#fff7ed;border:1px solid #fed7aa;border-radius:4px;padding:10px 12px;margin-top:6px}
  .hash-box .lbl{font-size:10px;color:#92400e;font-weight:700;text-transform:uppercase;letter-spacing:.5px;margin-bottom:3px}
  .hash-box .val{font-family:Consolas,'Courier New',monospace;font-size:10px;color:#451a03;word-break:break-all;font-weight:600}
  .footer{margin-top:24px;padding-top:12px;border-top:2px solid ${corTipo};font-size:10px;color:#555;line-height:1.6}
  .footer .impt{font-weight:700;color:${corTipo}}
  .assinatura{margin-top:36px;display:grid;grid-template-columns:1fr 1fr;gap:30px}
  .assinatura div{border-top:1px solid #333;padding-top:6px;text-align:center;font-size:10px;color:#444}
  .badge-info{background:#e0e7ff;color:#3730a3;padding:8px 12px;border-radius:6px;font-size:10px;margin-top:14px;line-height:1.5}
</style></head>
<body>
  <div class="header">
    <div>
      <h1>RECIBO DE ENVIO</h1>
      <div class="empresa">${esc(d.empresa)}</div>
    </div>
    <div class="meta">
      Documento ID:<br><strong>${esc(d.discId)}</strong><br>
      Emitido em ${dtBr}
    </div>
  </div>

  <div class="tipo-badge">${tipoLabel}</div>

  <h2>Identificação do Colaborador</h2>
  <table>
    <tr><td class="l">Nome</td><td><strong>${esc(d.empNome)}</strong></td></tr>
    <tr><td class="l">Matrícula</td><td>${esc(d.empMatricula)}</td></tr>
    <tr><td class="l">CPF</td><td>${esc(d.empCpf)}</td></tr>
    <tr><td class="l">Cargo</td><td>${esc(d.empCargo)}</td></tr>
    <tr><td class="l">Posto</td><td>${esc(d.empPosto)}</td></tr>
  </table>

  <h2>Dados do Ato Disciplinar</h2>
  <table>
    <tr><td class="l">Tipo</td><td><strong style="color:${corTipo}">${tipoLabel}</strong></td></tr>
    ${d.tipo==='suspensao' ? `<tr><td class="l">Dias de suspensão</td><td><strong>${esc(d.diasSusp)}</strong> dia(s)</td></tr>` : ''}
    <tr><td class="l">Motivo</td><td>${motivoEsc||'—'}</td></tr>
    ${d.artigoCLT ? `<tr><td class="l">Fundamento</td><td>${esc(d.artigoCLT)}</td></tr>` : ''}
    <tr><td class="l">Aplicado por</td><td>${esc(d.autorNome)}</td></tr>
    <tr><td class="l">Data/hora envio</td><td><strong>${dtBr}</strong></td></tr>
  </table>

  <h2>Conteúdo da Notificação</h2>
  <table>
    <tr><td class="l">Assunto</td><td><strong>${esc(d.assunto)}</strong></td></tr>
  </table>
  <div class="corpo-box">${corpoEsc}</div>

  <h2>Cadeia de Custódia — SHA-256</h2>
  <table>
    <tr><td class="l">Arquivo anexado</td><td><strong>${esc(d.anexoNome)}</strong></td></tr>
  </table>
  <div class="hash-box">
    <div class="lbl">SHA-256 do anexo</div>
    <div class="val">${hashAnexoFmt||'—'}</div>
  </div>
  ${hashMsgFmt ? `<div class="hash-box" style="margin-top:8px">
    <div class="lbl">SHA-256 da mensagem (conjunto)</div>
    <div class="val">${hashMsgFmt}</div>
  </div>` : ''}

  <div class="badge-info">
    <strong>ℹ Como verificar a integridade:</strong> baixe o anexo original e recalcule o SHA-256 (ferramentas como certutil no Windows, sha256sum no Linux/Mac).
    Se o hash bater com o registrado acima, o arquivo não foi alterado desde o envio.
    O timestamp e os identificadores são gerados pelo servidor do sistema.
  </div>

  <div class="footer">
    <p class="impt">Este recibo comprova o ENVIO do documento disciplinar pelo sistema DRG-Kronos.</p>
    <p>O documento original foi anexado e seu hash criptográfico SHA-256 está registrado acima.</p>
    <p>Um Recibo de Recebimento separado é gerado quando o colaborador visualiza a mensagem no app.</p>
    <p style="margin-top:8px">ID da comunicação: <code>${esc(d.comunicacaoId)}</code> · ID disciplina: <code>${esc(d.discId)}</code></p>
  </div>

  <div class="assinatura">
    <div>Pelo empregador<br><br><br>${esc(d.autorNome)}</div>
    <div>Pelo colaborador<br><br><br>${esc(d.empNome)}<br>Matrícula ${esc(d.empMatricula)}</div>
  </div>

</body></html>`;
}

// Modal pos-envio de disciplina — oferece abrir o e-mail (mailto) e ver o recibo
function _abrirPosEnvioDisciplina(disc){
  const e = State.employees.find(x=>x.id===disc.employeeId);
  const emailEmp = (e && e.email) || '';
  const tipoLabel = disc.tipo==='advertencia' ? 'Advertência' : 'Suspensão';
  const linhas = [
    `<strong>${tipoLabel}</strong> registrada para <strong>${(e&&e.nome)||disc.employeeNome}</strong>.`,
    `<small style="color:#666">SHA-256: <code style="font-size:11px">${(disc.anexoHash||'').substring(0,32)}...</code></small>`,
    '',
    'Próximas ações disponíveis:'
  ];
  const html = `
    <div style="padding:18px;max-width:520px">
      <div style="font-size:14px;line-height:1.6;margin-bottom:14px">${linhas.join('<br>')}</div>
      <div style="display:flex;gap:8px;flex-wrap:wrap">
        ${disc.reciboEnvioUrl ? `<a href="${disc.reciboEnvioUrl}" target="_blank" rel="noopener" class="btn btn-primary"><i class="fa-solid fa-file-pdf"></i> Ver Recibo de Envio</a>` : ''}
        <a href="${disc.anexoUrl}" target="_blank" rel="noopener" class="btn btn-outline"><i class="fa-solid fa-paperclip"></i> Abrir anexo</a>
        ${emailEmp
          ? `<button class="btn btn-outline" onclick="_abrirMailtoDisciplina('${disc.id}')"><i class="fa-solid fa-envelope"></i> Abrir e-mail para ${emailEmp}</button>`
          : `<span style="font-size:12px;color:#999;padding:6px 10px">⚠ Colaborador sem e-mail cadastrado</span>`}
      </div>
      <div style="font-size:11px;color:#888;margin-top:12px">A mensagem ja' chegou no app do colaborador. O Recibo de Recebimento sera gerado quando ele visualizar.</div>
    </div>`;
  _showFloatingModal('Ato disciplinar registrado', html);
  // guarda o recente para o mailto encontrar
  window._discRecente = disc;
}

// Abre o cliente de e-mail (Outlook/Gmail/Apple Mail) com destinatario, assunto
// e corpo ja' preenchidos. Anexos nao sao suportados via mailto:, entao
// incluimos os links do anexo e do recibo no corpo.
function _abrirMailtoDisciplina(discId){
  const disc = window._discRecente;
  if(!disc || disc.id!==discId){ toast('Dados não encontrados — feche e refaça.','error'); return; }
  const e = State.employees.find(x=>x.id===disc.employeeId);
  const emailEmp = (e && e.email) || '';
  if(!emailEmp){ toast('Colaborador sem e-mail cadastrado.','error'); return; }
  const tipoLabel = disc.tipo==='advertencia' ? 'Advertência Escrita' : 'Suspensão Disciplinar';
  const subject = `${tipoLabel} — ${(e&&e.nome)||disc.employeeNome}`;
  const lines = [
    `Prezado(a) ${(e&&e.nome)||disc.employeeNome},`,
    '',
    `Comunicamos oficialmente a aplicação de ${tipoLabel.toLowerCase()}, conforme documento em anexo.`,
    '',
    disc.tipo==='suspensao' ? `Dias de suspensão: ${disc.diasSuspensao}` : '',
    disc.motivo ? `Motivo: ${disc.motivo}` : '',
    disc.artigoCLT ? `Fundamento: ${disc.artigoCLT}` : '',
    '',
    `Documento anexado: ${disc.anexoUrl}`,
    disc.reciboEnvioUrl ? `Recibo de Envio: ${disc.reciboEnvioUrl}` : '',
    '',
    `SHA-256 do documento: ${disc.anexoHash}`,
    `Data/hora de envio: ${new Date(disc.criadoEm).toLocaleString('pt-BR')}`,
    '',
    `A mesma mensagem foi enviada para o app do colaborador.`,
    '',
    `Atenciosamente,`,
    `${disc.criadoPorNome}`,
    `${_e('nomeEmpresa')}`
  ].filter(s => s !== undefined);
  const body = lines.join('\n');
  const href = `mailto:${encodeURIComponent(emailEmp)}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  window.location.href = href;
}

// Render do conteudo da aba Disciplina no modal do colaborador
async function renderDisciplinaTab(empId){
  const box = document.getElementById('emp-disciplina-list'); if(!box) return;
  if(!empId){
    box.innerHTML = `<div class="empty-state small"><i class="fa-solid fa-gavel"></i><p>Salve o colaborador para registrar atos disciplinares</p></div>`;
    return;
  }
  box.innerHTML = '<div style="text-align:center;padding:20px;color:#999"><i class="fa-solid fa-spinner fa-spin"></i> Carregando disciplina...</div>';
  let lista = [];
  try{
    const snap = await firebase.firestore().collection('disciplina').where('employeeId','==',empId).get();
    lista = snap.docs.map(d => ({ id:d.id, ...d.data() }));
  }catch(e){ console.error('disciplina:fetch', e); }
  lista.sort((a,b) => (b.criadoEm||'').localeCompare(a.criadoEm||''));
  // Anuladas nao contam nas estatisticas — sao registros historicos
  const ativas = lista.filter(x => !x.anulada);
  const totAdv = ativas.filter(x=>x.tipo==='advertencia').length;
  const totSus = ativas.filter(x=>x.tipo==='suspensao').length;
  const totAnul = lista.filter(x=>x.anulada).length;
  const fmtDt = iso => { const d=iso?new Date(iso):null; if(!d||isNaN(d.getTime())) return '—'; return d.toLocaleDateString('pt-BR') + ' ' + d.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}); };
  const podeAnular = !!getUserModules(Auth.currentUser).disciplinaApagar || Auth.currentUser?.role==='master';
  let html = `
    <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;margin-bottom:12px">
      <div>
        <strong style="font-size:13px">Atos disciplinares (${ativas.length}${totAnul?` · ${totAnul} anulado(s)`:''})</strong>
        <div style="font-size:11px;color:#888;margin-top:2px">${totAdv} advertência(s) · ${totSus} suspensão(ões) vigentes</div>
      </div>
      <button class="btn btn-sm btn-primary" onclick="_abrirNovaDisciplinaParaColaborador('${empId}')" style="font-size:12px">
        <i class="fa-solid fa-gavel"></i> Nova advertência/suspensão
      </button>
    </div>`;
  if(!lista.length){
    html += `<div class="empty-state small"><i class="fa-solid fa-folder-open"></i><p>Sem atos disciplinares registrados</p></div>`;
  } else {
    html += lista.map(d => {
      const anulada = !!d.anulada;
      const cor = anulada ? '#94a3b8'
                : d.tipo==='advertencia' ? '#E65100' : '#c62828';
      const bg  = anulada ? '#f1f5f9'
                : d.tipo==='advertencia' ? '#fff7ed' : '#fee2e2';
      const lbl = d.tipo==='advertencia' ? 'ADVERTÊNCIA' : 'SUSPENSÃO';
      const styleTexto = anulada ? 'opacity:.65' : '';
      const styleAnul  = anulada ? 'text-decoration:line-through' : '';
      const hash16 = (d.anexoHash||'').substring(0,16);
      const recb = d.visualizadoEm
        ? `<span style="color:#16a34a;font-weight:600">✓✓ Visualizada em ${fmtDt(d.visualizadoEm)}</span>`
        : `<span style="color:#94a3b8">⏳ Aguardando visualização no app</span>`;
      // Bloco de anulacao (quando aplicavel)
      const anulHtml = anulada
        ? `<div style="background:#1e293b;color:#fff;border-radius:6px;padding:10px 12px;margin:8px 0;font-size:11.5px;line-height:1.5">
            <strong style="color:#fca5a5">⊘ ANULADA</strong> em ${fmtDt(d.anuladaEm)} por <strong>${(d.anuladaPorNome||'—').replace(/</g,'&lt;')}</strong>
            <div style="margin-top:4px;color:#cbd5e1">Motivo: ${(d.motivoAnulacao||'—').replace(/</g,'&lt;')}</div>
          </div>`
        : '';
      // Botao anular — so' aparece para quem tem permissao E se ainda nao foi anulada
      const btnAnular = (podeAnular && !anulada)
        ? `<button class="btn btn-sm btn-outline" onclick="anularDisciplina('${d.id}')" style="font-size:11px;color:#c62828;border-color:#ef9a9a;margin-left:auto"><i class="fa-solid fa-ban"></i> Anular</button>`
        : '';
      return `<div style="background:${bg};border-left:4px solid ${cor};border-radius:8px;padding:12px 14px;margin-bottom:10px;${styleTexto}">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:10px;margin-bottom:6px">
          <div style="${styleAnul}">
            <span style="background:${cor};color:#fff;padding:2px 8px;border-radius:4px;font-size:10px;font-weight:700;letter-spacing:.5px">${lbl}</span>
            ${d.tipo==='suspensao' && d.diasSuspensao ? `<span style="margin-left:6px;font-size:11px;color:${cor};font-weight:600">${d.diasSuspensao} dia(s)</span>` : ''}
          </div>
          <span style="font-size:11px;color:#666">${fmtDt(d.criadoEm)}</span>
        </div>
        ${anulHtml}
        ${d.motivo ? `<div style="font-size:12px;color:#333;margin:6px 0;line-height:1.5;${styleAnul}"><strong>Motivo:</strong> ${(d.motivo||'').replace(/</g,'&lt;')}</div>` : ''}
        ${d.artigoCLT ? `<div style="font-size:11px;color:#666;${styleAnul}"><strong>Fundamento:</strong> ${(d.artigoCLT||'').replace(/</g,'&lt;')}</div>` : ''}
        <div style="font-size:11px;color:#666;margin-top:6px">Aplicado por ${d.criadoPorNome||'—'}</div>
        <div style="margin-top:8px;padding:8px;background:rgba(255,255,255,.6);border-radius:6px;font-size:11px;font-family:Consolas,monospace;color:#555">
          🔒 SHA-256: <strong>${hash16}...${d.anexoHash?d.anexoHash.substring(d.anexoHash.length-8):''}</strong>
        </div>
        ${!anulada ? `<div style="margin-top:8px;font-size:11px">${recb}</div>` : ''}
        <div style="margin-top:10px;padding-top:8px;border-top:1px dashed rgba(0,0,0,.1);display:flex;gap:6px;flex-wrap:wrap;align-items:center">
          ${d.anexoUrl ? `<a href="${d.anexoUrl}" target="_blank" rel="noopener" class="btn btn-sm btn-outline" style="font-size:11px"><i class="fa-solid fa-paperclip"></i> ${(d.anexoNome||'anexo').substring(0,30)}</a>` : ''}
          ${d.reciboEnvioUrl ? `<a href="${d.reciboEnvioUrl}" target="_blank" rel="noopener" class="btn btn-sm btn-outline" style="font-size:11px;color:#1976D2;border-color:#1976D2"><i class="fa-solid fa-file-pdf"></i> Recibo de Envio</a>` : ''}
          ${d.reciboRecebimentoUrl ? `<a href="${d.reciboRecebimentoUrl}" target="_blank" rel="noopener" class="btn btn-sm btn-outline" style="font-size:11px;color:#16a34a;border-color:#16a34a"><i class="fa-solid fa-file-circle-check"></i> Recibo de Recebimento</a>` : ''}
          <button class="btn btn-sm btn-outline" onclick="_verHashesDisciplina('${d.id}')" style="font-size:11px;color:#7e22ce;border-color:#c084fc"><i class="fa-solid fa-fingerprint"></i> Hashes (auditoria)</button>
          ${btnAnular}
        </div>
      </div>`;
    }).join('');
  }
  box.innerHTML = html;
}

// Atalho: abre o modal de comunicar ja' pre-configurado para advertencia
function _abrirNovaDisciplinaParaColaborador(empId){
  openComunicarModal(empId);
  setVal('comu-tipo','advertencia');
  _comuOnTipoChange();
}

// Mostra os hashes completos em modal flutuante (para auditoria/comparacao)
function _verHashesDisciplina(discId){
  firebase.firestore().collection('disciplina').doc(discId).get().then(snap => {
    if(!snap.exists){ toast('Registro nao encontrado.','error'); return; }
    const d = snap.data();
    const html = `
      <div style="padding:18px;max-width:620px;font-size:12px">
        <div style="margin-bottom:14px;color:#555">
          <strong>Cadeia de custódia — SHA-256</strong><br>
          Use estes hashes para verificar a integridade do documento. Se voce baixar o anexo e recalcular o SHA-256, deve dar exatamente o mesmo valor.
        </div>
        <div style="background:#fff7ed;border:1px solid #fed7aa;border-radius:6px;padding:10px;margin-bottom:10px">
          <div style="font-size:11px;color:#92400e;font-weight:700;text-transform:uppercase;letter-spacing:.4px;margin-bottom:4px">Hash do anexo</div>
          <div style="font-family:Consolas,monospace;font-size:11px;color:#451a03;word-break:break-all;font-weight:600">${_formatHashLegivel(d.anexoHash||'—')}</div>
        </div>
        ${d.mensagemHash ? `<div style="background:#fff7ed;border:1px solid #fed7aa;border-radius:6px;padding:10px;margin-bottom:10px">
          <div style="font-size:11px;color:#92400e;font-weight:700;text-transform:uppercase;letter-spacing:.4px;margin-bottom:4px">Hash da mensagem (conjunto)</div>
          <div style="font-family:Consolas,monospace;font-size:11px;color:#451a03;word-break:break-all;font-weight:600">${_formatHashLegivel(d.mensagemHash)}</div>
        </div>` : ''}
        <div style="background:#f0f9ff;border:1px solid #bae6fd;border-radius:6px;padding:10px;font-size:11px;color:#0c4a6e;line-height:1.5">
          <strong>Como verificar no Windows:</strong><br>
          <code style="background:#fff;padding:2px 4px;border-radius:3px">certutil -hashfile "${(d.anexoNome||'arquivo').replace(/"/g,'\\"')}" SHA256</code>
        </div>
        <div style="margin-top:10px;font-size:11px;color:#888">
          ID disciplina: <code>${discId}</code><br>
          ID comunicação: <code>${d.comunicacaoId||'—'}</code><br>
          Registrado em: ${new Date(d.criadoEm).toLocaleString('pt-BR')}
        </div>
      </div>`;
    _showFloatingModal('Hashes de auditoria', html);
  }).catch(e => toast('Erro: '+(e.message||e),'error'));
}

// ===========================================================================
// HORARIOS / ESCALAS — periodos de mudanca + overrides por dia
// ===========================================================================
// Modelo de dados (no doc do colaborador):
//   historicoEscalas: [
//     { id, de, ate, escala, horarioEntrada, horarioRefIni, horarioRefFim,
//       horarioSaida, observacao, criadoEm, criadoPorNome }
//   ]
//   overridesHorario: [
//     { id, data, tipo, escala, horarioEntrada, horarioRefIni, horarioRefFim,
//       horarioSaida, observacao, criadoEm, criadoPorNome }
//   ]
// tipo do override: 'diferente' (horario diferente) ou 'folga' (dia livre).

// Resolve a escala/horarios validos numa data (YYYY-MM-DD ou Date).
// Prioridade: override do dia → periodo ativo → cadastro principal.
function escalaVigenteEm(emp, dataYMD){
  if(!emp) return null;
  let ymd;
  if(typeof dataYMD === 'string'){
    ymd = dataYMD;
  } else if(dataYMD instanceof Date){
    const y=dataYMD.getFullYear(), m=String(dataYMD.getMonth()+1).padStart(2,'0'), d=String(dataYMD.getDate()).padStart(2,'0');
    ymd = `${y}-${m}-${d}`;
  } else return null;
  // 1) Override do dia (mais especifico)
  const ov = (emp.overridesHorario||[]).find(o => o.data === ymd);
  if(ov) return { ...ov, origem: 'override' };
  // 2) Periodo ativo (mais recente primeiro)
  const periodos = (emp.historicoEscalas||[]).slice().sort((a,b) => (b.de||'').localeCompare(a.de||''));
  for(const p of periodos){
    const ini = p.de || '';
    const fim = p.ate || '9999-12-31';
    if(ini && ini <= ymd && ymd <= fim){
      return { ...p, origem: 'periodo' };
    }
  }
  // 3) Fallback: cadastro principal
  return {
    escala:         emp.escala || '5x2A',
    horarioEntrada: emp.horarioEntrada || '',
    horarioRefIni:  emp.horarioRefIni  || '',
    horarioRefFim:  emp.horarioRefFim  || '',
    horarioSaida:   emp.horarioSaida   || '',
    origem: 'cadastro'
  };
}

function _fmtDtBr(ymd){
  if(!ymd) return '—';
  const p = ymd.split('-');
  return p.length===3 ? `${p[2]}/${p[1]}/${p[0]}` : ymd;
}

// Render principal da aba "Horários/Escalas" — chamada pelo loadEmployee
function renderHorariosTab(empId){
  // Preview do horario padrao do cadastro
  const prev = document.getElementById('hor-padrao-preview');
  if(prev){
    const ent = val('emp-horario-entrada')||'—';
    const sai = val('emp-horario-saida')||'—';
    const rIni = val('emp-horario-ref-ini')||'—';
    const rFim = val('emp-horario-ref-fim')||'—';
    const esc = val('emp-escala')||'5x2A';
    prev.innerHTML = `
      <div style="font-size:12px;color:#475569;margin-bottom:6px"><strong>Horário padrão do cadastro:</strong></div>
      <div style="display:flex;gap:14px;flex-wrap:wrap;font-size:13px">
        <span><strong>Escala:</strong> ${escalaLabel(esc)}</span>
        <span><strong>Entrada:</strong> ${ent}</span>
        <span><strong>Almoço:</strong> ${rIni} – ${rFim}</span>
        <span><strong>Saída:</strong> ${sai}</span>
      </div>`;
  }
  const emp = empId ? State.employees.find(e=>e.id===empId) : null;
  const boxPer = document.getElementById('hor-periodos-list');
  const boxOvr = document.getElementById('hor-overrides-list');
  if(!emp){
    if(boxPer) boxPer.innerHTML = '<div class="empty-state small"><i class="fa-solid fa-calendar"></i><p>Salve o colaborador para cadastrar períodos</p></div>';
    if(boxOvr) boxOvr.innerHTML = '<div class="empty-state small"><i class="fa-solid fa-calendar"></i><p>Salve o colaborador para cadastrar dias avulsos</p></div>';
    return;
  }
  // Periodos
  const periodos = (emp.historicoEscalas||[]).slice().sort((a,b) => (b.de||'').localeCompare(a.de||''));
  if(!periodos.length){
    boxPer.innerHTML = '<div class="empty-state small"><i class="fa-solid fa-calendar-range"></i><p>Nenhum período de mudança cadastrado.</p></div>';
  } else {
    const hoje = new Date().toISOString().split('T')[0];
    boxPer.innerHTML = periodos.map(p => {
      const ativo = (p.de||'') <= hoje && (!p.ate || p.ate >= hoje);
      const fim = p.ate ? _fmtDtBr(p.ate) : '<em>indefinido</em>';
      const escTxt = p.escala ? escalaLabel(p.escala) : '<em>(mantém cadastro)</em>';
      return `<div style="background:${ativo?'#dcfce7':'#fff'};border:1px solid ${ativo?'#86efac':'var(--border)'};border-left:4px solid ${ativo?'#16a34a':'#94a3b8'};border-radius:7px;padding:10px 12px;margin-bottom:8px">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:8px">
          <div style="flex:1;min-width:0">
            <div style="font-size:13px;font-weight:600;color:var(--text)">
              ${_fmtDtBr(p.de)} → ${fim}
              ${ativo?'<span style="background:#16a34a;color:#fff;padding:1px 7px;border-radius:9px;font-size:10px;font-weight:700;margin-left:6px">ATIVO HOJE</span>':''}
            </div>
            <div style="font-size:11px;color:#64748b;margin-top:3px"><strong>Escala:</strong> ${escTxt}</div>
            <div style="font-size:11px;color:#64748b">
              <strong>Entrada:</strong> ${p.horarioEntrada||'—'} ·
              <strong>Almoço:</strong> ${p.horarioRefIni||'—'} – ${p.horarioRefFim||'—'} ·
              <strong>Saída:</strong> ${p.horarioSaida||'—'}
            </div>
            ${p.observacao?`<div style="font-size:11px;color:#666;margin-top:4px;font-style:italic">"${p.observacao.replace(/</g,'&lt;')}"</div>`:''}
            <div style="font-size:10px;color:#94a3b8;margin-top:4px">Criado por ${p.criadoPorNome||'—'}</div>
          </div>
          <div style="display:flex;gap:6px;flex-shrink:0">
            <button type="button" class="btn btn-sm btn-outline" onclick="editarPeriodoEscala('${p.id}')" style="font-size:11px;padding:4px 10px"><i class="fa-solid fa-pen"></i></button>
            <button type="button" class="btn btn-sm btn-outline" onclick="removerPeriodoEscala('${p.id}')" style="font-size:11px;padding:4px 10px;color:#c62828;border-color:#ef9a9a"><i class="fa-solid fa-trash"></i></button>
          </div>
        </div>
      </div>`;
    }).join('');
  }
  // Overrides
  const overrides = (emp.overridesHorario||[]).slice().sort((a,b) => (b.data||'').localeCompare(a.data||''));
  if(!overrides.length){
    boxOvr.innerHTML = '<div class="empty-state small"><i class="fa-solid fa-calendar-day"></i><p>Nenhum dia avulso cadastrado.</p></div>';
  } else {
    boxOvr.innerHTML = overrides.map(o => {
      const ehFolga = o.tipo === 'folga';
      return `<div style="background:#fff;border:1px solid var(--border);border-left:4px solid ${ehFolga?'#7e22ce':'#E65100'};border-radius:7px;padding:10px 12px;margin-bottom:8px">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:8px">
          <div style="flex:1;min-width:0">
            <div style="font-size:13px;font-weight:600;color:var(--text)">${_fmtDtBr(o.data)}
              <span style="background:${ehFolga?'#7e22ce':'#E65100'};color:#fff;padding:1px 8px;border-radius:9px;font-size:10px;font-weight:700;margin-left:6px">${ehFolga?'FOLGA':'HORÁRIO DIFERENTE'}</span>
            </div>
            ${!ehFolga ? `<div style="font-size:11px;color:#64748b;margin-top:3px">
              <strong>Entrada:</strong> ${o.horarioEntrada||'—'} ·
              <strong>Almoço:</strong> ${o.horarioRefIni||'—'} – ${o.horarioRefFim||'—'} ·
              <strong>Saída:</strong> ${o.horarioSaida||'—'}
            </div>` : ''}
            ${o.observacao?`<div style="font-size:11px;color:#666;margin-top:4px;font-style:italic">"${o.observacao.replace(/</g,'&lt;')}"</div>`:''}
            <div style="font-size:10px;color:#94a3b8;margin-top:4px">Criado por ${o.criadoPorNome||'—'}</div>
          </div>
          <div style="display:flex;gap:6px;flex-shrink:0">
            <button type="button" class="btn btn-sm btn-outline" onclick="editarOverrideEscala('${o.id}')" style="font-size:11px;padding:4px 10px"><i class="fa-solid fa-pen"></i></button>
            <button type="button" class="btn btn-sm btn-outline" onclick="removerOverrideEscala('${o.id}')" style="font-size:11px;padding:4px 10px;color:#c62828;border-color:#ef9a9a"><i class="fa-solid fa-trash"></i></button>
          </div>
        </div>
      </div>`;
    }).join('');
  }
}

// ── Periodo de escala — abrir/editar/salvar/remover ──────────────────────
function abrirNovoPeriodoEscala(){
  const empId = val('emp-id');
  if(!empId){ toast('Salve o colaborador primeiro.','warning'); return; }
  setVal('per-esc-id','');
  setVal('per-esc-de','');
  setVal('per-esc-ate','');
  setVal('per-esc-escala','');
  setVal('per-esc-entrada','');
  setVal('per-esc-saida','');
  setVal('per-esc-ref-ini','');
  setVal('per-esc-ref-fim','');
  setVal('per-esc-obs','');
  document.getElementById('modal-periodo-escala').classList.remove('hidden');
}

function editarPeriodoEscala(periodoId){
  const empId = val('emp-id');
  const emp = State.employees.find(e=>e.id===empId);
  if(!emp) return;
  const p = (emp.historicoEscalas||[]).find(x => x.id===periodoId);
  if(!p){ toast('Período não encontrado.','error'); return; }
  setVal('per-esc-id', p.id);
  setVal('per-esc-de', p.de||'');
  setVal('per-esc-ate', p.ate||'');
  setVal('per-esc-escala', p.escala||'');
  setVal('per-esc-entrada', p.horarioEntrada||'');
  setVal('per-esc-saida', p.horarioSaida||'');
  setVal('per-esc-ref-ini', p.horarioRefIni||'');
  setVal('per-esc-ref-fim', p.horarioRefFim||'');
  setVal('per-esc-obs', p.observacao||'');
  document.getElementById('modal-periodo-escala').classList.remove('hidden');
}

async function salvarPeriodoEscala(){
  const empId = val('emp-id');
  const emp = State.employees.find(e=>e.id===empId);
  if(!emp){ toast('Colaborador não encontrado.','error'); return; }
  const de = val('per-esc-de');
  if(!de){ toast('Informe a data de início.','warning'); return; }
  const ate = val('per-esc-ate') || '';
  if(ate && ate < de){ toast('Data fim deve ser maior ou igual à de início.','error'); return; }
  const periodId = val('per-esc-id') || genId();
  const quem = (Auth.currentUser && (Auth.currentUser.username||Auth.currentUser.id))||'—';
  const ja = (emp.historicoEscalas||[]).find(p => p.id===periodId);
  const novo = {
    id: periodId,
    de,
    ate: ate || '',
    escala:          val('per-esc-escala') || '',
    horarioEntrada:  val('per-esc-entrada') || '',
    horarioRefIni:   val('per-esc-ref-ini') || '',
    horarioRefFim:   val('per-esc-ref-fim') || '',
    horarioSaida:    val('per-esc-saida') || '',
    observacao:      val('per-esc-obs') || '',
    criadoEm:        ja ? ja.criadoEm : new Date().toISOString(),
    criadoPorNome:   ja ? ja.criadoPorNome : quem,
    updatedAt:       new Date().toISOString(),
  };
  emp.historicoEscalas = (emp.historicoEscalas||[]).filter(p => p.id !== periodId);
  emp.historicoEscalas.push(novo);
  try{
    await DB.merge('employees', emp.id, { historicoEscalas: emp.historicoEscalas, updatedAt: new Date().toISOString() });
    try{ Auth.log(ja?'ESCALA_PERIODO_EDIT':'ESCALA_PERIODO_NEW', null, `${emp.nome} | ${de} → ${ate||'—'}`); }catch(_){}
    closeModal('modal-periodo-escala');
    toast(ja?'Período atualizado.':'Período cadastrado.','success');
    renderHorariosTab(emp.id);
  }catch(e){
    toast('Erro ao salvar: '+(e.message||e),'error');
  }
}

async function removerPeriodoEscala(periodoId){
  const empId = val('emp-id');
  const emp = State.employees.find(e=>e.id===empId);
  if(!emp) return;
  const p = (emp.historicoEscalas||[]).find(x => x.id===periodoId);
  if(!p) return;
  if(!confirm(`Remover este período (${_fmtDtBr(p.de)} → ${p.ate?_fmtDtBr(p.ate):'indefinido'})?`)) return;
  emp.historicoEscalas = (emp.historicoEscalas||[]).filter(x => x.id !== periodoId);
  try{
    await DB.merge('employees', emp.id, { historicoEscalas: emp.historicoEscalas, updatedAt: new Date().toISOString() });
    try{ Auth.log('ESCALA_PERIODO_DEL', null, `${emp.nome} | ${p.de} → ${p.ate||'—'}`); }catch(_){}
    toast('Período removido.','success');
    renderHorariosTab(emp.id);
  }catch(e){ toast('Erro: '+(e.message||e),'error'); }
}

// ── Override por dia — abrir/editar/salvar/remover ───────────────────────
function abrirNovoOverrideEscala(){
  const empId = val('emp-id');
  if(!empId){ toast('Salve o colaborador primeiro.','warning'); return; }
  setVal('ovr-esc-id','');
  setVal('ovr-esc-data','');
  setVal('ovr-esc-tipo','diferente');
  setVal('ovr-esc-entrada','');
  setVal('ovr-esc-saida','');
  setVal('ovr-esc-ref-ini','');
  setVal('ovr-esc-ref-fim','');
  setVal('ovr-esc-obs','');
  _ovrEscTipoChange();
  document.getElementById('modal-override-escala').classList.remove('hidden');
  // Hook do change para mostrar/esconder campos de horario quando vira folga
  document.getElementById('ovr-esc-tipo').onchange = _ovrEscTipoChange;
}

function _ovrEscTipoChange(){
  const tipo = val('ovr-esc-tipo');
  const campos = document.getElementById('ovr-esc-campos-horario');
  if(campos) campos.style.display = (tipo==='folga') ? 'none' : '';
}

function editarOverrideEscala(overrideId){
  const empId = val('emp-id');
  const emp = State.employees.find(e=>e.id===empId);
  if(!emp) return;
  const o = (emp.overridesHorario||[]).find(x => x.id===overrideId);
  if(!o){ toast('Dia avulso não encontrado.','error'); return; }
  setVal('ovr-esc-id', o.id);
  setVal('ovr-esc-data', o.data||'');
  setVal('ovr-esc-tipo', o.tipo||'diferente');
  setVal('ovr-esc-entrada', o.horarioEntrada||'');
  setVal('ovr-esc-saida', o.horarioSaida||'');
  setVal('ovr-esc-ref-ini', o.horarioRefIni||'');
  setVal('ovr-esc-ref-fim', o.horarioRefFim||'');
  setVal('ovr-esc-obs', o.observacao||'');
  _ovrEscTipoChange();
  document.getElementById('modal-override-escala').classList.remove('hidden');
  document.getElementById('ovr-esc-tipo').onchange = _ovrEscTipoChange;
}

async function salvarOverrideEscala(){
  const empId = val('emp-id');
  const emp = State.employees.find(e=>e.id===empId);
  if(!emp){ toast('Colaborador não encontrado.','error'); return; }
  const data = val('ovr-esc-data');
  if(!data){ toast('Informe a data.','warning'); return; }
  const ovrId = val('ovr-esc-id') || genId();
  const ja = (emp.overridesHorario||[]).find(o => o.id===ovrId);
  // Tambem checa duplicidade de data (uma so' override por dia)
  const conflito = (emp.overridesHorario||[]).find(o => o.data===data && o.id !== ovrId);
  if(conflito){ toast('Já existe um override para esta data — edite o existente.','error'); return; }
  const quem = (Auth.currentUser && (Auth.currentUser.username||Auth.currentUser.id))||'—';
  const tipo = val('ovr-esc-tipo')||'diferente';
  const novo = {
    id: ovrId,
    data,
    tipo, // 'diferente' | 'folga'
    horarioEntrada:  tipo==='folga' ? '' : (val('ovr-esc-entrada')||''),
    horarioRefIni:   tipo==='folga' ? '' : (val('ovr-esc-ref-ini')||''),
    horarioRefFim:   tipo==='folga' ? '' : (val('ovr-esc-ref-fim')||''),
    horarioSaida:    tipo==='folga' ? '' : (val('ovr-esc-saida')||''),
    observacao:      val('ovr-esc-obs')||'',
    criadoEm:        ja ? ja.criadoEm : new Date().toISOString(),
    criadoPorNome:   ja ? ja.criadoPorNome : quem,
    updatedAt:       new Date().toISOString(),
  };
  emp.overridesHorario = (emp.overridesHorario||[]).filter(o => o.id !== ovrId);
  emp.overridesHorario.push(novo);
  try{
    await DB.merge('employees', emp.id, { overridesHorario: emp.overridesHorario, updatedAt: new Date().toISOString() });
    try{ Auth.log(ja?'ESCALA_OVR_EDIT':'ESCALA_OVR_NEW', null, `${emp.nome} | ${data} | ${tipo}`); }catch(_){}
    closeModal('modal-override-escala');
    toast(ja?'Dia avulso atualizado.':'Dia avulso cadastrado.','success');
    renderHorariosTab(emp.id);
  }catch(e){
    toast('Erro ao salvar: '+(e.message||e),'error');
  }
}

async function removerOverrideEscala(overrideId){
  const empId = val('emp-id');
  const emp = State.employees.find(e=>e.id===empId);
  if(!emp) return;
  const o = (emp.overridesHorario||[]).find(x => x.id===overrideId);
  if(!o) return;
  if(!confirm(`Remover override do dia ${_fmtDtBr(o.data)}?`)) return;
  emp.overridesHorario = (emp.overridesHorario||[]).filter(x => x.id !== overrideId);
  try{
    await DB.merge('employees', emp.id, { overridesHorario: emp.overridesHorario, updatedAt: new Date().toISOString() });
    try{ Auth.log('ESCALA_OVR_DEL', null, `${emp.nome} | ${o.data}`); }catch(_){}
    toast('Dia avulso removido.','success');
    renderHorariosTab(emp.id);
  }catch(e){ toast('Erro: '+(e.message||e),'error'); }
}

// Mini-modal flutuante reutilizavel (igual ao de stats)
function _showFloatingModal(titulo, htmlConteudo){
  const old = document.getElementById('modal-floating-disc');
  if(old) old.remove();
  const div = document.createElement('div');
  div.id = 'modal-floating-disc';
  div.className = 'modal-overlay';
  div.style.zIndex = '11000';
  div.onclick = (ev) => { if(ev.target===div) div.remove(); };
  div.innerHTML = `
    <div class="modal-dialog" style="max-width:680px;width:95%">
      <div class="modal-header">
        <h3>${titulo}</h3>
        <button class="modal-close" onclick="document.getElementById('modal-floating-disc').remove()"><i class="fa-solid fa-xmark"></i></button>
      </div>
      <div class="modal-body" style="padding:0">${htmlConteudo}</div>
    </div>`;
  document.body.appendChild(div);
}

// Anula um ato disciplinar — SOFT DELETE, nao apaga. O registro permanece
// arquivado com marca de "ANULADA", motivo, quem e quando. A mensagem
// correspondente em "comunicacoes" e' apagada (some do app do colaborador)
// mas o snapshot em "auditoria_disciplina" fica intacto (write-once).
// Isso preserva a trilha jurídica — voce sempre consegue provar que
// existiu o ato, quem o anulou, quando e por que.
async function anularDisciplina(discId){
  const mods = getUserModules(Auth.currentUser);
  if(!mods.disciplinaApagar && Auth.currentUser?.role!=='master'){
    toast('Sem permissão para anular atos disciplinares.','error'); return;
  }
  let snap;
  try{ snap = await firebase.firestore().collection('disciplina').doc(discId).get(); }
  catch(e){ toast('Erro ao buscar registro: '+(e.message||e),'error'); return; }
  if(!snap.exists){ toast('Registro nao encontrado.','error'); return; }
  const d = snap.data();
  if(d.anulada){ toast('Este ato ja foi anulado.','warning'); return; }
  const tipoLabel = d.tipo==='advertencia' ? 'advertência' : 'suspensão';
  if(!confirm(`Anular esta ${tipoLabel}?\n\nColaborador: ${d.employeeNome||'—'}\nMotivo original: ${d.motivo||'—'}\n\nA medida vai aparecer como ANULADA na aba Disciplina (registro mantido para auditoria). A mensagem some do app do colaborador.`)) return;
  const motivoAnul = (prompt('Motivo da anulação (obrigatorio — sera arquivado para auditoria):')||'').trim();
  if(!motivoAnul){ toast('Anulação cancelada — o motivo é obrigatório.','warning'); return; }
  const agora = new Date().toISOString();
  const quem  = (Auth.currentUser && (Auth.currentUser.username||Auth.currentUser.id))||'—';
  const quemId= (Auth.currentUser && Auth.currentUser.id)||'';
  try{
    // 1. Marca como anulada (soft delete) — mantem o registro
    await DB.merge('disciplina', discId, {
      anulada: true,
      anuladaEm: agora,
      anuladaPorId: quemId,
      anuladaPorNome: quem,
      motivoAnulacao: motivoAnul,
      updatedAt: agora,
    });
    // 2. Apaga a mensagem do app do colaborador (some da aba Avisos dele)
    if(d.comunicacaoId){
      try{ await DB.remove('comunicacoes', d.comunicacaoId); }catch(_){}
    }
    // 3. Snapshot do evento na auditoria imutavel
    try{
      await DB.save('auditoria_disciplina', _sanitizeForFirestore({
        id: genId(),
        disciplinaId: discId,
        employeeId: d.employeeId,
        tipo: d.tipo,
        evento: 'ANULACAO',
        motivoAnulacao: motivoAnul,
        anuladaEm: agora,
        anuladaPorId: quemId,
        anuladaPorNome: quem,
        snapshotOriginal: d,
        criadoEm: agora,
      }));
    }catch(_){}
    try{ Auth.log('DISCIPLINA_ANULADA', null, `${d.tipo.toUpperCase()} — ${d.employeeNome||''} — Motivo: ${motivoAnul}`); }catch(_){}
    toast(`${tipoLabel.charAt(0).toUpperCase()+tipoLabel.slice(1)} anulada. Registro mantido para auditoria.`,'success');
    renderDisciplinaTab(d.employeeId);
  }catch(e){
    toast('Erro ao anular: '+(e.message||e),'error');
  }
}

// Apaga uma mensagem da coleção comunicacoes. Sumirá do app do colaborador
// na próxima vez que ele abrir a aba Avisos (cache é invalidado por navTo).
async function apagarComunicacao(msgId){
  if(!getUserModules(Auth.currentUser).comunicacoesApagar && Auth.currentUser?.role!=='master'){
    toast('Sem permissão para apagar mensagens.','error'); return;
  }
  const m = _comuMensagensCache[msgId];
  const assuntoTxt = (m && m.assunto) || msgId;
  if(!confirm(`Apagar a mensagem "${assuntoTxt}"?\n\nEla também sumirá do app do colaborador.`)) return;
  try{
    await DB.remove('comunicacoes', msgId);
    try{ Auth.log('COMUNICACAO_APAGADA', null, `${(m&&m.employeeNome)||''} — ${assuntoTxt}`); }catch(_){}
    delete _comuMensagensCache[msgId];
    toast('Mensagem apagada.','success');
    const eid = val('emp-id');
    if(eid) renderComunicacoesTab(eid);
  }catch(e){
    toast('Erro ao apagar: '+(e.message||e),'error');
  }
}

function _comuRenderDest(){
  const box=document.getElementById('comu-dest-list');
  const cnt=document.getElementById('comu-dest-count');
  if(cnt) cnt.textContent=_comuDestinatarios.length;
  if(!box) return;
  if(!_comuDestinatarios.length){
    box.innerHTML='<span style="font-size:12px;color:#999;padding:4px 0">Nenhum destinatário</span>';
    return;
  }
  box.innerHTML=_comuDestinatarios.map(id=>{
    const e=State.employees.find(x=>x.id===id);
    const nome=(e&&e.nome)||id;
    // Em modo edição, nao mostra o "×" para nao deixar o usuario trocar de destinatario.
    const closeBtn = _comuEditandoId ? '' : `<button type="button" onclick="_comuRemoveDest('${id}')" title="Remover" style="background:none;border:none;color:#c62828;cursor:pointer;font-size:13px;line-height:1;padding:0">×</button>`;
    return `<span style="background:#fff;border:1px solid var(--border);border-radius:14px;padding:4px 10px;font-size:12px;display:inline-flex;align-items:center;gap:6px">
      ${nome}
      ${closeBtn}
    </span>`;
  }).join('');
}

function _comuAddDest(){
  const sel=document.getElementById('comu-add-emp'); if(!sel) return;
  const id=sel.value; if(!id) return;
  if(!_comuDestinatarios.includes(id)) _comuDestinatarios.push(id);
  sel.value='';
  _comuRenderDest();
}
function _comuRemoveDest(id){
  _comuDestinatarios=_comuDestinatarios.filter(x=>x!==id);
  _comuRenderDest();
}
function _comuAddTodos(){
  (State.employees||[]).filter(e=>(e.status||'ativo')==='ativo').forEach(e=>{
    if(!_comuDestinatarios.includes(e.id)) _comuDestinatarios.push(e.id);
  });
  _comuRenderDest();
}
function _comuLimparDest(){ _comuDestinatarios=[]; _comuRenderDest(); }

// ── Selecao em massa por filtro (posto, setor, escala) ─────────────────────
// Pega valores unicos do campo escolhido entre os ativos, abre um prompt
// para escolher (lista numerada) e adiciona todos do(s) selecionado(s).
// Modal visual de selecao multipla — substitui o prompt() horroroso.
// Recebe titulo, lista de {value, label} e callback com os values escolhidos.
function _abrirSelecaoMultipla(titulo, opcoes, onConfirm){
  const old = document.getElementById('modal-sel-mult');
  if(old) old.remove();
  if(!opcoes || !opcoes.length){
    toast('Nenhuma opção disponível.','warning');
    return;
  }
  const m = document.createElement('div');
  m.id = 'modal-sel-mult';
  m.className = 'modal-overlay';
  m.style.zIndex = '10500';
  m.onclick = ev => { if(ev.target===m) m.remove(); };
  const linhas = opcoes.map((o,i) => `
    <label style="display:flex;align-items:center;gap:10px;padding:10px 14px;cursor:pointer;border-bottom:1px solid #f1f5f9;transition:background .12s"
           onmouseover="this.style.background='#f8fafc'" onmouseout="this.style.background=''">
      <input type="checkbox" class="sel-mult-opt" value="${o.value.replace(/"/g,'&quot;')}" data-idx="${i}" style="width:18px;height:18px;cursor:pointer;flex-shrink:0">
      <span style="font-size:14px;color:#1e293b;flex:1">${o.label.replace(/</g,'&lt;')}</span>
    </label>`).join('');
  m.innerHTML = `
    <div class="modal-dialog" style="max-width:520px;width:95%;display:flex;flex-direction:column;max-height:85vh">
      <div class="modal-header">
        <h3 style="font-size:16px;color:#1e293b"><i class="fa-solid fa-list-check" style="color:#1976D2"></i> ${titulo}</h3>
        <button class="modal-close" onclick="document.getElementById('modal-sel-mult').remove()"><i class="fa-solid fa-xmark"></i></button>
      </div>
      <div style="padding:10px 14px;border-bottom:1px solid #e2e8f0;display:flex;gap:8px;align-items:center;flex-wrap:wrap">
        <button type="button" class="btn btn-sm btn-outline" onclick="_selMultMarcarTodos(true)" style="font-size:12px">
          <i class="fa-regular fa-square-check"></i> Marcar todos
        </button>
        <button type="button" class="btn btn-sm btn-outline" onclick="_selMultMarcarTodos(false)" style="font-size:12px">
          <i class="fa-regular fa-square"></i> Desmarcar todos
        </button>
        <span id="sel-mult-cnt" style="margin-left:auto;font-size:12px;color:#666">0 / ${opcoes.length} selecionado(s)</span>
      </div>
      <div id="sel-mult-list" style="overflow-y:auto;flex:1;min-height:120px">${linhas}</div>
      <div class="modal-footer" style="border-top:1px solid #e2e8f0;padding:12px 14px;display:flex;gap:8px;justify-content:flex-end">
        <button type="button" class="btn btn-outline" onclick="document.getElementById('modal-sel-mult').remove()">Cancelar</button>
        <button type="button" class="btn btn-primary" id="sel-mult-ok"><i class="fa-solid fa-check"></i> Confirmar</button>
      </div>
    </div>`;
  document.body.appendChild(m);
  // Atualiza contador conforme marca/desmarca
  const atualizarCnt = () => {
    const n = m.querySelectorAll('.sel-mult-opt:checked').length;
    document.getElementById('sel-mult-cnt').textContent = `${n} / ${opcoes.length} selecionado(s)`;
  };
  m.querySelectorAll('.sel-mult-opt').forEach(cb => cb.addEventListener('change', atualizarCnt));
  document.getElementById('sel-mult-ok').addEventListener('click', () => {
    const escolhidos = [...m.querySelectorAll('.sel-mult-opt:checked')].map(cb => cb.value);
    if(!escolhidos.length){ toast('Marque pelo menos uma opção.','warning'); return; }
    m.remove();
    onConfirm(escolhidos);
  });
}
function _selMultMarcarTodos(marcar){
  document.querySelectorAll('#modal-sel-mult .sel-mult-opt').forEach(cb => cb.checked = !!marcar);
  const n = document.querySelectorAll('#modal-sel-mult .sel-mult-opt:checked').length;
  const tot = document.querySelectorAll('#modal-sel-mult .sel-mult-opt').length;
  document.getElementById('sel-mult-cnt').textContent = `${n} / ${tot} selecionado(s)`;
}

// Adicionar destinatarios filtrando por um campo do cadastro (posto, setor).
function _comuAddPorCampo(campo, rotulo){
  const ativos = (State.employees||[]).filter(e=>(e.status||'ativo')==='ativo');
  const valores = [...new Set(ativos.map(e => (e[campo]||'').toString().trim()).filter(Boolean))]
    .sort((a,b)=>a.localeCompare(b,'pt-BR'));
  if(!valores.length){
    toast(`Nenhum colaborador ativo com ${rotulo} informado.`,'warning');
    return;
  }
  const opcoes = valores.map(v => ({ value:v, label:v }));
  _abrirSelecaoMultipla(`Selecionar por ${rotulo}`, opcoes, (escolhidos) => {
    let n = 0;
    ativos.forEach(e=>{
      if(escolhidos.includes((e[campo]||'').toString().trim())){
        if(!_comuDestinatarios.includes(e.id)){ _comuDestinatarios.push(e.id); n++; }
      }
    });
    _comuRenderDest();
    toast(`${n} colaborador(es) adicionado(s) (${rotulo}: ${escolhidos.join(', ')}).`,'success');
  });
}
function _comuAddPorPosto() { _comuAddPorCampo('posto', 'Posto de trabalho'); }
function _comuAddPorSetor() { _comuAddPorCampo('setor', 'Setor'); }
function _comuAddPorEscala(){
  const ativos = (State.employees||[]).filter(e=>(e.status||'ativo')==='ativo');
  const codigos = [...new Set(ativos.map(e => (e.escala||'').toString().trim()).filter(Boolean))]
    .sort((a,b)=>a.localeCompare(b));
  if(!codigos.length){ toast('Nenhum colaborador ativo com escala informada.','warning'); return; }
  const opcoes = codigos.map(c => ({ value:c, label: `${escalaLabel(c)} (${c})` }));
  _abrirSelecaoMultipla('Selecionar por Escala', opcoes, (escolhidos) => {
    let n = 0;
    ativos.forEach(e=>{
      if(escolhidos.includes((e.escala||'').toString().trim())){
        if(!_comuDestinatarios.includes(e.id)){ _comuDestinatarios.push(e.id); n++; }
      }
    });
    _comuRenderDest();
    toast(`${n} colaborador(es) adicionado(s).`,'success');
  });
}

// Classifica o turno do colaborador conforme o horario de entrada cadastrado:
//   Madrugada: entrada 00:00-05:59
//   Manha:     entrada 06:00-11:59
//   Tarde:     entrada 12:00-17:59
//   Noite:     entrada 18:00-23:59 ou turnoNoturno=true
//   Indefinido: sem horario cadastrado
function _classificarTurno(emp){
  if(!emp) return 'Indefinido';
  if(emp.turnoNoturno) return 'Noite';
  const ent = (emp.horarioEntrada||'').toString().trim();
  if(!ent || !ent.includes(':')) return 'Indefinido';
  const h = parseInt(ent.split(':')[0], 10);
  if(isNaN(h)) return 'Indefinido';
  if(h >= 0  && h <  6) return 'Madrugada';
  if(h >= 6  && h < 12) return 'Manhã';
  if(h >= 12 && h < 18) return 'Tarde';
  return 'Noite';
}
const _TURNO_ICON = { 'Madrugada':'🌙', 'Manhã':'🌅', 'Tarde':'☀️', 'Noite':'🌃', 'Indefinido':'❓' };

function _comuAddPorTurno(){
  const ativos = (State.employees||[]).filter(e=>(e.status||'ativo')==='ativo');
  // Conta quantos cada turno tem (so' mostra turnos que ja existem)
  const map = {};
  ativos.forEach(e => {
    const t = _classificarTurno(e);
    map[t] = (map[t]||0) + 1;
  });
  const ordem = ['Madrugada','Manhã','Tarde','Noite','Indefinido'];
  const opcoes = ordem.filter(t => map[t]).map(t => ({
    value: t,
    label: `${_TURNO_ICON[t]||''} ${t}  (${map[t]} colaborador${map[t]!==1?'es':''})`
  }));
  if(!opcoes.length){ toast('Nenhum colaborador ativo encontrado.','warning'); return; }
  _abrirSelecaoMultipla('Selecionar por Turno', opcoes, (escolhidos) => {
    let n = 0;
    ativos.forEach(e=>{
      if(escolhidos.includes(_classificarTurno(e))){
        if(!_comuDestinatarios.includes(e.id)){ _comuDestinatarios.push(e.id); n++; }
      }
    });
    _comuRenderDest();
    toast(`${n} colaborador(es) adicionado(s) (turno: ${escolhidos.join(', ')}).`,'success');
  });
}

// ── FILTRO AVANCADO — combina varias dimensoes em UM unico envio ─────────
// AND entre dimensoes, OR dentro de cada dimensao. Exemplo:
//   Turno: [Noite] + Escala: [12x36, 6x1A] + Posto: [todos]
//   = quem trabalha a noite E (esta em 12x36 OU 6x1A) E em qualquer posto.
// Dimensao sem nada marcado = "qualquer" (nao restringe).
function _comuAddFiltroAvancado(){
  const ativos = (State.employees||[]).filter(e=>(e.status||'ativo')==='ativo');
  if(!ativos.length){ toast('Sem colaboradores ativos.','warning'); return; }
  // Calcula opcoes para cada dimensao
  const turnos = [...new Set(ativos.map(e=>_classificarTurno(e)))]
    .sort((a,b)=>['Madrugada','Manhã','Tarde','Noite','Indefinido'].indexOf(a) - ['Madrugada','Manhã','Tarde','Noite','Indefinido'].indexOf(b));
  const escalas = [...new Set(ativos.map(e=>(e.escala||'').trim()).filter(Boolean))].sort();
  const postos = [...new Set(ativos.map(e=>(e.posto||'').trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'pt-BR'));
  const setores= [...new Set(ativos.map(e=>(e.setor||'').trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,'pt-BR'));
  const old = document.getElementById('modal-filtro-av');
  if(old) old.remove();
  const m = document.createElement('div');
  m.id = 'modal-filtro-av';
  m.className = 'modal-overlay';
  m.style.zIndex = '10500';
  m.onclick = ev => { if(ev.target===m) m.remove(); };
  const secao = (titulo, icone, key, opts) => `
    <div style="margin-bottom:12px">
      <div style="font-size:12px;font-weight:700;color:#475569;margin-bottom:6px;text-transform:uppercase;letter-spacing:.4px">${icone} ${titulo}</div>
      <div style="background:#f8fafc;border:1px solid #e2e8f0;border-radius:8px;max-height:160px;overflow-y:auto">
        ${opts.length === 0
          ? `<div style="padding:10px;font-size:12px;color:#94a3b8;text-align:center">Nenhum valor</div>`
          : opts.map(o => `
            <label style="display:flex;align-items:center;gap:8px;padding:7px 10px;cursor:pointer;border-bottom:1px solid #f1f5f9;font-size:13px"
                   onmouseover="this.style.background='#fff'" onmouseout="this.style.background=''">
              <input type="checkbox" class="fav-${key}" value="${o.replace(/"/g,'&quot;')}" style="width:16px;height:16px;cursor:pointer">
              <span>${o.replace(/</g,'&lt;')}${key==='escala' ? ` <span style="color:#94a3b8;font-size:11px">(${escalaLabel(o)})</span>`:''}</span>
            </label>`).join('')}
      </div>
    </div>`;
  m.innerHTML = `
    <div class="modal-dialog" style="max-width:640px;width:95%;display:flex;flex-direction:column;max-height:90vh">
      <div class="modal-header">
        <h3 style="font-size:16px;color:#1e293b"><i class="fa-solid fa-filter" style="color:#7c3aed"></i> Filtro avançado — combinar critérios</h3>
        <button class="modal-close" onclick="document.getElementById('modal-filtro-av').remove()"><i class="fa-solid fa-xmark"></i></button>
      </div>
      <div style="padding:12px 16px;background:#faf5ff;border-bottom:1px solid #e9d5ff;font-size:12px;color:#6b21a8;line-height:1.5">
        <strong>Como funciona:</strong> dentro de uma seção, marca o que quer incluir (OR).
        Entre seções, o sistema cruza tudo (AND). Seção sem nada marcado = qualquer valor (não restringe).
      </div>
      <div style="padding:14px 16px;overflow-y:auto;flex:1">
        ${secao('Turno (baseado no horário de entrada)', '⏰', 'turno',  turnos.map(t=>`${_TURNO_ICON[t]||''} ${t}`))}
        ${secao('Escala', '📅', 'escala', escalas)}
        ${secao('Posto de trabalho', '🏢', 'posto',  postos)}
        ${secao('Setor', '🌐', 'setor',  setores)}
      </div>
      <div class="modal-footer" style="border-top:1px solid #e2e8f0;padding:12px 16px;display:flex;gap:8px;justify-content:space-between;align-items:center;flex-wrap:wrap">
        <div id="fav-preview" style="font-size:12px;color:#666;flex:1;min-width:160px">Selecione critérios para ver a prévia</div>
        <div style="display:flex;gap:8px">
          <button type="button" class="btn btn-outline" onclick="document.getElementById('modal-filtro-av').remove()">Cancelar</button>
          <button type="button" class="btn btn-primary" id="fav-aplicar"><i class="fa-solid fa-check"></i> Aplicar filtro</button>
        </div>
      </div>
    </div>`;
  document.body.appendChild(m);
  // Calcula prevista de quem cai no filtro a cada mudanca
  const calcular = () => {
    const sel = {
      turno:  [...m.querySelectorAll('.fav-turno:checked')].map(cb => cb.value.replace(/^[^a-zA-ZÀ-ÿ]+/, '').trim()),
      escala: [...m.querySelectorAll('.fav-escala:checked')].map(cb => cb.value),
      posto:  [...m.querySelectorAll('.fav-posto:checked')].map(cb => cb.value),
      setor:  [...m.querySelectorAll('.fav-setor:checked')].map(cb => cb.value),
    };
    const algumMarcado = sel.turno.length+sel.escala.length+sel.posto.length+sel.setor.length > 0;
    const matches = ativos.filter(e => {
      if(sel.turno.length  && !sel.turno.includes(_classificarTurno(e))) return false;
      if(sel.escala.length && !sel.escala.includes((e.escala||'').trim())) return false;
      if(sel.posto.length  && !sel.posto.includes((e.posto||'').trim())) return false;
      if(sel.setor.length  && !sel.setor.includes((e.setor||'').trim())) return false;
      return true;
    });
    const prevEl = document.getElementById('fav-preview');
    if(!algumMarcado){
      prevEl.innerHTML = `<span style="color:#94a3b8">Selecione critérios para ver a prévia</span>`;
    } else {
      prevEl.innerHTML = `<i class="fa-solid fa-users" style="color:#7c3aed"></i> <strong>${matches.length}</strong> colaborador${matches.length!==1?'es':''} atende${matches.length===1?'':'m'} o filtro`;
    }
    return matches;
  };
  m.querySelectorAll('input[type=checkbox]').forEach(cb => cb.addEventListener('change', calcular));
  document.getElementById('fav-aplicar').addEventListener('click', () => {
    const matches = calcular();
    const sel = {
      turno:  [...m.querySelectorAll('.fav-turno:checked')].length,
      escala: [...m.querySelectorAll('.fav-escala:checked')].length,
      posto:  [...m.querySelectorAll('.fav-posto:checked')].length,
      setor:  [...m.querySelectorAll('.fav-setor:checked')].length,
    };
    const algumMarcado = sel.turno+sel.escala+sel.posto+sel.setor > 0;
    if(!algumMarcado){ toast('Marque ao menos um critério.','warning'); return; }
    if(!matches.length){ toast('Nenhum colaborador atende a esse filtro.','warning'); return; }
    let n = 0;
    matches.forEach(e => {
      if(!_comuDestinatarios.includes(e.id)){ _comuDestinatarios.push(e.id); n++; }
    });
    m.remove();
    _comuRenderDest();
    toast(`${n} colaborador(es) adicionado(s) pelo filtro avançado.`,'success');
  });
}

async function enviarComunicacao(){
  const ids=[..._comuDestinatarios];
  if(!ids.length){ toast('Adicione ao menos um destinatário.','warning'); return; }
  const assunto=(val('comu-assunto')||'').trim();
  if(!assunto){ toast('Informe o assunto.','warning'); return; }
  const corpo=(val('comu-corpo')||'').trim();
  if(!corpo){ toast('Escreva a mensagem.','warning'); return; }
  const tipo=(val('comu-tipo')||'normal').toLowerCase();
  const ehDisciplina = (tipo==='advertencia' || tipo==='suspensao');
  const fi=document.getElementById('comu-anexo');
  const file=fi && fi.files && fi.files[0] ? fi.files[0] : null;
  if(file && file.size > 10*1024*1024){ toast('Anexo grande demais (máx. 10 MB).','error'); return; }
  // Disciplina exige anexo (nao reaproveita herdado para nao bagunçar cadeia)
  if(ehDisciplina && !file){
    toast('Para advertência/suspensão é obrigatório anexar o documento.','error'); return;
  }
  // Disciplina nao deve ser enviada em massa (uma por colaborador, com ato proprio)
  if(ehDisciplina && ids.length > 1){
    toast('Advertência/suspensão deve ser enviada individualmente (1 colaborador por envio).','error'); return;
  }
  const motivoDisc = ehDisciplina ? (val('comu-disc-motivo')||'').trim() : '';
  if(ehDisciplina && !motivoDisc){ toast('Informe o motivo da medida disciplinar.','error'); return; }
  const diasSusp = (tipo==='suspensao') ? parseInt(val('comu-disc-dias')||'0',10) : 0;
  if(tipo==='suspensao' && (!diasSusp || diasSusp<1)){ toast('Informe os dias de suspensão (1 ou mais).','error'); return; }
  const artigoCLT = ehDisciplina ? (val('comu-disc-artigo')||'').trim() : '';

  const btn=document.getElementById('comu-enviar');
  setBtnLoading(btn,true,'');
  try{
    let anexoUrl='', anexoNome='', anexoTipo='', anexoHash='';
    if(file){
      // Calcula SHA-256 ANTES do upload — assim o hash representa exatamente
      // o que o gestor anexou (cadeia de custodia comeca aqui).
      if(ehDisciplina){
        try{ anexoHash = await _sha256Hex(file); }
        catch(e){ console.error('sha256', e); toast('Erro ao calcular hash do anexo.','error'); setBtnLoading(btn,false,''); return; }
      }
      const ext=(file.name.split('.').pop()||'bin').toLowerCase();
      const refId=Date.now().toString(36)+Math.random().toString(36).slice(2,8);
      const ref=firebase.storage().ref(`comunicacoes/${refId}.${ext}`);
      await ref.put(file);
      anexoUrl=await ref.getDownloadURL();
      anexoNome=file.name;
      anexoTipo=file.type||'';
    } else if(_comuAnexoHerdado){
      // reenviar: reaproveita o anexo da mensagem original (sem novo upload)
      anexoUrl  = _comuAnexoHerdado.url;
      anexoNome = _comuAnexoHerdado.nome;
      anexoTipo = _comuAnexoHerdado.tipo;
    }
    const quem=(Auth.currentUser && (Auth.currentUser.username||Auth.currentUser.id))||'—';
    const quemId=(Auth.currentUser && Auth.currentUser.id)||'';
    const agora=new Date().toISOString();

    // MODO EDIÇÃO — atualiza a mensagem original (mantém destinatário, reações e datas).
    // Reseta o "lida" para que a versão editada seja sinalizada como nao-vista
    // ate o colaborador abrir a aba Avisos de novo.
    if(_comuEditandoId){
      const changes = {
        assunto, corpo,
        anexoUrl, anexoNome, anexoTipo,
        editadoEm: agora,
        editadoPorNome: quem,
        lida: false,
        lidaEm: '',
        updatedAt: agora,
      };
      try{
        await DB.merge('comunicacoes', _comuEditandoId, changes);
        try{ Auth.log('COMUNICACAO_EDITADA', null, `${assunto}`); }catch(_){}
        toast('Mensagem atualizada.','success');
        closeModal('modal-comunicar');
        const m=document.getElementById('modal-employee');
        if(m && !m.classList.contains('hidden')){
          const eid=val('emp-id');
          if(eid) renderComunicacoesTab(eid);
        }
      }catch(e){
        toast('Erro ao atualizar: '+(e.message||e),'error');
      }finally{
        setBtnLoading(btn,false,'');
      }
      return;
    }

    let ok=0;
    // Quando for disciplina, ja' sabemos que ids tem exatamente 1 elemento.
    let disciplinaCriada = null;
    for(const empId of ids){
      const e=State.employees.find(x=>x.id===empId);
      const msgId = genId();
      // Hash da mensagem disciplinar (assunto + corpo + hash do anexo +
      // timestamp + autor + colaborador) — preserva a integridade do conjunto.
      let mensagemHash = '';
      if(ehDisciplina){
        const payloadParaHash = JSON.stringify({
          tipo, assunto, corpo, motivoDisc, diasSusp, artigoCLT,
          anexoHash, anexoNome,
          employeeId: empId,
          employeeNome: (e&&e.nome)||'',
          origemUserId: quemId,
          origemUserNome: quem,
          criadoEm: agora,
        });
        try{ mensagemHash = await _sha256Hex(payloadParaHash); }catch(_){}
      }
      const msg={
        id: msgId,
        employeeId: empId,
        employeeNome: (e&&e.nome)||'',
        assunto, corpo,
        tipo,
        anexoUrl, anexoNome, anexoTipo,
        origemUserId: quemId,
        origemUserNome: quem,
        criadoEm: agora,
        lida: false,
      };
      if(ehDisciplina){
        msg.anexoHash = anexoHash;
        msg.mensagemHash = mensagemHash;
        msg.motivoDisciplina = motivoDisc;
        msg.diasSuspensao = diasSusp;
        msg.artigoCLT = artigoCLT;
      }
      try{ await DB.save('comunicacoes', _sanitizeForFirestore(msg)); ok++; }
      catch(err){ console.error('Erro ao salvar comunicacao', err); continue; }

      // Para disciplina: criar registro em "disciplina" + snapshot em
      // "auditoria_disciplina" + recibo de envio em HTML/PDF.
      if(ehDisciplina){
        const discId = genId();
        const reciboHtml = _gerarReciboEnvioHTML({
          discId,
          tipo,
          empNome: (e&&e.nome)||'',
          empMatricula: (e&&e.registro) ? String(e.registro).padStart(4,'0') : '—',
          empCpf: (e&&e.cpf)||'—',
          empCargo: (e&&e.cargo)||'—',
          empPosto: (e&&e.posto)||'—',
          assunto, corpo, motivoDisc, diasSusp, artigoCLT,
          anexoNome, anexoHash, anexoUrl,
          mensagemHash,
          autorNome: quem,
          empresa: _e('nomeEmpresa'),
          criadoEm: agora,
          comunicacaoId: msgId,
        });
        let reciboUrl = '';
        try{
          const blob = new Blob([reciboHtml], { type:'text/html;charset=utf-8' });
          const refR = firebase.storage().ref(`disciplina/recibos/envio-${discId}.html`);
          await refR.put(blob);
          reciboUrl = await refR.getDownloadURL();
        }catch(err){ console.error('Falha ao subir recibo de envio', err); }
        const disc = {
          id: discId,
          employeeId: empId,
          employeeNome: (e&&e.nome)||'',
          tipo,
          motivo: motivoDisc,
          diasSuspensao: diasSusp,
          artigoCLT,
          anexoUrl, anexoNome, anexoTipo, anexoHash,
          mensagemHash,
          comunicacaoId: msgId,
          reciboEnvioUrl: reciboUrl,
          reciboRecebimentoUrl: '',
          criadoEm: agora,
          criadoPorId: quemId,
          criadoPorNome: quem,
          visualizadoEm: '',
        };
        try{ await DB.save('disciplina', _sanitizeForFirestore(disc)); disciplinaCriada = disc; }
        catch(err){ console.error('Erro ao salvar disciplina', err); }
        // Snapshot imutavel — coleção write-once via Rules (a ser configurado)
        try{
          await DB.save('auditoria_disciplina', _sanitizeForFirestore({
            id: genId(),
            disciplinaId: discId,
            employeeId: empId,
            tipo,
            snapshot: disc,
            anexoHash,
            mensagemHash,
            criadoEm: agora,
            criadoPorId: quemId,
            criadoPorNome: quem,
            evento: 'ENVIO',
          }));
        }catch(err){ console.error('Erro ao salvar auditoria', err); }
        try{ Auth.log('DISCIPLINA_ENVIADA', null, `${tipo.toUpperCase()} — ${(e&&e.nome)||''} — Hash: ${(anexoHash||'').substring(0,16)}...`); }catch(_){}
      }
    }
    try{ Auth.log('COMUNICACAO_ENVIADA', null, `${ok} destinatario(s) — ${assunto}`); }catch(_){}
    if(ok===0){
      toast('Nenhuma mensagem foi salva — abra o console do navegador (F12) para o erro.','error');
      return;
    }
    if(ehDisciplina && disciplinaCriada){
      toast(`${tipo==='advertencia'?'Advertência':'Suspensão'} registrada e enviada. Hash arquivado.`, 'success');
      closeModal('modal-comunicar');
      // Pos-envio: oferece abrir e-mail (mailto) + ver recibo de envio
      _abrirPosEnvioDisciplina(disciplinaCriada);
    } else {
      toast(`Mensagem enviada para ${ok} colaborador(es).`, 'success');
      closeModal('modal-comunicar');
    }
    const m=document.getElementById('modal-employee');
    if(m && !m.classList.contains('hidden')){
      const eid=val('emp-id');
      if(eid && ids.includes(eid)){
        renderComunicacoesTab(eid);
        if(ehDisciplina) renderDisciplinaTab(eid);
      }
    }
  }catch(e){
    toast('Erro ao enviar: '+(e.message||e),'error');
  }finally{
    setBtnLoading(btn,false,'');
  }
}

// Aba "Comunicações" no cadastro — log de mensagens manuais + snapshot
// dos avisos automáticos correntes do colaborador.
async function renderComunicacoesTab(empId){
  const box=document.getElementById('emp-comunicacoes-list'); if(!box) return;
  if(!empId){
    box.innerHTML=`<div class="empty-state small"><i class="fa-solid fa-envelope"></i><p>Salve o colaborador para registrar comunicações</p></div>`;
    return;
  }
  box.innerHTML='<div style="text-align:center;padding:20px;color:#999"><i class="fa-solid fa-spinner fa-spin"></i> Carregando comunicações...</div>';
  let lista=[];
  try{
    const snap=await firebase.firestore().collection('comunicacoes').where('employeeId','==',empId).get();
    lista=snap.docs.map(d=>({id:d.id,...d.data()}));
  }catch(e){ console.error('comunicacoes:fetch',e); }
  lista.sort((a,b)=>(b.criadoEm||'').localeCompare(a.criadoEm||''));
  // cache das mensagens para o botão "Reenviar"
  _comuMensagensCache = {};
  lista.forEach(m => { _comuMensagensCache[m.id] = m; });
  const podeApagar = !!getUserModules(Auth.currentUser).comunicacoesApagar || Auth.currentUser?.role==='master';
  const emp=State.employees.find(e=>e.id===empId);
  const autos = emp ? _computeAvisosAutomaticos(emp) : [];
  let html='';
  html+=`<div style="margin-bottom:12px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
    <strong style="font-size:13px">Mensagens enviadas (${lista.length})</strong>
    <button class="btn btn-sm btn-primary" onclick="openComunicarModal('${empId}')" style="font-size:12px">
      <i class="fa-solid fa-paper-plane"></i> Nova mensagem
    </button>
  </div>`;
  if(!lista.length){
    html+=`<div class="empty-state small" style="margin-bottom:14px"><i class="fa-solid fa-envelope-open"></i><p>Nenhuma mensagem enviada ainda</p></div>`;
  } else {
    // Helpers de formatacao em horario local (criadoEm/lidaEm sao ISO em UTC;
    // o usuario esta em America/Sao_Paulo — converter pelo Date do navegador).
    const _fmtDt = iso => { const d=iso?new Date(iso):null; return (d && !isNaN(d.getTime())) ? d.toLocaleDateString('pt-BR') : ''; };
    const _fmtHr = iso => { const d=iso?new Date(iso):null; return (d && !isNaN(d.getTime())) ? d.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}) : ''; };
    html+=lista.map(m=>{
      const dt=_fmtDt(m.criadoEm);
      const hr=_fmtHr(m.criadoEm);
      const anexo=m.anexoUrl?`<div style="margin-top:6px;font-size:12px"><a href="${m.anexoUrl}" target="_blank" rel="noopener" style="color:var(--primary)"><i class="fa-solid fa-paperclip"></i> ${m.anexoNome||'anexo'}</a></div>`:'';
      // Reações do colaborador (emojis) — mostra o que ele já reagiu
      const reacEntries = Object.entries(m.reacoes||{}).filter(([_,ids])=>(ids||[]).length>0);
      const reacHtml = reacEntries.length
        ? `<div style="margin-top:6px;font-size:12px;color:#475569"><span style="color:#94a3b8">Reagiu:</span> ${reacEntries.map(([emo])=>`<span style="font-size:14px;margin-right:2px">${emo}</span>`).join('')}</div>`
        : '';
      // Confirmação de leitura — ✓✓ verde se visualizada
      const lidaHtml = m.lida
        ? `<span style="color:#16a34a;font-weight:600" title="Visualizada">✓✓ visualizada${m.lidaEm?` em ${_fmtDt(m.lidaEm)} ${_fmtHr(m.lidaEm)}`:''}</span>`
        : `<span style="color:#94a3b8" title="Ainda não visualizada">✓ enviada · não visualizada</span>`;
      return `<div style="background:#fff;border:1px solid var(--border);border-radius:8px;padding:10px 12px;margin-bottom:8px">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:10px">
          <strong style="font-size:13px;color:var(--text)">${m.assunto||'(sem assunto)'}</strong>
          <span style="font-size:11px;color:#999;white-space:nowrap">${dt}${hr?' '+hr:''}</span>
        </div>
        <div style="font-size:12px;color:#555;margin-top:4px;white-space:pre-wrap">${m.corpo||''}</div>
        ${anexo}
        ${reacHtml}
        <div style="margin-top:6px;font-size:11px">${lidaHtml}</div>
        <div style="margin-top:8px;padding-top:7px;border-top:1px dashed var(--border);display:flex;justify-content:space-between;align-items:center;gap:8px;flex-wrap:wrap">
          <span style="font-size:11px;color:#888">Enviado por ${m.origemUserNome||'—'}${m.editadoEm?` · <em>editado ${_fmtDt(m.editadoEm)}</em>`:''}</span>
          <div style="display:flex;gap:6px;flex-wrap:wrap">
            <button type="button" onclick="editarMensagem('${m.id}')" class="btn btn-sm btn-outline" style="font-size:11px;padding:3px 10px;color:#E65100;border-color:#FFCC80"><i class="fa-solid fa-pen"></i> Editar</button>
            <button type="button" onclick="reenviarMensagem('${m.id}')" class="btn btn-sm btn-outline" style="font-size:11px;padding:3px 10px;color:#1976D2;border-color:#1976D2"><i class="fa-solid fa-rotate-right"></i> Reenviar</button>
            ${podeApagar?`<button type="button" onclick="apagarComunicacao('${m.id}')" class="btn btn-sm btn-outline" style="font-size:11px;padding:3px 10px;color:#c62828;border-color:#ef9a9a"><i class="fa-solid fa-trash"></i> Apagar</button>`:''}
          </div>
        </div>
      </div>`;
    }).join('');
  }
  if(autos.length){
    html+=`<div style="margin-top:18px;padding-top:14px;border-top:1px solid var(--border)">
      <strong style="font-size:13px">Avisos automáticos do sistema (${autos.length})</strong>
      <div style="font-size:11px;color:#888;margin-bottom:8px">O que o colaborador vê no app dele agora.</div>
      ${autos.map(a=>`<div style="background:#fafafa;border-left:3px solid #999;padding:7px 10px;margin-bottom:6px;border-radius:4px;font-size:12px"><strong>${a.icone} ${a.titulo}</strong><br><span style="color:#555">${a.msg}</span></div>`).join('')}
    </div>`;
  }
  // Ação no fim da aba: gerar relatório PDF SO deste colaborador — usado em
  // auditorias / pastas individuais. Abre o modal universal de relatorios
  // em modo dedicado (sem grid de tipos e sem filtros).
  html+=`<div style="margin-top:20px;padding-top:14px;border-top:1px dashed var(--border);display:flex;justify-content:flex-end;flex-wrap:wrap;gap:8px">
    <button type="button" class="btn btn-outline btn-sm" onclick="gerarRelatorioComunicacoesIndividual('${empId}')" style="font-size:12px;color:#1a3a6b;border-color:#1a3a6b">
      <i class="fa-solid fa-file-pdf"></i> Gerar relatório PDF deste colaborador
    </button>
  </div>`;
  box.innerHTML=html;
}

// Computa os avisos automáticos correntes do colaborador (snapshot do que
// o app dele mostra agora) — usado no log da aba "Comunicações".
function _computeAvisosAutomaticos(emp){
  if(!emp) return [];
  const hoje=new Date(); hoje.setHours(0,0,0,0);
  const D=86400000;
  const out=[];
  if(emp.exameVencimento){
    const venc=new Date(emp.exameVencimento+'T00:00:00');
    const diff=Math.round((venc-hoje)/D);
    if(diff<0) out.push({icone:'🩺',titulo:'Exame médico VENCIDO',msg:`Venceu há ${Math.abs(diff)} dia(s).`});
    else if(diff<=10) out.push({icone:'🩺',titulo:'Exame médico vencendo',msg:`Vence em ${diff} dia(s).`});
  }
  (emp.ferias||[]).forEach(f=>{
    if(!f.inicio||!f.fim) return;
    const ini=new Date(f.inicio+'T00:00:00');
    const fim=new Date(f.fim+'T00:00:00');
    if(ini>hoje){
      const dd=Math.round((ini-hoje)/D);
      if(dd<=30) out.push({icone:'🏖️',titulo:'Férias programadas',msg:`Começa em ${dd} dia(s).`});
    } else if(ini<=hoje&&fim>=hoje){
      const r=Math.round((fim-hoje)/D);
      out.push({icone:'🏖️',titulo:'Em férias agora',msg:`Retorno em ${r} dia(s).`});
    }
  });
  if(emp.tipoContrato==='experiencia' && emp.expDecisao1==='renovado' && emp.expDecisao1Data){
    const dd=Math.round((hoje-new Date(emp.expDecisao1Data+'T00:00:00'))/D);
    if(dd>=0 && dd<=14) out.push({icone:'⏳',titulo:'Renovado p/ 2º período',msg:`Em ${emp.expDecisao1Data.split('-').reverse().join('/')}.`});
  }
  if(emp.efetivadoEm){
    const dd=Math.round((hoje-new Date(emp.efetivadoEm+'T00:00:00'))/D);
    if(dd>=0 && dd<=30) out.push({icone:'🤝',titulo:'Contrato efetivado',msg:`Em ${emp.efetivadoEm.split('-').reverse().join('/')}.`});
  }
  return out;
}

function renderAprovacoes(){
  const tbody=document.getElementById('aprovacoes-tbody'); if(!tbody) return;
  const filtro=val('aprovacoes-filtro')||'pendente';
  const mods=getUserModules(Auth.currentUser);
  const podeAprovar=!!mods.pagamentosAprovar;
  _autoBuscarComprovantes();   // puxa em 2o plano os comprovantes que faltam

  let lista=[...(State.solicitacoes||[])];
  if(filtro!=='todos') lista=lista.filter(s=>s.status===filtro);
  lista.sort((a,b)=>new Date(b.criadoEm||0)-new Date(a.criadoEm||0));

  const pend=(State.solicitacoes||[]).filter(s=>s.status==='pendente');
  const cnt=document.getElementById('aprovacoes-contador');
  if(cnt){
    const totalP=pend.reduce((s,x)=>s+(x.valor||0),0);
    cnt.innerHTML = pend.length
      ? `<strong style="color:#E65100">${pend.length}</strong> pendente(s) · Total ${fmtMoney(totalP)}`
      : '<span style="color:#2e7d32">Nenhuma pendência</span>';
  }
  const aviso=document.getElementById('aprovacoes-sem-perm');
  if(aviso) aviso.style.display = podeAprovar ? 'none' : '';

  if(lista.length===0){
    tbody.innerHTML=`<tr><td colspan="8" style="padding:26px;text-align:center;color:#999">Nenhuma solicitação${filtro!=='todos'?' ('+filtro+')':''}.</td></tr>`;
    return;
  }
  tbody.innerHTML=lista.map((s,idx)=>{
    const bg=idx%2?'#f9fafb':'#fff';
    const dt=(s.criadoEm||'').substring(0,10).split('-').reverse().join('/');
    const sched=(s.scheduleDate||'').split('-').reverse().join('/');
    // Nome do colaborador clicavel → abre o cadastro (se o colaborador existe)
    const _empCad=State.employees.find(e=>e.id===s.employeeId);
    const nomeCell=_empCad
      ? `<strong style="color:var(--primary);cursor:pointer;text-decoration:underline;text-decoration-style:dotted;text-underline-offset:2px" onclick="openEmployeeModal('${s.employeeId}')" title="Abrir cadastro de ${(s.employeeNome||'').replace(/"/g,'&quot;')}">${s.employeeNome||'—'}</strong>`
      : `<strong>${s.employeeNome||'—'}</strong>`;
    let acoes='—';
    if(s.status==='pendente'){
      acoes = podeAprovar
        ? `<button class="btn btn-sm" style="background:#2e7d32;color:#fff;border-color:#2e7d32;margin-right:4px" onclick="openAprovarPagamento('${s.id}')"><i class="fa-solid fa-check"></i> Aprovar</button>`
          + `<button class="btn btn-sm btn-outline" style="color:#c62828;border-color:#ef9a9a" onclick="recusarSolicitacao('${s.id}')"><i class="fa-solid fa-ban"></i> Recusar</button>`
        : `<span style="font-size:11px;color:#999">aguardando aprovador</span>`;
    } else if(s.status==='pago'){
      const idTxt=s.asaasTransferId?`<div style="font-size:10px;color:#aaa;margin-top:3px">ID: ${s.asaasTransferId}</div>`:'';
      // "Estornar" so' aparece quando NAO existe comprovante oficial da Asaas
      // ainda. Comprovante presente = PIX confirmado pelo banco — nao da' pra
      // estornar so' no sistema sem o dinheiro voltar de fato. Nesses casos,
      // se houver problema, abre disputa direto na Asaas (fora do app).
      const podeEstornar = podeAprovar && !s.asaasComprovante;
      const estornarBtn = podeEstornar
        ? `<div style="margin-top:5px"><button class="btn btn-sm btn-outline" style="color:#E65100;border-color:#FFCC80;font-size:11px;padding:3px 9px" onclick="estornarPagamento('${s.id}')" title="Marcar como estornado — use quando o PIX nao foi concluido no banco"><i class="fa-solid fa-rotate-left"></i> Estornar</button></div>`
        : '';
      if(s.asaasComprovante){
        acoes=`<a href="${s.asaasComprovante}" target="_blank" rel="noopener" class="btn btn-sm" style="background:#00695C;color:#fff;border-color:#00695C;text-decoration:none"><i class="fa-solid fa-receipt"></i> Comprovante</a>${idTxt}`;
      } else if(s.asaasTransferId){
        acoes=`<button class="btn btn-sm btn-outline" style="color:#00695C;border-color:#00695C" onclick="verComprovante('${s.id}',this)"><i class="fa-solid fa-receipt"></i> Comprovante</button>${idTxt}${estornarBtn}`;
      } else {
        acoes=`<span style="font-size:11px;color:#00695C">pago</span>${estornarBtn}`;
      }
    } else if(s.status==='estornado'){
      const refazBtn = mods.pagamentosLancar
        ? `<div style="margin-top:5px"><button class="btn btn-sm btn-outline" style="color:#1565C0;border-color:#90CAF9;font-size:11px;padding:3px 9px" onclick="refazerSolicitacao('${s.id}')" title="Cria uma NOVA solicitação pendente com os mesmos dados"><i class="fa-solid fa-arrows-rotate"></i> Refazer lançamento</button></div>`
        : '';
      acoes=`<span style="font-size:11px;color:#E65100" title="${(s.motivoEstorno||'').replace(/"/g,'&quot;')}"><i class="fa-solid fa-rotate-left"></i> ${s.motivoEstorno||'estornado'}</span>`
        + (s.estornadoEm?`<div style="font-size:10px;color:#aaa;margin-top:2px">por ${s.estornadoPorNome||'—'} · ${(s.estornadoEm||'').substring(0,10).split('-').reverse().join('/')}</div>`:'')
        + refazBtn;
    } else if(s.status==='recusado'){
      const refazBtn = mods.pagamentosLancar
        ? `<div style="margin-top:5px"><button class="btn btn-sm btn-outline" style="color:#1565C0;border-color:#90CAF9;font-size:11px;padding:3px 9px" onclick="refazerSolicitacao('${s.id}')" title="Cria uma NOVA solicitação pendente com os mesmos dados"><i class="fa-solid fa-arrows-rotate"></i> Refazer lançamento</button></div>`
        : '';
      acoes=`<span style="font-size:11px;color:#c62828">${(s.motivoRecusa||'recusado')}</span>` + refazBtn;
    } else if(s.status==='erro'){
      const refazBtn = mods.pagamentosLancar
        ? `<button class="btn btn-sm btn-outline" style="color:#1565C0;border-color:#90CAF9;font-size:11px;padding:3px 9px;margin-left:4px" onclick="refazerSolicitacao('${s.id}')" title="Cria uma NOVA solicitação pendente (em vez de retentar a mesma)"><i class="fa-solid fa-arrows-rotate"></i> Refazer</button>`
        : '';
      acoes = podeAprovar
        ? `<button class="btn btn-sm" style="background:#e65100;color:#fff;border-color:#e65100;margin-right:4px" onclick="openAprovarPagamento('${s.id}')" title="${(s.erro||'').replace(/"/g,'')}"><i class="fa-solid fa-rotate-right"></i> Tentar de novo</button>`
          + `<button class="btn btn-sm btn-outline" style="color:#c62828;border-color:#ef9a9a" onclick="recusarSolicitacao('${s.id}')" title="${(s.erro||'').replace(/"/g,'')}"><i class="fa-solid fa-ban"></i> Recusar</button>`
          + refazBtn
        : `<span style="font-size:11px;color:#c62828">${s.erro||'erro'}</span>`;
    }
    return `<tr style="background:${bg}">
      <td style="padding:9px 10px">${nomeCell}${s.origem==='lote'?' <span style="font-size:10px;color:#aaa">(lote)</span>':''}</td>
      <td style="padding:9px 10px;text-align:right;font-weight:700;color:#00695C">${fmtMoney(s.valor||0)}</td>
      <td style="padding:9px 10px;font-family:monospace;font-size:11px">${s.pixKey||'—'}</td>
      <td style="padding:9px 10px;font-size:12px">${sched||'—'}</td>
      <td style="padding:9px 10px;font-size:12px">${s.criadoPorNome||'—'}<br><span style="color:#aaa;font-size:10px">${dt}</span></td>
      <td style="padding:9px 10px;text-align:center">${_aprovacaoStatusBadge(s.status)}</td>
      <td style="padding:9px 10px;font-size:12px">${s.aprovadoPorNome||'—'}</td>
      <td style="padding:9px 10px">${acoes}</td>
    </tr>`;
  }).join('');
}

let _aprovacaoAtualId=null;
function openAprovarPagamento(id){
  if(!getUserModules(Auth.currentUser).pagamentosAprovar){ toast('Sem permissão para aprovar pagamentos.','error'); return; }
  const s=(State.solicitacoes||[]).find(x=>x.id===id);
  if(!s){ toast('Solicitação não encontrada.','error'); return; }
  _aprovacaoAtualId=id;
  document.getElementById('aprovar-pag-info').innerHTML=`
    <div style="font-weight:700;color:#00695C;font-size:15px">${s.employeeNome}</div>
    <div style="font-size:14px;margin-top:6px"><strong>${fmtMoney(s.valor)}</strong> &rarr; <i class="fa-brands fa-pix" style="color:#00695C"></i> <code style="background:#fff;padding:2px 6px;border-radius:4px">${s.pixKey}</code></div>
    <div style="font-size:12px;color:#666;margin-top:6px">${s.descricao||''}${s.scheduleDate?' · data '+s.scheduleDate.split('-').reverse().join('/'):''}</div>
    <div style="font-size:11px;color:#999;margin-top:4px">Lançado por ${s.criadoPorNome||'—'}</div>`;
  setVal('aprovar-pag-code','');
  const resEl=document.getElementById('aprovar-pag-resultado');
  resEl.style.display='none'; resEl.innerHTML='';
  const btn=document.getElementById('btn-confirmar-aprovacao');
  btn.style.display=''; btn.disabled=false;
  btn.innerHTML='<i class="fa-solid fa-lock"></i> Aprovar e Pagar';
  document.getElementById('modal-aprovar-pagamento').classList.remove('hidden');
  setTimeout(()=>document.getElementById('aprovar-pag-code')?.focus(),150);
}

async function confirmarAprovacaoPagamento(){
  const id=_aprovacaoAtualId; if(!id) return;
  const code=(val('aprovar-pag-code')||'').replace(/\D/g,'');
  if(code.length!==6){ toast('Digite o código de 6 dígitos do app autenticador.','warning'); return; }

  const btn=document.getElementById('btn-confirmar-aprovacao');
  btn.disabled=true; btn.innerHTML='<i class="fa-solid fa-spinner fa-spin"></i> Processando...';
  const resEl=document.getElementById('aprovar-pag-resultado'); resEl.style.display='none';

  try{
    const r=await _aprovacaoReq('/aprovar-pagamento',{code,solicitacaoId:id});
    if(r.ok){
      const s=(State.solicitacoes||[]).find(x=>x.id===id);
      Auth.log('PAGAMENTO_APROVADO',null,
        `${s?.employeeNome||id} | R$ ${(s?.valor||0).toFixed(2)} | ID Asaas ${r.asaasTransferId||'—'}`);
      resEl.style.display='block';
      resEl.innerHTML=`<div style="background:#e8f5e9;border:1px solid #a5d6a7;border-radius:9px;padding:14px;font-size:13px;color:#2e7d32">
        <i class="fa-solid fa-circle-check"></i> <strong>${r.jaPago?'Esta solicitação já estava paga.':'Pagamento aprovado e enviado ao Asaas!'}</strong><br>
        ID Asaas: <code>${r.asaasTransferId||'—'}</code> · Status: ${r.status||'—'}</div>`;
      btn.style.display='none';
      toast('Pagamento aprovado!','success');
      setTimeout(()=>{ closeModal('modal-aprovar-pagamento'); if(State.currentSection==='aprovacoes') renderAprovacoes(); },2000);
    } else {
      resEl.style.display='block';
      resEl.innerHTML=`<div style="background:#fce4e4;border:1px solid #ef9a9a;border-radius:9px;padding:14px;font-size:13px;color:#c62828">
        <i class="fa-solid fa-triangle-exclamation"></i> ${r.erro||'Não foi possível aprovar.'}</div>`;
      btn.disabled=false; btn.innerHTML='<i class="fa-solid fa-lock"></i> Aprovar e Pagar';
    }
  }catch(e){
    resEl.style.display='block';
    resEl.innerHTML=`<div style="background:#fce4e4;border:1px solid #ef9a9a;border-radius:9px;padding:14px;font-size:13px;color:#c62828">
      <i class="fa-solid fa-triangle-exclamation"></i> ${e.message}</div>`;
    btn.disabled=false; btn.innerHTML='<i class="fa-solid fa-lock"></i> Aprovar e Pagar';
  }
}

// Estorna um pagamento marcado como "pago" — usar quando o PIX nao foi
// concluido no banco (devolvido / falhou apos a aprovacao). A linha sai
// da lista "Pagos" e aparece no filtro "Estornados". Mantem o registro
// para auditoria (motivo, quem estornou, quando).
async function estornarPagamento(id){
  const mods = getUserModules(Auth.currentUser);
  if(!mods.pagamentosAprovar && Auth.currentUser?.role!=='master'){
    toast('Sem permissão para estornar pagamentos.','error'); return;
  }
  const s = (State.solicitacoes||[]).find(x=>x.id===id);
  if(!s){ toast('Solicitação não encontrada.','error'); return; }
  if(s.status!=='pago'){ toast('Só dá pra estornar uma solicitação com status "Pago".','warning'); return; }
  // Blindagem: comprovante oficial = PIX confirmado pelo banco. Estornar so'
  // no sistema cria divergencia (dinheiro saiu mas o registro diz que nao).
  // Se mesmo assim houver problema, abra disputa direto na Asaas.
  if(s.asaasComprovante){
    toast('Este pagamento ja tem comprovante oficial da Asaas — nao pode ser estornado pelo sistema. Para contestar, abra disputa direto na Asaas.','error');
    return;
  }
  if(!confirm(`Estornar este pagamento?\n\n${s.employeeNome||''} — ${fmtMoney(s.valor||0)}\nID Asaas: ${s.asaasTransferId||'—'}\n\nUse quando o PIX nao chegou no banco (devolvido / falhou). A linha sai da lista "Pagos" e fica em "Estornados".`)) return;
  const motivo = (prompt('Motivo do estorno (obrigatorio):')||'').trim();
  if(!motivo){ toast('Estorno cancelado — o motivo é obrigatório.','warning'); return; }
  const agora = new Date().toISOString();
  const quem = (Auth.currentUser && (Auth.currentUser.username||Auth.currentUser.id))||'—';
  try{
    await DB.merge('solicitacoesPagamento', id, {
      status: 'estornado',
      motivoEstorno: motivo,
      estornadoEm: agora,
      estornadoPorNome: quem,
      updatedAt: agora,
    });
    Object.assign(s, { status:'estornado', motivoEstorno:motivo, estornadoEm:agora, estornadoPorNome:quem });
    try{ Auth.log('PAGAMENTO_ESTORNADO', null, `${s.employeeNome||''} — ${fmtMoney(s.valor||0)} — ${motivo}`); }catch(_){}
    toast('Pagamento estornado. Saiu da lista de "Pagos".','success');
    renderAprovacoes();
  }catch(e){
    toast('Erro ao estornar: '+(e.message||e),'error');
  }
}

async function recusarSolicitacao(id){
  if(!getUserModules(Auth.currentUser).pagamentosAprovar){ toast('Sem permissão para recusar pagamentos.','error'); return; }
  const s=(State.solicitacoes||[]).find(x=>x.id===id);
  if(!s) return;
  const motivo=prompt(`Recusar o pagamento de ${s.employeeNome} (${fmtMoney(s.valor)})?\n\nInforme o motivo da recusa:`);
  if(motivo===null) return;
  if(!motivo.trim()){ toast('O motivo da recusa é obrigatório.','warning'); return; }
  try{
    const u=Auth.currentUser||{};
    await DB.merge('solicitacoesPagamento',id,{
      status:'recusado', motivoRecusa:motivo.trim(),
      aprovadoPor:u.username||u.id||'', aprovadoPorNome:u.username||'',
      aprovadoEm:new Date().toISOString(),
    });
    Auth.log('PAGAMENTO_RECUSADO',null,`${s.employeeNome} | R$ ${(s.valor||0).toFixed(2)} | ${motivo.trim()}`);
    toast('Solicitação recusada.','success');
  }catch(e){ toast('Erro ao recusar: '+e.message,'error'); }
}

// Cria uma NOVA solicitação pendente a partir de uma estornada/recusada/erro —
// pra refazer o lançamento sem ter que voltar pra tela de origem (Benefícios,
// Folha…). A original fica preservada (histórico). Bloqueia se já existir outra
// solicitação pendente do mesmo colaborador no mesmo período.
async function refazerSolicitacao(id){
  if(!getUserModules(Auth.currentUser).pagamentosLancar){
    toast('Você não tem permissão para lançar pagamentos.','error'); return;
  }
  const orig=(State.solicitacoes||[]).find(s=>s.id===id);
  if(!orig){ toast('Solicitação não encontrada.','error'); return; }
  if(!orig.pixKey || (orig.valor||0)<=0){ toast('Solicitação original sem chave PIX ou valor — não dá pra refazer.','error'); return; }
  const jaPend=(State.solicitacoes||[]).some(s=>s.employeeId===orig.employeeId && s.competencia===orig.competencia && s.status==='pendente' && s.id!==orig.id);
  if(jaPend){ toast(`Já existe uma solicitação PENDENTE para ${orig.employeeNome} neste período — aprove/recuse a existente antes.`,'warning'); return; }
  const motivoOrig = orig.status==='estornado' ? (orig.motivoEstorno||'estornado')
                    : orig.status==='recusado' ? (orig.motivoRecusa||'recusado')
                    : (orig.erro||orig.status||'');
  if(!confirm(`Refazer o lançamento de ${orig.employeeNome} — ${fmtMoney(orig.valor||0)}?\n\nOriginal: ${orig.status.toUpperCase()} (${motivoOrig})\n\nCria uma NOVA solicitação PENDENTE com os mesmos dados (mesma chave PIX). Vai pra "Aprovações" e o aprovador faz o 2FA.`)) return;
  try{
    const dtOrig=(orig.criadoEm||'').substring(0,10).split('-').reverse().join('/');
    const novo=await _criarSolicitacaoPagamento({
      employeeId:    orig.employeeId,
      employeeNome:  orig.employeeNome,
      payrollId:     orig.payrollId||'',
      valor:         orig.valor||0,
      pixKey:        orig.pixKey,
      keyType:       orig.keyType||'',
      descricao:     `[RE-LANÇAMENTO de ${dtOrig} — ${orig.status}] ${orig.descricao||''}`.slice(0,500),
      scheduleDate:  new Date().toISOString().substring(0,10),
      competencia:   orig.competencia||'',
      origem:        orig.origem||'avulso',
    });
    Auth.log('PAGAMENTO_SOLICITADO',null,`RE-LANÇAMENTO ${orig.employeeNome} | R$ ${(orig.valor||0).toFixed(2)} | nova ${novo.id} (original ${orig.id} / ${orig.status})`);
    toast(`Lançamento refeito — nova solicitação pendente criada. Vá em Aprovações p/ aprovar.`,'success');
    renderAprovacoes();
  }catch(e){ toast('Erro ao refazer: '+(e.message||e),'error'); }
}

// ============================================
// DOCUMENTOS ENVIADOS PELO COLABORADOR (via app de ponto)
// ============================================
// Espelho gestor da feature do ponto.html: o colaborador envia documento
// pelo app -> coleção `documentos` com status 'pendente' -> aqui o gestor
// aprova ou reprova. Atestados NÃO entram aqui (continuam na Folha de Ponto).
const DOC_TIPOS_META = {
  declaracao:        { ico:'📜', nome:'Declaração' },
  comprovante:       { ico:'📄', nome:'Comprovante' },
  documento_pessoal: { ico:'🪪', nome:'Documento pessoal' },
  outros:            { ico:'📁', nome:'Outro documento' }
};

function _docStatusBadge(status){
  if(status==='aprovado')  return '<span style="background:#E8F5E9;color:#1B5E20;padding:3px 9px;border-radius:9px;font-size:11px;font-weight:600">aprovado</span>';
  if(status==='reprovado') return '<span style="background:#FFEBEE;color:#c62828;padding:3px 9px;border-radius:9px;font-size:11px;font-weight:600">reprovado</span>';
  return '<span style="background:#FFF3E0;color:#E65100;padding:3px 9px;border-radius:9px;font-size:11px;font-weight:600">pendente</span>';
}

function renderDocumentosPendentes(){
  const tbody=document.getElementById('documentos-tbody'); if(!tbody) return;
  const filtro=val('documentos-filtro')||'pendente';

  let lista=[...(State.documentos||[])];
  if(filtro!=='todos') lista=lista.filter(d=>d.status===filtro);
  lista.sort((a,b)=>new Date(b.createdAt||0)-new Date(a.createdAt||0));

  const pend=(State.documentos||[]).filter(d=>d.status==='pendente');
  const cnt=document.getElementById('documentos-contador');
  if(cnt){
    cnt.innerHTML = pend.length
      ? `<strong style="color:#E65100">${pend.length}</strong> documento(s) aguardando aprovação`
      : '<span style="color:#2e7d32">Nenhuma pendência</span>';
  }

  if(lista.length===0){
    tbody.innerHTML=`<tr><td colspan="7" style="padding:26px;text-align:center;color:#999">Nenhum documento${filtro!=='todos'?' ('+filtro+')':''}.</td></tr>`;
    return;
  }

  tbody.innerHTML=lista.map((d,idx)=>{
    const bg=idx%2?'#f9fafb':'#fff';
    const emp=State.employees.find(e=>e.id===d.employeeId);
    const nomeEmp=emp?emp.nome:(d.employeeId||'—');
    const nomeCell=emp
      ? `<strong style="color:var(--primary);cursor:pointer;text-decoration:underline;text-decoration-style:dotted;text-underline-offset:2px" onclick="openEmployeeModal('${d.employeeId}')" title="Abrir cadastro de ${nomeEmp.replace(/"/g,'&quot;')}">${nomeEmp}</strong>`
      : `<strong>${nomeEmp}</strong>`;
    const meta=DOC_TIPOS_META[d.tipo]||{ico:'📄',nome:d.tipoLabel||d.tipo||'Documento'};
    const dt=(d.createdAt||'').substring(0,10).split('-').reverse().join('/');
    const arquivoCell = d.arquivoUrl
      ? `<a href="${d.arquivoUrl}" target="_blank" rel="noopener" class="btn btn-sm btn-outline" style="font-size:11px;padding:3px 9px"><i class="fa-solid fa-paperclip"></i> Abrir</a>`
      : '—';

    let acoes='—';
    if(d.status==='pendente'){
      acoes = `<button class="btn btn-sm" style="background:#2e7d32;color:#fff;border-color:#2e7d32;margin-right:4px" onclick="aprovarDocumento('${d.id}')"><i class="fa-solid fa-check"></i> Aprovar</button>`
            + `<button class="btn btn-sm btn-outline" style="color:#c62828;border-color:#ef9a9a" onclick="reprovarDocumento('${d.id}')"><i class="fa-solid fa-ban"></i> Reprovar</button>`;
    } else if(d.status==='aprovado'){
      const quando=(d.aprovadoEm||'').substring(0,10).split('-').reverse().join('/');
      acoes=`<span style="font-size:11px;color:#1B5E20">por ${d.aprovadoPorNome||'—'}${quando?' · '+quando:''}</span>`;
    } else if(d.status==='reprovado'){
      acoes=`<span style="font-size:11px;color:#c62828" title="${(d.motivoReprovacao||'').replace(/"/g,'&quot;')}">${d.motivoReprovacao||'reprovado'}</span>`;
    }

    return `<tr style="background:${bg}">
      <td style="padding:9px 10px">${nomeCell}</td>
      <td style="padding:9px 10px"><span style="font-size:16px">${meta.ico}</span> ${meta.nome}</td>
      <td style="padding:9px 10px;font-size:12px;color:#475569">${(d.descricao||'').replace(/</g,'&lt;')||'<span style="color:#aaa">—</span>'}</td>
      <td style="padding:9px 10px;font-size:12px">${dt}</td>
      <td style="padding:9px 10px;text-align:center">${arquivoCell}</td>
      <td style="padding:9px 10px;text-align:center">${_docStatusBadge(d.status)}</td>
      <td style="padding:9px 10px">${acoes}</td>
    </tr>`;
  }).join('');
}

async function aprovarDocumento(id){
  if(!getUserModules(Auth.currentUser).employees){ toast('Sem permissão para aprovar documentos.','error'); return; }
  const d=(State.documentos||[]).find(x=>x.id===id);
  if(!d){ toast('Documento não encontrado.','error'); return; }
  if(d.status!=='pendente'){ toast('Este documento já foi processado.','warning'); return; }
  try{
    const u=Auth.currentUser||{};
    await DB.merge('documentos',id,{
      status:'aprovado',
      aprovadoPor:u.username||u.id||'',
      aprovadoPorNome:u.username||'',
      aprovadoEm:new Date().toISOString(),
      updatedAt:new Date().toISOString()
    });
    const emp=State.employees.find(e=>e.id===d.employeeId);
    Auth.log('DOCUMENTO_APROVADO',null,`${emp?.nome||d.employeeId} | ${d.tipoLabel||d.tipo} | ${(d.descricao||'').substring(0,80)}`);
    toast('Documento aprovado.','success');
  }catch(e){ toast('Erro ao aprovar: '+e.message,'error'); }
}

async function reprovarDocumento(id){
  if(!getUserModules(Auth.currentUser).employees){ toast('Sem permissão para reprovar documentos.','error'); return; }
  const d=(State.documentos||[]).find(x=>x.id===id);
  if(!d){ toast('Documento não encontrado.','error'); return; }
  if(d.status!=='pendente'){ toast('Este documento já foi processado.','warning'); return; }
  const emp=State.employees.find(e=>e.id===d.employeeId);
  const motivo=prompt(`Reprovar o ${(d.tipoLabel||d.tipo||'documento').toLowerCase()} de ${emp?.nome||d.employeeId}?\n\nInforme o motivo (o colaborador não recebe notificação automática — combine pessoalmente):`);
  if(motivo===null) return;
  if(!motivo.trim()){ toast('O motivo da reprovação é obrigatório.','warning'); return; }
  try{
    const u=Auth.currentUser||{};
    await DB.merge('documentos',id,{
      status:'reprovado',
      motivoReprovacao:motivo.trim(),
      aprovadoPor:u.username||u.id||'',
      aprovadoPorNome:u.username||'',
      aprovadoEm:new Date().toISOString(),
      updatedAt:new Date().toISOString()
    });
    Auth.log('DOCUMENTO_REPROVADO',null,`${emp?.nome||d.employeeId} | ${d.tipoLabel||d.tipo} | ${motivo.trim()}`);
    toast('Documento reprovado.','success');
  }catch(e){ toast('Erro ao reprovar: '+e.message,'error'); }
}

// Renderiza, no topo da aba "Documentos" da ficha, os documentos APROVADOS
// que vieram do app do colaborador. Pendentes ficam na tela de Aprovação;
// reprovados ficam ocultos da ficha (auditoria via tela de Documentos).
function renderDocumentosAprovadosNaFicha(empId){
  const box=document.getElementById('doc-app-list'); if(!box) return;
  const docs=(State.documentos||[])
    .filter(d=>d.employeeId===empId && d.status==='aprovado')
    .sort((a,b)=>new Date(b.createdAt||0)-new Date(a.createdAt||0));
  if(docs.length===0){
    box.innerHTML='<div style="font-size:12px;color:#94a3b8;padding:8px 2px">Nenhum documento enviado pelo app ainda.</div>';
    return;
  }
  box.innerHTML = docs.map(d=>{
    const meta=DOC_TIPOS_META[d.tipo]||{ico:'📄',nome:d.tipoLabel||d.tipo||'Documento'};
    const dt=(d.createdAt||'').substring(0,10).split('-').reverse().join('/');
    return `<div class="doc-item">
      <div class="doc-icon" style="font-size:22px">${meta.ico}</div>
      <div class="doc-info">
        <div class="doc-name">${meta.nome}${d.descricao?` <span style="color:#64748b;font-weight:400">— ${d.descricao.replace(/</g,'&lt;')}</span>`:''}</div>
        <div class="doc-meta">Enviado em ${dt} · aprovado por ${d.aprovadoPorNome||'—'}</div>
      </div>
      <div class="doc-actions">
        <a href="${d.arquivoUrl}" target="_blank" rel="noopener" class="btn-icon btn-primary-icon" title="Abrir"><i class="fa-solid fa-download"></i></a>
      </div>
    </div>`;
  }).join('');
}

function _lockPayrollForm(isLocked){
  const form=document.querySelector('#section-payroll .payroll-form-col');
  if(!form) return;
  // Inputs e selects (exceto colaborador, mês, ano, período)
  const editIds=['payroll-dias','payroll-faltas-justificadas','payroll-faltas-injustificadas',
    'payroll-remuneracao','payroll-vt-dia','payroll-vt-total','payroll-vr-dia','payroll-vr-total',
    'payroll-va-total','payroll-va-liquido','payroll-bonus','payroll-noturno','payroll-acumulo',
    'payroll-insalubridade','payroll-atraso-min','payroll-desconto-atraso',
    'payroll-atraso-tipo','payroll-atraso-justificativa','payroll-atraso-abonado','payroll-adiantamento-ativo',
    'payroll-adiantamento-perc','payroll-adiantamento-valor','payroll-entrada','payroll-saida',
    'payroll-intervalo-inicio','payroll-intervalo-fim','payroll-he-total','payroll-he-perc',
    'payroll-he-valor','pdf-input'];
  editIds.forEach(id=>{ const el=document.getElementById(id); if(el) el.disabled=isLocked; });
  // Botões
  const saveBtn=document.querySelector('#section-payroll .btn-primary');
  if(saveBtn) saveBtn.disabled=isLocked;
  const recalcBtn=document.querySelector('#section-payroll [onclick*="recalculate"]');
  if(recalcBtn) recalcBtn.disabled=isLocked;
  // PDF upload area
  const pdfArea=document.getElementById('pdf-upload-area');
  if(pdfArea) pdfArea.style.pointerEvents=isLocked?'none':'auto';
  // Botão Reabrir
  const btnReabrir=document.getElementById('btn-reabrir-folha');
  if(btnReabrir) btnReabrir.style.display=isLocked?'inline-flex':'none';
  // Overlay visual
  const formCard=document.querySelector('#section-payroll .payroll-form-col .card-body');
  if(formCard) formCard.style.opacity=isLocked?'0.75':'1';
}

function _updateFolhaStatusBadge(){
  const empId=val('payroll-employee');
  const mes=parseInt(val('payroll-mes')||currentMes());
  const ano=parseInt(val('payroll-ano')||currentAno());
  const badge=document.getElementById('payroll-status-badge');
  if(!badge) return;
  const p=State.payrolls.find(r=>r.employeeId===empId&&r.mes==mes&&r.ano==ano);
  const fechada=p?.status==='fechada';
  const temFolha=!!p;
  badge.innerHTML=fechada
    ? `<span style="background:#E8EAF6;color:#5C6BC0;padding:3px 10px;border-radius:10px;font-size:12px;font-weight:700;white-space:nowrap"><i class="fa-solid fa-lock"></i> Folha Fechada</span>`
    : (temFolha?`<span style="background:#E8F5E9;color:#2E7D32;padding:3px 10px;border-radius:10px;font-size:12px;font-weight:700;white-space:nowrap"><i class="fa-solid fa-lock-open"></i> Folha Aberta</span>`:'');
  // Botão "Fechar esta Folha" — visível só quando tem folha salva e está aberta
  const btnFecharInd=document.getElementById('btn-fechar-folha-individual');
  if(btnFecharInd) btnFecharInd.style.display=(temFolha&&!fechada)?'inline-flex':'none';
  // Botão "Reabrir esta Folha" — visível só quando fechada
  const btnReabrir=document.getElementById('btn-reabrir-folha');
  if(btnReabrir) btnReabrir.style.display=fechada?'inline-flex':'none';
  // Botão "Pagar via PIX" — visível quando fechada + colaborador tem chave PIX + sem pagamento anterior
  const btnPix=document.getElementById('btn-pagar-asaas');
  const pixBadge=document.getElementById('asaas-pago-badge');
  if(btnPix||pixBadge){
    const emp=State.employees.find(e=>e.id===empId);
    const temPix=!!(emp?.chavePix);
    const jaPago=!!(p?.pagamentoAsaas);
    if(btnPix) btnPix.style.display=(fechada&&temPix&&!jaPago)?'inline-flex':'none';
    if(pixBadge){
      if(fechada&&jaPago){
        const pg=p.pagamentoAsaas;
        pixBadge.style.display='inline-flex';
        pixBadge.innerHTML=`<span style="background:#E0F2F1;color:#00695C;padding:3px 10px;border-radius:10px;font-size:12px;font-weight:700;white-space:nowrap;cursor:pointer" onclick="openPagarColaborador()" title="Ver pagamento Asaas"><i class="fa-brands fa-pix"></i> ${fmtMoney(pg.asaasValor)} pago</span>`;
      } else {
        pixBadge.style.display='none';
        pixBadge.innerHTML='';
      }
    }
  }
  _lockPayrollForm(fechada);
}

// ============================================
// PDF PROCESSING
// ============================================
function handleDragOver(e){ e.preventDefault(); document.getElementById('pdf-upload-area').classList.add('drag-over'); }
function handleDrop(e){
  e.preventDefault(); document.getElementById('pdf-upload-area').classList.remove('drag-over');
  const file=e.dataTransfer.files[0];
  if(file&&isArquivoAceito(file)) loadPdfFile(file);
  else toast('Formato não aceito. Use PDF, JPG ou PNG.','error');
}
function handlePdfSelected(event){ const file=event.target.files[0]; if(file&&isArquivoAceito(file)) loadPdfFile(file); }
function isArquivoAceito(file){
  const tipos=['application/pdf','image/jpeg','image/jpg','image/png','image/webp'];
  return tipos.includes(file.type);
}
function loadPdfFile(file){
  State.currentPdfFile=file;
  document.getElementById('pdf-placeholder').classList.add('hidden');
  document.getElementById('pdf-selected').classList.remove('hidden');
  document.getElementById('pdf-file-name').textContent=file.name;
  document.getElementById('pdf-file-size').textContent=formatBytes(file.size);
  document.getElementById('btn-process-pdf').disabled=false;
}
function clearPdf(event,silent=false){
  if(event) event.stopPropagation();
  State.currentPdfFile=null; State.currentPdfText='';
  document.getElementById('pdf-placeholder').classList.remove('hidden');
  document.getElementById('pdf-selected').classList.add('hidden');
  document.getElementById('pdf-input').value='';
  document.getElementById('btn-process-pdf').disabled=true;
  if(!silent) toast('PDF removido.','warning');
}
function formatBytes(b){ if(b<1024) return b+' B'; if(b<1048576) return (b/1024).toFixed(1)+' KB'; return (b/1048576).toFixed(1)+' MB'; }

// ============================================
// LEITURA DE FOLHA DE PONTO COM GEMINI AI
// ============================================
// Usa Cloudflare Worker como proxy: a chave Gemini fica em segredo no
// servidor e nunca aparece no código público (LGPD/segurança).
const GEMINI_PROXY_URL = 'https://drg-gemini-proxy.zett-romao.workers.dev';
const GEMINI_MODEL     = 'gemini-2.5-flash';

// Converte arquivo para base64
async function fileToBase64(file){
  return new Promise((resolve,reject)=>{
    const reader=new FileReader();
    reader.onload=()=>resolve(reader.result.split(',')[1]);
    reader.onerror=reject;
    reader.readAsDataURL(file);
  });
}

// Regras de falta por tipo de escala de trabalho
const ESCALA_RULES = {
  '5x2A': 'Escala 5x2 — Variante A. Dias de trabalho: SEGUNDA a SEXTA (08h-18h, exceto Sex 08h-16h). Sábado e domingo: FOLGA (não é falta, não soma em "faltas"). FALTA = somente dia entre Segunda e Sexta sem registro de entrada nem saída E sem nenhuma justificativa na OBS.',
  '5x2B': 'Escala 5x2 — Variante B. Dias de trabalho: SEGUNDA a SEXTA (07h-17h, exceto Sex 07h-16h). Sábado e domingo: FOLGA (não é falta). FALTA = somente dia entre Segunda e Sexta sem registro de entrada nem saída E sem justificativa na OBS.',
  '6x1A': 'Escala 6x1 — Variante A. Dias de trabalho: SEGUNDA a SÁBADO (07h-16h, exceto Sáb 07h-11h). Domingo: FOLGA (não é falta). FALTA = somente dia entre Segunda e Sábado sem registro de entrada nem saída E sem justificativa na OBS.',
  '6x1B': 'Escala 6x1 — Variante B. Trabalha 6 dias e folga 1 (a folga roda durante a semana, não é fixa em domingo). O dia de FOLGA aparece marcado como "FOLGA", "DSR" ou linha vazia explicitamente identificada como descanso. FALTA = dia em que era para trabalhar (não marcado como folga/DSR/atestado) e está sem registro.',
  '12x36': 'Escala 12x36. O colaborador trabalha 12 horas e folga 36 horas (alternado: 1 dia trabalha / 1 dia folga). ATENÇÃO CRÍTICA: dias sem registro são FOLGAS PROGRAMADAS — NÃO são faltas automaticamente. Considere FALTA = 0 (zero) por padrão. Só conte como FALTA se a coluna OBS contiver expressamente "FALTA", "FALTOU", "AUSENTE" ou "F.I." (falta injustificada). Atestado/Férias/Afastamento NÃO são faltas.'
};

// Chama a API do Gemini com visão
// Registra o uso de IA (tokens consumidos) na coleção `usoIA`, alimentando
// o Painel de Recursos. Fire-and-forget — nunca atrapalha a análise.
async function _registrarUsoIA(tipo, geminiData){
  try{
    const um=(geminiData&&geminiData.usageMetadata)||{};
    await DB.save('usoIA', {
      id: genId(),
      ts: new Date().toISOString(),
      tipo: tipo,
      model: GEMINI_MODEL,
      promptTokens: um.promptTokenCount||0,
      outputTokens: um.candidatesTokenCount||0,
      totalTokens: um.totalTokenCount||0,
      usuario: (Auth.currentUser&&(Auth.currentUser.username||Auth.currentUser.nome))||''
    });
  }catch(e){ console.warn('Falha ao registrar uso de IA:', e); }
}

// Faz o parse do JSON devolvido pelo Gemini, tolerando erros comuns do
// modelo: cercas markdown, vírgula faltando entre objetos/strings do array,
// vírgula sobrando antes de } ou ], comentários de bloco.
function _parseGeminiJson(text){
  const raw=String(text||'');
  // 1) tentativa direta (em JSON mode normalmente já vem certo)
  try { return JSON.parse(raw); } catch(_e){}
  // 2) tira cercas markdown e isola do 1º "{" ao último "}"
  let t=raw.replace(/```(?:json)?/gi,'').trim();
  const ini=t.indexOf('{'), fim=t.lastIndexOf('}');
  if(ini>=0 && fim>ini) t=t.slice(ini,fim+1);
  try { return JSON.parse(t); } catch(_e){}
  // 3) repara os erros comuns do modelo e tenta pela última vez
  const r=t
    .replace(/\/\*[\s\S]*?\*\//g,'')                       // comentários de bloco
    .replace(/}\s*{/g,'},{')                               // vírgula faltando entre objetos
    .replace(/]\s*\[/g,'],[')                              // ... entre arrays
    .replace(/}\s*\[/g,'},[')
    .replace(/]\s*{/g,'],{')
    .replace(/("(?:[^"\\]|\\.)*")\s*\n\s*(")/g,'$1,\n$2')  // ... entre valores string
    .replace(/,\s*([}\]])/g,'$1');                         // vírgula sobrando antes de } ]
  try { return JSON.parse(r); }
  catch(e){ throw new Error('A IA devolveu um JSON malformado ('+e.message+'). Tente novamente.'); }
}

// Converte a string compacta de dias da IA ("1|folga|-|-|-|-;2|trabalho|07:00|...")
// no array de objetos {dia,tipo,entrada,intervaloInicio,intervaloFim,saida}.
function _parseDiasIA(diasStr){
  const out=[];
  String(diasStr||'').split(/[;\n]+/).forEach(linha=>{
    const p=linha.split('|');
    if(p.length<2) return;
    const dia=parseInt(p[0]);
    if(!dia||dia<1||dia>31) return;
    const lim=v=>{ v=(v||'').trim(); return (!v||v==='-')?null:v; };
    out.push({
      dia,
      tipo:((p[1]||'').trim().toLowerCase())||'trabalho',
      entrada:lim(p[2]),
      intervaloInicio:lim(p[3]),
      intervaloFim:lim(p[4]),
      saida:lim(p[5])
    });
  });
  return out;
}

async function callGemini(base64Data, mimeType, escala, mes, ano){
  const escalaRule=ESCALA_RULES[escala]||ESCALA_RULES[escalaFamilia(escala)]||ESCALA_RULES['5x2A'];
  const refTxt=(mes&&ano)?`Esta folha é da competência ${MESES[mes]}/${ano}, que vai do dia ${_compLabel(mes,ano)} (fecha no dia 25). Os dias 26 a 31 pertencem ao mês anterior; os dias 1 a 25 ao mês ${mes}.`:'';
  const prompt=`Você é um sistema de leitura de folha de ponto brasileira. Analise a imagem/PDF desta folha de ponto e extraia os horários de CADA DIA com PRECISÃO MÁXIMA. A folha pode ser digitada ou preenchida à mão.

${refTxt}

ESTRUTURA DA FOLHA: cada linha representa 1 dia do mês. As colunas geralmente são: DIA | DIA DA SEMANA | ENTRADA | INÍCIO INTERVALO | RETORNO INTERVALO | SAÍDA | RUBRICA | HORA EXTRA | OBS. A ordem pode variar — adapte-se.

ESCALA DO COLABORADOR (regra de negócio para distinguir folga de falta):
${escalaRule}

Retorne SOMENTE um JSON válido, COMPACTO, em UMA linha, com este formato exato:
{"nome":"...","cargo":"...","ctps":"...","dias":"...","diasTrabalhados":0,"faltas":0,"horasExtras":0,"observacoes":"..."}

O CAMPO "dias" É UMA ÚNICA STRING DE TEXTO (não é lista nem array). Dentro dessa string:
- Coloque um dia por vez, na ordem em que aparecem na folha (a competência começa no dia 26 do mês anterior e termina no dia 25), separados por ponto-e-vírgula ";".
- Cada dia tem 6 campos separados por barra vertical "|", nesta ordem EXATA: dia|tipo|entrada|intervaloInicio|intervaloFim|saida
- "tipo": um de trabalho, folga, falta, atestado, ferias, feriado, dsr.
- Horários no formato 24 horas HH:MM (ex.: 07:00, 13:30, 22:00). Campo vazio = "-".
- Em dias de folga/falta/atestado/ferias/feriado/dsr, os 4 horários são "-".
- Se a folha registra só ENTRADA e SAÍDA (sem intervalo), use "-" nos dois campos de intervalo.
- Copie o horário EXATAMENTE como está escrito — não arredonde, não invente, não complete.
- Turno noturno: registre a hora do relógio mesmo que a saída caia no dia seguinte.
Exemplo do campo "dias": "1|folga|-|-|-|-;2|trabalho|07:00|11:00|12:00|16:00;3|atestado|-|-|-|-"

REGRAS DOS TOTAIS:
- "diasTrabalhados": quantidade de dias com ENTRADA e SAÍDA preenchidas.
- "faltas": dias contados como FALTA pela regra da ESCALA acima. NUNCA conte folgas, sábados/domingos de quem não trabalha neles, atestados, férias, feriados ou DSR.
- "horasExtras": soma da coluna HORA EXTRA em horas decimais (1.5 = 1h30min). Se não houver, 0.

ANTI-ENGANO:
1. NÃO conte sábado/domingo como falta na escala 5x2 — são folga.
2. NÃO conte linha vazia como falta na escala 12x36 sem indicação explícita.
3. "ATESTADO", "FÉRIAS", "AFAST.", "INSS", "LICENÇA", "DSR", "FOLGA", "FERIADO" são dias justificados — nunca "falta".

Retorne APENAS o JSON em uma única linha, compacto, sem markdown, sem comentários, sem quebras de linha. Se um valor não puder ser lido, use "-" (texto/horário) ou 0 (números).`;

  const resp=await fetch(GEMINI_PROXY_URL, {
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({
      model: GEMINI_MODEL,
      prompt: prompt,
      mimeType: mimeType,
      base64Data: base64Data
    })
  });
  if(!resp.ok){
    const err=await resp.json().catch(()=>({error:'Resposta inválida do servidor'}));
    throw new Error(err.error?.message||err.error||'Erro na chamada Gemini via proxy');
  }
  const data=await resp.json();
  const text=data.candidates?.[0]?.content?.parts?.[0]?.text||'';
  console.log('Gemini raw response:', text);
  _registrarUsoIA('folha', data);
  try {
    const parsed=_parseGeminiJson(text);
    if(typeof parsed.dias==='string') parsed.dias=_parseDiasIA(parsed.dias);
    else if(!Array.isArray(parsed.dias)) parsed.dias=[];
    return parsed;
  } catch(e){
    // Salvação: a IA pode truncar a resposta. Extrai os campos por regex —
    // inclusive um "dias" cortado no meio (string sem aspas de fechamento).
    const gS=k=>{ const m=text.match(new RegExp('"'+k+'"\\s*:\\s*"([^"]*)')); return m?m[1]:null; };
    const gN=k=>{ const m=text.match(new RegExp('"'+k+'"\\s*:\\s*(-?[0-9]+(?:\\.[0-9]+)?)')); return m?Number(m[1]):0; };
    const diasArr=_parseDiasIA(gS('dias')||'');
    if(diasArr.length){
      return { nome:gS('nome'), cargo:gS('cargo'), ctps:gS('ctps'), dias:diasArr,
        diasTrabalhados:gN('diasTrabalhados'), faltas:gN('faltas'),
        horasExtras:gN('horasExtras'), observacoes:gS('observacoes'), _parcial:true };
    }
    const err=new Error(e.message);
    err.rawResponse=text;
    throw err;
  }
}

let _iaPontoExtracted = null;

async function processPdf(){
  const file=State.currentPdfFile; if(!file){ toast('Nenhum arquivo selecionado.','error'); return; }
  const modal=document.getElementById('modal-pdf');
  const statusEl=document.getElementById('extraction-status');
  const resultEl=document.getElementById('extraction-result');
  const footerEl=document.getElementById('modal-pdf-footer');
  modal.classList.remove('hidden');
  statusEl.classList.remove('hidden');
  statusEl.innerHTML=`<div style="text-align:center;padding:20px">
    <div class="spinner" style="margin:0 auto 12px"></div>
    <div style="font-weight:600;color:var(--primary)">🤖 Inteligência Artificial analisando a folha...</div>
    <div style="font-size:12px;color:var(--text-muted);margin-top:6px">Gemini está lendo os registros dia a dia. Aguarde.</div>
  </div>`;
  resultEl.classList.add('hidden'); footerEl.classList.add('hidden');
  try {
    const base64=await fileToBase64(file);
    // Para PDF, usa o tipo do arquivo; para imagem, usa o MIME real
    let mimeType=file.type;
    if(mimeType==='application/pdf') mimeType='application/pdf';
    // Escala + mês/ano do colaborador selecionado (afetam a leitura da IA)
    const empId=val('payroll-employee');
    const emp=State.employees.find(e=>e.id===empId);
    const escala=emp?.escala||'5x2A';
    const mes=parseInt(val('payroll-mes')||currentMes());
    const ano=parseInt(val('payroll-ano')||currentAno());
    const extracted=await callGemini(base64, mimeType, escala, mes, ano);
    _iaPontoExtracted=extracted;
    const diasIA=Array.isArray(extracted.dias)?extracted.dias:[];
    const diasComHora=diasIA.filter(d=>d&&(d.entrada||d.saida));
    const temDias=diasComHora.length>0;
    // Info do que a IA leu
    const nomeInfo=extracted.nome?`<br><i class="fa-solid fa-user"></i> <strong>${extracted.nome}</strong>${extracted.cargo?' — '+extracted.cargo:''}`:'';
    const heInfo=extracted.horasExtras>0?`<br><i class="fa-solid fa-clock"></i> Horas extras detectadas: <strong>${extracted.horasExtras}h</strong>`:'';
    const obsInfo=extracted.observacoes?`<br><i class="fa-solid fa-note-sticky"></i> Obs: ${extracted.observacoes}`:'';
    const okLine=extracted._parcial
      ? '<div style="color:#E65100;font-weight:700"><i class="fa-solid fa-triangle-exclamation"></i> Leitura PARCIAL — a resposta da IA veio cortada. Confira com atenção; pode faltar dia.</div>'
      : '<div style="color:var(--success);font-weight:700"><i class="fa-solid fa-robot"></i> Gemini AI leu a folha com sucesso!</div>';
    document.getElementById('extraction-info').innerHTML=`
      ${okLine}
      ${nomeInfo}${heInfo}${obsInfo}
      <div style="margin-top:6px"><i class="fa-solid fa-calendar-check"></i> Dias com horário lido: <strong>${temDias?diasComHora.length:(extracted.diasTrabalhados||0)}</strong> · Faltas estimadas: <strong>${extracted.faltas||0}</strong></div>
      <div style="margin-top:8px;font-size:12px;color:var(--text-muted)">${temDias
        ? 'Os horários serão abertos dia a dia na Folha de Ponto para você conferir antes de aplicar.'
        : 'A IA não leu os horários dia a dia — confira e ajuste os totais abaixo antes de aplicar.'}</div>`;
    // Campos-resumo só aparecem quando a IA NÃO trouxe o dia a dia
    ['ext-dias','ext-faltas','ext-remuneracao'].forEach(id=>{
      const el=document.getElementById(id);
      const fg=el?el.closest('.form-group'):null;
      if(fg) fg.style.display=temDias?'none':'';
    });
    if(!temDias){
      setVal('ext-dias', extracted.diasTrabalhados||0);
      setVal('ext-faltas', extracted.faltas||0);
      setVal('ext-remuneracao','');
    }
    const applyBtn=document.getElementById('btn-aplicar-extracao');
    if(applyBtn) applyBtn.innerHTML=temDias
      ? '<i class="fa-solid fa-list-check"></i> Conferir na Folha de Ponto'
      : '<i class="fa-solid fa-check"></i> Aplicar Dados';
    // Esconder raw text (não temos mais)
    const rawBlock=document.getElementById('ext-raw-text');
    if(rawBlock) rawBlock.parentElement?.classList?.add('hidden');
    statusEl.classList.add('hidden');
    resultEl.classList.remove('hidden');
    footerEl.classList.remove('hidden');
  } catch(err){
    const rawHtml = err.rawResponse
      ? `<details open style="margin-top:10px;text-align:left;font-size:11px">
           <summary style="cursor:pointer;color:var(--primary)">Resposta recebida da IA (para diagnóstico)</summary>
           <pre style="white-space:pre-wrap;word-break:break-word;background:#f5f5f5;padding:8px;border-radius:6px;max-height:220px;overflow:auto;font-size:10px">${String(err.rawResponse).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}</pre>
         </details>`
      : '';
    statusEl.innerHTML=`<div style="color:var(--danger);text-align:center;padding:20px">
      <i class="fa-solid fa-circle-xmark" style="font-size:32px;display:block;margin-bottom:10px"></i>
      <strong>Erro ao processar com IA</strong><br>
      <span style="font-size:12px">${err.message}</span><br>
      <span style="font-size:11px;color:var(--text-muted);margin-top:6px;display:block">A IA às vezes erra — clique em "Analisar com IA" de novo. Se persistir, mostre a resposta abaixo ao suporte.</span>
    </div>${rawHtml}`;
    footerEl.classList.remove('hidden');
    footerEl.innerHTML='<button class="btn btn-outline" onclick="closeModal(\'modal-pdf\')">Fechar</button>';
  }
}

// Normaliza um horário lido pela IA para "HH:MM" (input type=time exige).
function _normHora(s){
  if(s==null) return '';
  const m=String(s).match(/(\d{1,2})\s*[:hH.]?\s*(\d{2})/);
  if(!m) return '';
  const h=parseInt(m[1],10), mi=parseInt(m[2],10);
  if(isNaN(h)||isNaN(mi)||h>23||mi>59) return '';
  return String(h).padStart(2,'0')+':'+String(mi).padStart(2,'0');
}

async function applyExtraction(){
  const ex=_iaPontoExtracted;
  const diasIA=ex&&Array.isArray(ex.dias)?ex.dias:[];
  // Fluxo principal: a IA leu o ponto dia a dia → preenche o grid de Ponto
  // Manual. É a partir dele que HE, atrasos, faltas, recálculo e impressão
  // são alimentados — ou seja, os dados chegam a todo o sistema.
  if(diasIA.some(d=>d&&(d.entrada||d.saida))){
    const empId=val('payroll-employee');
    if(!empId){ toast('Selecione um colaborador na Folha de Ponto antes de aplicar.','error'); return; }
    closeModal('modal-pdf');
    await openPontoManual();
    let preenchidos=0;
    diasIA.forEach(d=>{
      const dia=parseInt(d&&d.dia);
      if(!dia) return;
      const card=document.querySelector(`#ponto-manual-grid [data-dia="${dia}"]`);
      if(!card) return;
      [['.pm-entrada',_normHora(d.entrada)],
       ['.pm-int-ini',_normHora(d.intervaloInicio)],
       ['.pm-int-fim',_normHora(d.intervaloFim)],
       ['.pm-saida',  _normHora(d.saida)]].forEach(([sel,hora])=>{
        if(!hora) return;
        const inp=card.querySelector(sel);
        if(!inp || inp.dataset.origem==='app') return; // preserva batida do app (GPS)
        inp.value=hora;
        inp.dataset.origem='ia';
        _updatePontoOrigemMarker(inp);
        preenchidos++;
      });
    });
    calcResumoManual();
    if(preenchidos>0) toast(`IA preencheu ${preenchidos} horário(s). Confira dia a dia e clique em "Aplicar na Folha".`,'success');
    else toast('A IA não encontrou horários válidos. Lance o ponto manualmente.','warning');
    return;
  }
  // Fallback: a IA só trouxe o resumo (sem dia a dia) → preenche os totais.
  setVal('payroll-dias',numVal('ext-dias'));
  setVal('payroll-faltas-injustificadas',numVal('ext-faltas'));
  setVal('payroll-faltas-justificadas',0);
  const r=numVal('ext-remuneracao'); if(r>0) setVal('payroll-remuneracao',r.toFixed(2));
  recalculate(); closeModal('modal-pdf'); toast('Dados da folha aplicados com sucesso!');
}

// ============================================
// LEITURA DE DOCUMENTOS DO COLABORADOR COM IA (CADASTRO)
// ============================================
// Permite importar fotos/PDFs dos documentos (RG, CPF, CNH, CTPS, PIS,
// título de eleitor, comprovante de residência) e preencher automaticamente
// os campos das abas Dados Pessoais e Endereço. Usa o mesmo Worker proxy.
let _cadastroDocs = [];

function _resetCadastroImport(){
  _cadastroDocs = [];
  const fl=document.getElementById('emp-ia-filelist'); if(fl) fl.innerHTML='';
  const st=document.getElementById('emp-ia-status');   if(st) st.innerHTML='';
  const pb=document.getElementById('emp-ia-process');  if(pb){ pb.classList.add('hidden'); pb.disabled=false; }
  const fi=document.getElementById('emp-ia-files');    if(fi) fi.value='';
}

function onCadastroDocsSelected(event){
  const files=Array.from(event.target.files||[]);
  for(const f of files){
    if(!isArquivoAceito(f)){ toast(`"${f.name}" — formato não aceito (use PDF, JPG, PNG ou WEBP).`,'error'); continue; }
    if(f.size > 15*1024*1024){ toast(`"${f.name}" é grande demais (máx. 15MB).`,'error'); continue; }
    _cadastroDocs.push(f);
  }
  event.target.value='';
  _renderCadastroDocList();
}

function _renderCadastroDocList(){
  const fl=document.getElementById('emp-ia-filelist');
  const pb=document.getElementById('emp-ia-process');
  if(!fl) return;
  if(!_cadastroDocs.length){ fl.innerHTML=''; if(pb) pb.classList.add('hidden'); return; }
  fl.innerHTML=_cadastroDocs.map((f,i)=>{
    const icon = f.type==='application/pdf' ? 'fa-file-pdf' : 'fa-file-image';
    return `<div class="ia-import-file">
      <i class="fa-solid ${icon}" style="color:#4F6BF5"></i>
      <span class="fname">${f.name}</span>
      <span style="color:#94A3B8">${formatBytes(f.size)}</span>
      <button type="button" title="Remover" onclick="removeCadastroDoc(${i})"><i class="fa-solid fa-xmark"></i></button>
    </div>`;
  }).join('');
  if(pb) pb.classList.remove('hidden');
}

function removeCadastroDoc(i){
  _cadastroDocs.splice(i,1);
  _renderCadastroDocList();
}

// Chama o Gemini para extrair os dados cadastrais de UM documento
async function callGeminiCadastro(base64Data, mimeType){
  const prompt=`Você é um sistema de leitura de documentos pessoais brasileiros (RG, CPF, CNH, CTPS, PIS/NIT, Título de Eleitor, comprovante de residência, fichas de cadastro). Analise o documento e extraia TODOS os dados pessoais que conseguir identificar com segurança.

Retorne SOMENTE um JSON válido (sem markdown, sem comentários, sem explicação) neste formato exato. Para cada campo que NÃO conseguir ler com certeza, use null. NUNCA invente nem adivinhe dados.

{
  "nome": "nome completo da pessoa ou null",
  "sexo": "Masculino ou Feminino ou null",
  "rg": "número do RG/Carteira de Identidade ou null",
  "rgExpedicao": "data de expedição do RG no formato AAAA-MM-DD ou null",
  "rgOrgao": "órgão emissor do RG (ex: SSP/SP, DETRAN/RJ) ou null",
  "cpf": "número do CPF, apenas dígitos, ou null",
  "nascimento": "data de nascimento no formato AAAA-MM-DD ou null",
  "estadoCivil": "um de: Solteiro(a), Casado(a), União Estável, Divorciado(a), Separado(a), Viúvo(a) — ou null",
  "localNascimento": "cidade de naturalidade ou null",
  "ufNascimento": "sigla (2 letras) do estado de nascimento ou null",
  "raca": "um de: Branca, Preta, Parda, Amarela, Indígena — ou null",
  "nomeMae": "nome completo da mãe ou null",
  "nomePai": "nome completo do pai ou null",
  "grauInstrucao": "um de: Analfabeto, Fundamental, Médio, Técnico, Superior, Pós-graduação, Mestrado, Doutorado — ou null",
  "email": "endereço de e-mail ou null",
  "celular": "telefone celular com DDD, apenas dígitos, ou null",
  "pis": "número do PIS/PASEP/NIT ou null",
  "pisData": "data de cadastro do PIS no formato AAAA-MM-DD ou null",
  "tituloEleitor": "número do título de eleitor ou null",
  "tituloZona": "zona eleitoral ou null",
  "tituloSecao": "seção eleitoral ou null",
  "ctpsNumero": "número da CTPS (Carteira de Trabalho) ou null",
  "ctpsSerie": "série da CTPS ou null",
  "ctpsEmissao": "data de emissão da CTPS no formato AAAA-MM-DD ou null",
  "cnh": "número de registro da CNH ou null",
  "cnhCategoria": "categoria da CNH (A, B, AB, C, AC, D, AD, E, AE) ou null",
  "cep": "CEP do endereço, apenas dígitos, ou null",
  "logradouro": "nome da rua/avenida do endereço ou null",
  "numero": "número do imóvel ou null",
  "complemento": "complemento do endereço (apto, bloco, casa) ou null",
  "bairro": "bairro ou null",
  "cidade": "cidade do endereço ou null",
  "estado": "sigla (2 letras) do estado do endereço ou null"
}

REGRAS IMPORTANTES:
1. Datas SEMPRE no formato AAAA-MM-DD. Se vier como DD/MM/AAAA, converta.
2. Este arquivo pode conter apenas UM tipo de documento (ex: só um RG). Preencha os campos desse documento e deixe TODO o resto como null.
3. NÃO confunda data de expedição/emissão com data de nascimento.
4. NÃO confunda nome da pessoa com nome da mãe ou do pai.
5. Retorne APENAS o JSON.`;

  const resp=await fetch(GEMINI_PROXY_URL, {
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({ model: GEMINI_MODEL, prompt, mimeType, base64Data })
  });
  if(!resp.ok){
    const err=await resp.json().catch(()=>({error:'Resposta inválida do servidor'}));
    throw new Error(err.error?.message||err.error||'Erro na chamada Gemini via proxy');
  }
  const data=await resp.json();
  const text=data.candidates?.[0]?.content?.parts?.[0]?.text||'';
  _registrarUsoIA('cadastro', data);
  return _parseGeminiJson(text);
}

// ============================================
// IA — Importação da CCT a partir de PDF/imagem
// ============================================
// Lê o PDF/imagem da CCT que o usuário anexou no modal e preenche os campos.
async function processCctDoc(){
  const inp = document.getElementById('cct-ia-file');
  const file = inp?.files?.[0];
  const status = document.getElementById('cct-ia-status');
  if(!file){
    if(status) status.innerHTML = '<span style="color:#c0392b"><i class="fa-solid fa-triangle-exclamation"></i> Selecione um PDF ou imagem da CCT primeiro.</span>';
    return;
  }
  if(status) status.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Lendo o documento — pode levar 10–30 segundos…';
  try {
    const b64 = await new Promise((res,rej)=>{
      const r = new FileReader();
      r.onload = ()=>res(String(r.result).split(',')[1] || '');
      r.onerror = ()=>rej(new Error('Falha ao ler o arquivo.'));
      r.readAsDataURL(file);
    });
    const data = await callGeminiCct(b64, file.type || 'application/pdf');
    const n = _preencherCctDoIA(data);
    if(status) status.innerHTML = `<span style="color:#1B5E20"><i class="fa-solid fa-circle-check"></i> ${n} campo(s) preenchido(s). Confira os valores e clique em <strong>Salvar CCT</strong>.</span>`;
  } catch(e){
    console.error('processCctDoc', e);
    if(status) status.innerHTML = '<span style="color:#c0392b"><i class="fa-solid fa-triangle-exclamation"></i> Erro: ' + ((e&&e.message)||e) + '</span>';
  }
}

// Chamada ao Gemini (via Worker) com prompt focado em CCT brasileira.
async function callGeminiCct(base64Data, mimeType){
  const prompt = `Você é um sistema de leitura de Convenção Coletiva de Trabalho (CCT) brasileira. Analise o documento e extraia os valores mais importantes para gestão de folha de pagamento.

Retorne SOMENTE um JSON válido (sem markdown, sem comentários, sem explicação) neste formato exato. Para cada campo que NÃO conseguir ler com certeza, use null. NUNCA invente nem adivinhe valores.

{
  "vigencia": "data de início da vigência no formato AAAA-MM-DD ou null",
  "salarioBase": "salário-base mínimo da categoria em R$ (apenas número, ex: 1850.50) ou null",
  "vtDiario": "valor diário do vale-transporte em R$ ou null",
  "vrDiario": "valor diário do vale-refeição em R$ ou null",
  "vaMensal": "valor mensal do vale-alimentação em R$ ou null",
  "bonificacao": "valor da bonificação de Boa Permanência / Assiduidade (geralmente R$/mês) ou null",
  "plrValorAnual": "valor anual da PLR (Participação nos Lucros e Resultados) em R$ ou null",
  "percentualAdNoturno": "percentual de adicional noturno (geralmente 20) ou null",
  "salarioMinimoNacional": "salário mínimo nacional vigente em R$ ou null",
  "bancoValidadeMeses": "prazo em MESES para compensar horas do banco (geralmente 6 ou 12) ou null",
  "salariosPorFuncao": [
    { "funcao": "nome exato da função (ex.: Porteiro/Controlador de Acesso, Recepcionista de Portaria, Folguista, Fiscal de Piso/Fiscal de Loja, Op. Portaria Remota, Auxiliar/Oficial de Serv. Gerais, Zelador)", "salario": 0.00, "observacao": "texto curto se houver complemento (ex.: + Acúmulo de Função 20%) ou string vazia" }
  ]
}

REGRAS:
1. Valores monetários apenas como número (sem R$, sem pontos de milhar, ponto como separador decimal).
2. Datas SEMPRE em AAAA-MM-DD. Se vier DD/MM/AAAA, converta.
3. NÃO confunda salário-base da categoria com salário mínimo nacional.
4. "Bonificação" / "Boa Permanência" / "Assiduidade" = bônus por NÃO faltar no mês. Não confunda com PLR.
5. "salariosPorFuncao" — extraia TODAS as funções listadas no documento com seu piso salarial. Mantenha o nome EXATO como aparece no documento. Se a CCT tiver "Zelador R$ 2.144,33 + Acúmulo Função no valor de 20% salário", coloque o salário 2144.33 e a observação "+ Acúmulo de Função 20%". Se não houver lista por função, retorne array vazio [].
6. Retorne APENAS o JSON.`;

  const resp = await fetch(GEMINI_PROXY_URL, {
    method:'POST',
    headers:{'Content-Type':'application/json'},
    body:JSON.stringify({ model: GEMINI_MODEL, prompt, mimeType, base64Data })
  });
  if(!resp.ok){
    const err = await resp.json().catch(()=>({error:'Resposta inválida do servidor'}));
    throw new Error(err.error?.message||err.error||'Erro na chamada Gemini via proxy');
  }
  const data = await resp.json();
  const text = data.candidates?.[0]?.content?.parts?.[0]?.text || '';
  try { _registrarUsoIA('cct', data); } catch(_){}
  return _parseGeminiJson(text);
}

// Preenche os campos do modal-cct com o JSON da IA. Retorna a contagem preenchida.
function _preencherCctDoIA(d){
  if(!d || typeof d !== 'object') return 0;
  let n = 0;
  const _setN = (id, v, decimals) => {
    if(v == null || v === '') return;
    const num = Number(v);
    if(!isFinite(num)) return;
    setVal(id, decimals!=null ? num.toFixed(decimals) : String(num));
    n++;
  };
  if(d.vigencia){ setVal('cct-vigencia', d.vigencia); n++; }
  _setN('cct-salario-base',      d.salarioBase,           2);
  _setN('cct-vt-diario',         d.vtDiario,              2);
  _setN('cct-vr-diario',         d.vrDiario,              2);
  _setN('cct-va-mensal',         d.vaMensal,              2);
  _setN('cct-bonificacao',       d.bonificacao,           2);
  _setN('cct-adicional-noturno', d.percentualAdNoturno,   null);
  _setN('cct-salario-minimo',    d.salarioMinimoNacional, 2);
  _setN('cct-banco-validade',    d.bancoValidadeMeses,    null);
  if(d.plrValorAnual != null){
    setVal('cct-plr',       Number(d.plrValorAnual).toFixed(2));
    setVal('cct-plr-anual', Number(d.plrValorAnual).toFixed(2));
    n++;
  }
  // Salários por função — vindos do array. Faz merge com o que já está na tela
  // (preserva linhas digitadas manualmente que a IA não trouxe).
  if(Array.isArray(d.salariosPorFuncao) && d.salariosPorFuncao.length){
    const atual = _coletarSalariosFuncao();
    const norm = s => String(s||'').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'').replace(/[^a-z0-9 ]/g,' ').replace(/\s+/g,' ').trim();
    const idx = new Map(atual.map((s,i)=>[norm(s.funcao), i]));
    d.salariosPorFuncao.forEach(s=>{
      if(!s || !s.funcao) return;
      const key = norm(s.funcao);
      const salario = Number(s.salario)||0;
      const obs = String(s.observacao||'');
      if(idx.has(key)){
        const i = idx.get(key);
        atual[i] = { funcao: s.funcao, salario, observacao: obs };
      } else {
        atual.push({ funcao: s.funcao, salario, observacao: obs });
      }
    });
    renderCctSalariosFuncao(atual);
    n += d.salariosPorFuncao.length;
  }
  return n;
}

// Lê todos os documentos selecionados, mescla os resultados e preenche o formulário
async function processCadastroDocs(){
  if(!_cadastroDocs.length){ toast('Selecione ao menos um documento.','error'); return; }
  const st=document.getElementById('emp-ia-status');
  const pb=document.getElementById('emp-ia-process');
  if(pb) pb.disabled=true;
  const merged={};
  let okCount=0, errCount=0;
  for(let i=0;i<_cadastroDocs.length;i++){
    const f=_cadastroDocs[i];
    if(st) st.innerHTML=`<span style="color:#4F6BF5"><i class="fa-solid fa-spinner fa-spin"></i> 🤖 Lendo documento ${i+1} de ${_cadastroDocs.length}: <strong>${f.name}</strong>...</span>`;
    try {
      const base64=await fileToBase64(f);
      const data=await callGeminiCadastro(base64, f.type);
      for(const k in data){
        const v=data[k];
        const jaTem = merged[k]!==undefined && merged[k]!==null && String(merged[k]).trim()!=='';
        if(!jaTem && v!==null && v!==undefined && String(v).trim()!==''){
          merged[k]=v;
        }
      }
      okCount++;
    } catch(err){
      errCount++;
      console.error('Erro ao ler documento', f.name, err);
    }
  }
  if(pb) pb.disabled=false;
  if(!okCount){
    if(st) st.innerHTML=`<span style="color:#C62828"><i class="fa-solid fa-circle-xmark"></i> Não foi possível ler os documentos. Tente fotos mais nítidas e bem iluminadas, ou preencha manualmente.</span>`;
    return;
  }
  const filled=applyCadastroExtraction(merged);
  let msg=`<span style="color:#15803D"><i class="fa-solid fa-circle-check"></i> <strong>${filled}</strong> campo(s) preenchido(s) a partir de ${okCount} documento(s).`;
  if(errCount) msg+=` <span style="color:#C62828">${errCount} arquivo(s) não puderam ser lidos.</span>`;
  msg+=` Confira todas as abas antes de salvar.</span>`;
  if(st) st.innerHTML=msg;
  toast(filled>0 ? `IA preencheu ${filled} campo(s). Revise antes de salvar.` : 'A IA não encontrou dados aproveitáveis nos documentos.', filled>0?'success':'warning');
}

// Aplica os dados extraídos nos campos do formulário de colaborador
function applyCadastroExtraction(d){
  const map={
    nome:'emp-nome', sexo:'emp-sexo', rg:'emp-rg', rgExpedicao:'emp-rg-expedicao',
    rgOrgao:'emp-rg-orgao', cpf:'emp-cpf', nascimento:'emp-nascimento',
    estadoCivil:'emp-estado-civil', localNascimento:'emp-local-nascimento',
    ufNascimento:'emp-uf-nascimento', raca:'emp-raca', nomeMae:'emp-mae', nomePai:'emp-pai',
    grauInstrucao:'emp-grau-instrucao', email:'emp-email', celular:'emp-celular',
    pis:'emp-pis', pisData:'emp-pis-data', tituloEleitor:'emp-titulo',
    tituloZona:'emp-titulo-zona', tituloSecao:'emp-titulo-secao',
    ctpsNumero:'emp-ctps-numero', ctpsSerie:'emp-ctps-serie', ctpsEmissao:'emp-ctps-emissao',
    cnh:'emp-cnh', cnhCategoria:'emp-cnh-categoria', cep:'emp-cep', logradouro:'emp-endereco',
    numero:'emp-numero', complemento:'emp-complemento', bairro:'emp-bairro',
    cidade:'emp-cidade', estado:'emp-estado'
  };
  let count=0;
  for(const key in map){
    let v=d[key];
    if(v===null||v===undefined||String(v).trim()==='') continue;
    v=String(v).trim();
    const el=document.getElementById(map[key]);
    if(!el) continue;
    if(el.tagName==='SELECT'){
      const opt=Array.from(el.options).find(o=>
        o.value.toLowerCase()===v.toLowerCase() || o.text.toLowerCase()===v.toLowerCase());
      if(!opt) continue;
      el.value=opt.value;
    } else {
      el.value=v;
    }
    if(map[key]==='emp-cpf')     maskCpf(el);
    if(map[key]==='emp-celular') maskPhone(el);
    if(map[key]==='emp-cep')     maskCep(el);
    // Destaque visual temporário do campo preenchido
    el.classList.remove('ia-filled-flash');
    void el.offsetWidth;
    el.classList.add('ia-filled-flash');
    setTimeout(()=>el.classList.remove('ia-filled-flash'), 3200);
    count++;
  }
  return count;
}

// ============================================
// MÓDULO DE RESCISÃO (TRCT)
// ============================================
const RESCISAO_TIPOS = {
  sem_justa_causa: {label:'Dispensa sem justa causa',   aviso:'empregador', m13:true,  feriasProp:true,  multaFgts:'40'},
  indireta:        {label:'Rescisão indireta',          aviso:'empregador', m13:true,  feriasProp:true,  multaFgts:'40'},
  pedido_demissao: {label:'Pedido de demissão',         aviso:'empregado',  m13:true,  feriasProp:true,  multaFgts:'0'},
  justa_causa:     {label:'Dispensa por justa causa',   aviso:'nenhum',     m13:false, feriasProp:false, multaFgts:'0'},
  acordo:          {label:'Acordo (art. 484-A)',        aviso:'metade',     m13:true,  feriasProp:true,  multaFgts:'20'},
  fim_contrato:    {label:'Término de contrato',        aviso:'nenhum',     m13:true,  feriasProp:true,  multaFgts:'0'},
  experiencia_antecipada: {label:'Rescisão antecipada (experiência — Art. 479)', aviso:'nenhum', m13:true, feriasProp:true, multaFgts:'0'},
  aposentadoria:   {label:'Aposentadoria',              aviso:'nenhum',     m13:true,  feriasProp:true,  multaFgts:'0'},
  falecimento:     {label:'Falecimento do colaborador', aviso:'nenhum',     m13:true,  feriasProp:true,  multaFgts:'0'}
};

// Conta meses com >=15 dias trabalhados entre duas datas (avos de 13º / férias)
function _contaAvos(ini, fim){
  if(!ini||!fim||fim<ini) return 0;
  let avos=0, y=ini.getFullYear(), m=ini.getMonth();
  const DIA=1000*60*60*24;
  while(y<fim.getFullYear() || (y===fim.getFullYear() && m<=fim.getMonth())){
    const mIni=new Date(y,m,1), mFim=new Date(y,m+1,0);
    const dIni=ini>mIni?ini:mIni;
    const dFim=fim<mFim?fim:mFim;
    const dias=Math.round((dFim-dIni)/DIA)+1;
    if(dias>=15) avos++;
    m++; if(m>11){m=0;y++;}
  }
  return Math.min(12, avos);
}

// Avos de 13º do ano de referência: meses com >=15 dias trabalhados, de
// max(admissão, 1/jan/ano) até 31/dez/ano. Mesma regra (e função) da rescisão.
function _avosDecimo(emp, ano){
  const adm = emp && emp.dataAdmissao ? new Date(emp.dataAdmissao.substring(0,10)+'T00:00:00') : null;
  if(!adm || isNaN(adm.getTime())) return 0;
  const ini = adm > new Date(ano,0,1) ? adm : new Date(ano,0,1);
  return _contaAvos(ini, new Date(ano,11,31));
}

// Tempo de serviço detalhado: "X dias" / "X meses, Y dias" / "X anos, Y meses, Z dias"
function _formatTempoServico(adm, dem){
  if(!adm || !dem || dem<adm) return '—';
  let anos=dem.getFullYear()-adm.getFullYear();
  let meses=dem.getMonth()-adm.getMonth();
  let dias=dem.getDate()-adm.getDate();
  if(dias<0){
    const ultimoDiaMesAnterior=new Date(dem.getFullYear(), dem.getMonth(), 0).getDate();
    dias+=ultimoDiaMesAnterior;
    meses--;
  }
  if(meses<0){ meses+=12; anos--; }
  const partes=[];
  if(anos>0)  partes.push(anos+(anos===1?' ano':' anos'));
  if(meses>0) partes.push(meses+(meses===1?' mês':' meses'));
  if(dias>0)  partes.push(dias+(dias===1?' dia':' dias'));
  return partes.length ? partes.join(', ') : '0 dias';
}

// Motor de cálculo da rescisão — retorna todas as verbas e descontos
function _calcRescisao(r){
  const pl=_pl();
  const emp=r.emp||{};
  const sal=parseFloat(emp.salarioBase)||0;
  const cfg=RESCISAO_TIPOS[r.tipo]||RESCISAO_TIPOS.sem_justa_causa;
  const o={ avisoDias:0, anos:0, tempoServico:'—', saldoSalario:0, avisoValor:0, decimo:0, decimoAvos:0,
    feriasVenc:0, feriasProp:0, feriasPropAvos:0, indenizAdic:0, indenizArt479:0, indenizArt479Dias:0, indenizEstabilidade:0, estabMeses:0, inss:0, irrf:0,
    fgtsMes:0, multaFgts:0, multaPct:0, pensao:0, adiantamentos:0, avisoDescontado:0,
    outrasVerbas:0, outrosDescontos:0, totalVerbas:0, totalDescontos:0, liquido:0,
    prazoPagamento:'' };
  if(!r.dataAdmissao||!r.dataDemissao||sal<=0) return o;
  const adm=new Date(r.dataAdmissao+'T00:00:00');
  const dem=new Date(r.dataDemissao+'T00:00:00');
  if(isNaN(adm.getTime())||isNaN(dem.getTime())||dem<adm) return o;
  // Anos completos por CALENDÁRIO (mesma regra de _formatTempoServico). Dividir
  // por 365,25 "comia" o ano cheio em aniversário exato (Lei 12.506/2011 — aviso).
  { let _a=dem.getFullYear()-adm.getFullYear();
    const _m=dem.getMonth()-adm.getMonth();
    if(_m<0||(_m===0&&dem.getDate()<adm.getDate())) _a--;
    o.anos=Math.max(0,_a); }
  o.tempoServico=_formatTempoServico(adm,dem);
  // Aviso prévio (dias)
  const avisoCheio=Math.min(pl.avisoMax, pl.avisoBase+pl.avisoPorAno*o.anos);
  if(cfg.aviso==='empregador') o.avisoDias=avisoCheio;
  else if(cfg.aviso==='metade') o.avisoDias=Math.round(avisoCheio/2);
  const indeniza=(r.avisoTipo==='indenizado' && cfg.aviso!=='nenhum');
  const dataProj=new Date(dem);
  if(indeniza && o.avisoDias>0) dataProj.setDate(dataProj.getDate()+o.avisoDias);
  o.dataAfastamentoProj=`${dataProj.getFullYear()}-${String(dataProj.getMonth()+1).padStart(2,'0')}-${String(dataProj.getDate()).padStart(2,'0')}`;
  // Saldo de salário — dias do mês de desligamento efetivamente trabalhados.
  // Se admitiu e demitiu no MESMO mês, conta do dia da admissão até o desligamento
  // (inclusive), e não o mês corrido — senão pagaria dias anteriores à admissão.
  const _mesmoMesAdm = adm.getFullYear()===dem.getFullYear() && adm.getMonth()===dem.getMonth();
  const _diasSaldo = _mesmoMesAdm ? (dem.getDate()-adm.getDate()+1) : dem.getDate();
  o.saldoSalario=(sal/30)*Math.max(0,_diasSaldo);
  // Aviso prévio indenizado (valor)
  if(indeniza && o.avisoDias>0) o.avisoValor=(sal/30)*o.avisoDias;
  // 13º proporcional (avos do ano-calendário até a data projetada)
  if(cfg.m13){
    const jan1=new Date(dataProj.getFullYear(),0,1);
    const ini13=adm>jan1?adm:jan1;
    o.decimoAvos=_contaAvos(ini13, dataProj);
    o.decimo=(sal/12)*o.decimoAvos;
  }
  // Férias vencidas + 1/3 (dias informados manualmente)
  const fvDias=parseFloat(r.feriasVencidasDias)||0;
  o.feriasVenc=(sal/30)*fvDias*(4/3);
  // Férias proporcionais + 1/3 (avos do período aquisitivo em curso)
  if(cfg.feriasProp){
    let aniv=new Date(adm); aniv.setFullYear(dataProj.getFullYear());
    if(aniv>dataProj) aniv.setFullYear(aniv.getFullYear()-1);
    if(aniv<adm) aniv=new Date(adm);
    o.feriasPropAvos=_contaAvos(aniv, dataProj);
    o.feriasProp=(sal/12)*o.feriasPropAvos*(4/3);
  }
  // Indenização adicional — art. 9º Lei 7.238/84 (1 salário)
  if(r.indenizacaoAdicional) o.indenizAdic=sal;
  // Indenização Art. 479 — rescisão antecipada de contrato de experiência.
  // (metade da remuneração dos dias que faltavam até o término do contrato)
  if(r.tipo==='experiencia_antecipada' && emp.tipoContrato==='experiencia'){
    const _p1=parseInt(emp.expPeriodo1)||45;
    const _p2=parseInt(emp.expPeriodo2)||45;
    const _totalDias = emp.expDecisao1==='renovado' ? (_p1+_p2) : _p1;
    const _fimContrato = new Date(adm.getTime()+(_totalDias-1)*86400000);
    if(_fimContrato>dem){
      o.indenizArt479Dias = Math.round((_fimContrato-dem)/86400000);
      o.indenizArt479 = (sal/30)*o.indenizArt479Dias*0.5;
    }
  }
  // Indenização do período de estabilidade (situação especial)
  if(r.situacaoEspecial && r.situacaoEspecial!=='nenhuma'){
    if(r.estabModo==='calcular'){
      const fimEstab=r.situacaoFim?new Date(r.situacaoFim+'T00:00:00'):null;
      if(fimEstab && !isNaN(fimEstab.getTime()) && fimEstab>dem){
        o.estabMeses=Math.round(((fimEstab-dem)/(1000*60*60*24*30.44))*10)/10;
        o.indenizEstabilidade=Math.round(o.estabMeses*sal*100)/100;
      }
    } else {
      o.indenizEstabilidade=parseFloat(r.estabValorInformado)||0;
    }
  }
  // FGTS
  o.fgtsMes=(o.saldoSalario+o.decimo+o.avisoValor)*(pl.fgtsAliq/100);
  o.multaPct=cfg.multaFgts==='40'?pl.fgtsMulta40:(cfg.multaFgts==='20'?pl.fgtsMulta20:0);
  o.multaFgts=(parseFloat(r.saldoFgts)||0)*(o.multaPct/100);
  // Descontos — INSS / IRRF (saldo e 13º calculados em separado)
  const deps=parseInt(emp.dependentesIRRF)||0;
  const inssSaldo=calcINSS(o.saldoSalario);
  const inss13=cfg.m13?calcINSS(o.decimo):0;
  o.inss=Math.round((inssSaldo+inss13)*100)/100;
  const irrfSaldo=calcIRRF(o.saldoSalario, deps, 0, 0, inssSaldo);
  const irrf13=cfg.m13?calcIRRF(o.decimo, deps, 0, 0, inss13):0;
  o.irrf=Math.round((irrfSaldo+irrf13)*100)/100;
  o.inssSaldo=Math.round(inssSaldo*100)/100;
  o.inss13=Math.round(inss13*100)/100;
  o.irrfSaldo=Math.round(irrfSaldo*100)/100;
  o.irrf13=Math.round(irrf13*100)/100;
  // Descontos manuais
  o.pensao=parseFloat(r.pensao)||0;
  o.adiantamentos=parseFloat(r.adiantamentos)||0;
  o.avisoDescontado=parseFloat(r.avisoDescontado)||0;
  o.outrosDescontos=_somaRescItens(r.outrosDescontos);
  o.outrasVerbas=_somaRescItens(r.outrasVerbas);
  // Totais — verbas em dinheiro (a multa do FGTS vai para a conta vinculada / saque)
  o.totalVerbas=o.saldoSalario+o.avisoValor+o.decimo+o.feriasVenc+o.feriasProp+o.indenizAdic+o.indenizArt479+o.indenizEstabilidade+o.outrasVerbas;
  o.totalDescontos=o.inss+o.irrf+o.pensao+o.adiantamentos+o.avisoDescontado+o.outrosDescontos;
  o.liquido=Math.max(0, o.totalVerbas-o.totalDescontos);
  // Prazo de pagamento — 10 dias corridos (CLT art. 477 §6º)
  const prazo=new Date(dem); prazo.setDate(prazo.getDate()+10);
  o.prazoPagamento=`${String(prazo.getDate()).padStart(2,'0')}/${String(prazo.getMonth()+1).padStart(2,'0')}/${prazo.getFullYear()}`;
  return o;
}

// --- Listas dinâmicas de verbas/descontos da rescisão ---
function _somaRescItens(v){
  if(Array.isArray(v)) return v.reduce((s,i)=>s+(parseFloat(i.valor)||0),0);
  return parseFloat(v)||0;
}
function _rescItemRowHtml(descricao, valor){
  return `<div class="outro-item-row">
    <input type="text" placeholder="Descrição (ex: comissão, vale, mensalidade...)" value="${(descricao||'').replace(/"/g,'&quot;')}">
    <input type="number" placeholder="0,00" min="0" step="0.01" value="${valor||''}" oninput="recalcRescisaoModal()">
    <button type="button" class="btn-icon btn-danger-icon" onclick="removeRescItem(this)" title="Remover"><i class="fa-solid fa-xmark"></i></button>
  </div>`;
}
function renderRescItens(key, items){
  const c=document.getElementById('resc-'+key+'-list'); if(!c) return;
  let arr=items;
  if(!Array.isArray(arr)) arr=(parseFloat(items)>0)?[{descricao:'',valor:parseFloat(items)}]:[];
  c.innerHTML=arr.map(it=>_rescItemRowHtml(it.descricao,it.valor)).join('');
}
function addRescItem(key){
  const c=document.getElementById('resc-'+key+'-list'); if(!c) return;
  const wrap=document.createElement('div');
  wrap.innerHTML=_rescItemRowHtml('','');
  const row=wrap.firstElementChild;
  c.appendChild(row);
  row.querySelector('input[type="text"]')?.focus();
}
function removeRescItem(btn){
  const row=btn.closest('.outro-item-row');
  if(row) row.remove();
  recalcRescisaoModal();
}
function collectRescItens(key){
  const c=document.getElementById('resc-'+key+'-list'); if(!c) return [];
  return Array.from(c.querySelectorAll('.outro-item-row')).map(row=>{
    const ins=row.querySelectorAll('input');
    const descricao=(ins[0]?.value||'').trim();
    const valor=parseFloat(ins[1]?.value)||0;
    return (descricao||valor)?{descricao,valor}:null;
  }).filter(Boolean);
}

// Monta o objeto de rescisão a partir dos campos do modal
function _rescisaoFromModal(){
  const empId=val('resc-employee');
  const emp=State.employees.find(e=>e.id===empId);
  return {
    employeeId:empId, emp,
    tipo:val('resc-tipo')||'sem_justa_causa',
    dataAdmissao:emp?.dataAdmissao||'',
    dataDemissao:val('resc-data-demissao'),
    avisoTipo:val('resc-aviso-tipo')||'indenizado',
    feriasVencidasDias:numVal('resc-ferias-venc-dias'),
    saldoFgts:numVal('resc-saldo-fgts'),
    indenizacaoAdicional:!!document.getElementById('resc-indeniz-adic')?.checked,
    pensao:numVal('resc-pensao'),
    adiantamentos:numVal('resc-adiantamentos'),
    avisoDescontado:numVal('resc-aviso-descontado'),
    outrasVerbas:collectRescItens('verbas'),
    outrosDescontos:collectRescItens('descontos'),
    situacaoEspecial:val('resc-situacao-tipo')||'nenhuma',
    situacaoInicio:val('resc-situacao-inicio')||'',
    situacaoFim:val('resc-situacao-fim')||'',
    situacaoMotivo:val('resc-situacao-motivo')||'',
    estabModo:val('resc-estab-modo')||'informar',
    estabValorInformado:numVal('resc-estab-valor')||0,
    pago:!!document.getElementById('resc-pago')?.checked,
    observacoes:val('resc-observacoes')
  };
}

// Recalcula e preenche os campos do modal de rescisão
function recalcRescisaoModal(){
  const r=_rescisaoFromModal();
  const emp=r.emp;
  const cfg=RESCISAO_TIPOS[r.tipo]||RESCISAO_TIPOS.sem_justa_causa;
  // Mostra/oculta campo de aviso prévio conforme o tipo
  const avisoWrap=document.getElementById('resc-aviso-wrap');
  if(avisoWrap) avisoWrap.style.display=(cfg.aviso==='nenhum')?'none':'';
  const avisoDescWrap=document.getElementById('resc-aviso-descontado-wrap');
  if(avisoDescWrap) avisoDescWrap.style.display=(cfg.aviso==='empregado')?'':'none';
  if(!emp){ return; }
  // Identificação
  setVal('resc-emp-cargo', emp.cargo||emp.setor||'—');
  setVal('resc-emp-admissao', emp.dataAdmissao?formatDateBr(emp.dataAdmissao):'—');
  setVal('resc-emp-salario', (parseFloat(emp.salarioBase)||0).toFixed(2));
  const o=_calcRescisao(r);
  setVal('resc-tempo-servico', o.tempoServico||'—');
  setVal('resc-aviso-dias', o.avisoDias>0?`${o.avisoDias} dias`:'—');
  // Verbas
  setVal('resc-v-saldo',      o.saldoSalario.toFixed(2));
  setVal('resc-v-aviso',      o.avisoValor.toFixed(2));
  setVal('resc-v-13',         o.decimo.toFixed(2));
  setVal('resc-v-13-avos',    o.decimoAvos>0?`${o.decimoAvos}/12`:'—');
  setVal('resc-v-ferias-venc',o.feriasVenc.toFixed(2));
  setVal('resc-v-ferias-prop',o.feriasProp.toFixed(2));
  setVal('resc-v-ferias-prop-avos', o.feriasPropAvos>0?`${o.feriasPropAvos}/12`:'—');
  setVal('resc-v-indeniz',    o.indenizAdic.toFixed(2));
  setVal('resc-v-indeniz-art479',     o.indenizArt479.toFixed(2));
  setVal('resc-v-indeniz-art479-dias',o.indenizArt479Dias>0?`${o.indenizArt479Dias} dia(s) × 50%`:'—');
  // Descontos
  setVal('resc-d-inss',  o.inss.toFixed(2));
  setVal('resc-d-irrf',  o.irrf.toFixed(2));
  // FGTS
  setVal('resc-fgts-mes',   o.fgtsMes.toFixed(2));
  setVal('resc-multa-fgts', o.multaFgts.toFixed(2));
  setVal('resc-multa-pct',  o.multaPct>0?`${o.multaPct}%`:'não se aplica');
  // Totais
  setVal('resc-total-verbas',    o.totalVerbas.toFixed(2));
  setVal('resc-total-descontos', o.totalDescontos.toFixed(2));
  setVal('resc-liquido',         o.liquido.toFixed(2));
  setVal('resc-prazo-pagamento', o.prazoPagamento);
  // Situação especial — valor calculado e texto de apoio
  const _estabModo=val('resc-estab-modo')||'informar';
  if(_estabModo==='calcular') setVal('resc-estab-valor', o.indenizEstabilidade>0?o.indenizEstabilidade.toFixed(2):'');
  const _estabInfo=document.getElementById('resc-estab-calc-info');
  if(_estabInfo){
    const _sit=val('resc-situacao-tipo')||'nenhuma';
    if(_sit==='nenhuma') _estabInfo.innerHTML='';
    else if(_estabModo==='calcular') _estabInfo.innerHTML=o.estabMeses>0
      ? `&asymp; ${o.estabMeses} meses restantes &times; ${fmtMoney(parseFloat(emp.salarioBase)||0)} = ${fmtMoney(o.indenizEstabilidade)}. Estimativa dos salários do período — confira os reflexos (13º, férias, FGTS) com a contabilidade.`
      : 'Para o cálculo automático, informe a Data de Demissão e o "Fim previsto da estabilidade" (posterior à demissão).';
    else _estabInfo.innerHTML='Digite o valor da indenização conforme orientação da contabilidade/jurídico.';
  }
  return o;
}

function populateRescEmployees(){
  const sel=document.getElementById('resc-employee');
  if(!sel) return;
  const atuais=sel.value;
  sel.innerHTML='<option value="">— Selecione o colaborador —</option>'+
    State.employees.slice().sort((a,b)=>(a.nome||'').localeCompare(b.nome||''))
      .map(e=>`<option value="${e.id}">${e.nome}${e.registro?` (${String(e.registro).padStart(4,'0')})`:''}</option>`).join('');
  if(atuais) sel.value=atuais;
}

function openRescisaoModal(id){
  const modal=document.getElementById('modal-rescisao');
  populateRescEmployees();
  const titleEl=document.getElementById('modal-rescisao-title');
  // Reset
  ['resc-id','resc-data-demissao','resc-ferias-venc-dias','resc-saldo-fgts',
   'resc-pensao','resc-adiantamentos','resc-aviso-descontado',
   'resc-observacoes','resc-situacao-inicio','resc-situacao-fim',
   'resc-situacao-motivo','resc-estab-valor'].forEach(f=>setVal(f,''));
  setVal('resc-tipo','sem_justa_causa');
  setVal('resc-aviso-tipo','indenizado');
  setVal('resc-situacao-tipo','nenhuma');
  setVal('resc-estab-modo','informar');
  renderRescItens('verbas',[]);
  renderRescItens('descontos',[]);
  const indChk=document.getElementById('resc-indeniz-adic'); if(indChk) indChk.checked=false;
  const pagoChk=document.getElementById('resc-pago'); if(pagoChk) pagoChk.checked=false;
  const empSel=document.getElementById('resc-employee');
  if(id){
    const r=State.rescisoes.find(x=>x.id===id); if(!r) return;
    titleEl.innerHTML='<i class="fa-solid fa-file-circle-xmark"></i> Rescisão — '+( (State.employees.find(e=>e.id===r.employeeId)||{}).nome||'');
    setVal('resc-id',r.id);
    setVal('resc-employee',r.employeeId);
    setVal('resc-tipo',r.tipo||'sem_justa_causa');
    setVal('resc-data-demissao',r.dataDemissao||'');
    setVal('resc-aviso-tipo',r.avisoTipo||'indenizado');
    setVal('resc-ferias-venc-dias',r.feriasVencidasDias||'');
    setVal('resc-saldo-fgts',r.saldoFgts||'');
    if(indChk) indChk.checked=!!r.indenizacaoAdicional;
    if(pagoChk) pagoChk.checked=!!r.pago;
    setVal('resc-pensao',r.pensao||'');
    setVal('resc-adiantamentos',r.adiantamentos||'');
    setVal('resc-aviso-descontado',r.avisoDescontado||'');
    renderRescItens('verbas',r.outrasVerbas);
    renderRescItens('descontos',r.outrosDescontos);
    setVal('resc-observacoes',r.observacoes||'');
    setVal('resc-situacao-tipo',r.situacaoEspecial||'nenhuma');
    setVal('resc-situacao-inicio',r.situacaoInicio||'');
    setVal('resc-situacao-fim',r.situacaoFim||'');
    setVal('resc-situacao-motivo',r.situacaoMotivo||'');
    setVal('resc-estab-modo',r.estabModo||'informar');
    setVal('resc-estab-valor',r.estabValorInformado||'');
    empSel.disabled=true;
    _toggleRescisaoLock(r.status==='fechada');
  } else {
    titleEl.innerHTML='<i class="fa-solid fa-file-circle-xmark"></i> Nova Rescisão';
    empSel.disabled=false;
    if(State.employees.find(e=>e.id===empSel.value)) {} else empSel.value='';
    setVal('resc-pensao','');
    _toggleRescisaoLock(false);
  }
  modal.classList.remove('hidden');
  onRescSituacaoChange();
}

// Avisos jurídicos por tipo de situação especial / estabilidade
const RESC_SITUACAO_AVISOS = {
  afastamento_inss: 'Contrato SUSPENSO pelo INSS (auxílio-doença). Em regra não cabe dispensa sem justa causa durante a suspensão — confirme a viabilidade com a contabilidade/jurídico.',
  licenca_maternidade: 'Gestante/lactante tem estabilidade da confirmação da gravidez até 5 meses após o parto (ADCT art. 10, II, "b"). Dispensa sem justa causa no período gera direito à indenização do período remanescente.',
  estab_gestante: 'Estabilidade da gestante: da confirmação da gravidez até 5 meses após o parto (ADCT art. 10, II, "b"). Dispensa sem justa causa no período gera indenização do período remanescente.',
  estab_acidentaria: 'Estabilidade acidentária: 12 meses após o retorno do auxílio-doença acidentário (Lei 8.213/91, art. 118). Dispensa no período gera indenização.',
  estab_cipa: 'Membro da CIPA tem estabilidade do registro da candidatura até 1 ano após o fim do mandato. Dispensa no período gera indenização.',
  estab_pre_aposentadoria: 'Estabilidade pré-aposentadoria conforme convenção/acordo coletivo. Confira o prazo exato na CCT aplicável.',
  outra: 'Situação especial registrada. Confira as regras aplicáveis com a contabilidade/jurídico antes de concluir a rescisão.'
};

// Quando troca o colaborador no modal — puxa pensão do cadastro e, pelo
// status do colaborador, pré-seleciona a situação especial.
function onRescEmployeeChange(){
  const emp=State.employees.find(e=>e.id===val('resc-employee'));
  if(emp){
    if(!val('resc-pensao')) setVal('resc-pensao',(parseFloat(emp.pensaoAlimenticia)||0)>0?parseFloat(emp.pensaoAlimenticia).toFixed(2):'');
    if(!val('resc-data-demissao') && emp.dataDemissao) setVal('resc-data-demissao',emp.dataDemissao);
    if((val('resc-situacao-tipo')||'nenhuma')==='nenhuma'){
      if(emp.status==='licenca-maternidade'){
        setVal('resc-situacao-tipo','licenca_maternidade');
        if(emp.licencaMaternidadeInicio)  setVal('resc-situacao-inicio', emp.licencaMaternidadeInicio);
        if(emp.licencaMaternidadeTermino) setVal('resc-situacao-fim',    emp.licencaMaternidadeTermino);
        onRescSituacaoChange();
      } else if(emp.status==='afastado'){
        setVal('resc-situacao-tipo','afastamento_inss');
        onRescSituacaoChange();
      }
    }
  }
  recalcRescisaoModal();
}

// Mostra/oculta o bloco de situação especial e o aviso jurídico do tipo.
function onRescSituacaoChange(){
  const tipo=val('resc-situacao-tipo')||'nenhuma';
  const campos=document.getElementById('resc-situacao-campos');
  const aviso=document.getElementById('resc-situacao-aviso');
  if(campos) campos.style.display=(tipo==='nenhuma')?'none':'';
  if(aviso && tipo!=='nenhuma'){
    aviso.innerHTML='<i class="fa-solid fa-triangle-exclamation"></i> <div><strong>Atenção — rescisão que exige cuidado.</strong> '+(RESC_SITUACAO_AVISOS[tipo]||'')+'</div>';
  }
  onRescEstabModoChange();
}

// Alterna o campo de valor da indenização de estabilidade entre editável
// (informar) e somente leitura (calcular automaticamente).
function onRescEstabModoChange(){
  const modo=val('resc-estab-modo')||'informar';
  const campo=document.getElementById('resc-estab-valor');
  if(campo){
    campo.readOnly=(modo==='calcular');
    campo.classList.toggle('input-readonly', modo==='calcular');
  }
  recalcRescisaoModal();
}

function _toggleRescisaoLock(locked){
  const ids=['resc-tipo','resc-data-demissao','resc-aviso-tipo','resc-ferias-venc-dias',
    'resc-saldo-fgts','resc-indeniz-adic','resc-pensao','resc-adiantamentos',
    'resc-aviso-descontado','resc-observacoes','resc-situacao-tipo','resc-situacao-inicio',
    'resc-situacao-fim','resc-situacao-motivo','resc-estab-modo','resc-estab-valor'];
  ids.forEach(i=>{ const el=document.getElementById(i); if(el) el.disabled=locked; });
  document.querySelectorAll('#resc-verbas-list input, #resc-descontos-list input').forEach(el=>el.disabled=locked);
  document.querySelectorAll('#modal-rescisao button[onclick^="addRescItem"]').forEach(b=>b.disabled=locked);
  const btnSalvar=document.getElementById('resc-btn-salvar');
  const btnFechar=document.getElementById('resc-btn-fechar');
  const btnReabrir=document.getElementById('resc-btn-reabrir');
  if(btnSalvar)  btnSalvar.style.display=locked?'none':'';
  if(btnFechar)  btnFechar.style.display=locked?'none':'';
  if(btnReabrir) btnReabrir.style.display=locked?'':'none';
  const badge=document.getElementById('resc-status-badge');
  if(badge){
    badge.innerHTML=locked
      ? '<i class="fa-solid fa-lock"></i> Rescisão fechada'
      : '<i class="fa-solid fa-pen"></i> Em edição';
    badge.style.background=locked?'#FFEBEE':'#E8F5E9';
    badge.style.color=locked?'#C62828':'#1B5E20';
  }
}

async function saveRescisao(fechar){
  const empId=val('resc-employee');
  if(!empId){ toast('Selecione o colaborador.','error'); return; }
  const dataDemissao=val('resc-data-demissao');
  if(!dataDemissao){ toast('Informe a data de demissão.','error'); return; }
  const r=_rescisaoFromModal();
  const o=_calcRescisao(r);
  const existingId=val('resc-id');
  const existing=existingId?State.rescisoes.find(x=>x.id===existingId):null;
  const rec={
    id: existing?existing.id:genId(),
    employeeId:empId,
    tipo:r.tipo, dataDemissao, dataAdmissao:r.dataAdmissao,
    avisoTipo:r.avisoTipo,
    feriasVencidasDias:r.feriasVencidasDias||0,
    saldoFgts:r.saldoFgts||0,
    indenizacaoAdicional:r.indenizacaoAdicional,
    pensao:r.pensao||0, adiantamentos:r.adiantamentos||0,
    avisoDescontado:r.avisoDescontado||0,
    outrasVerbas:r.outrasVerbas||[],
    outrosDescontos:r.outrosDescontos||[],
    pago:r.pago,
    observacoes:r.observacoes||'',
    situacaoEspecial:r.situacaoEspecial||'nenhuma',
    situacaoInicio:r.situacaoInicio||'',
    situacaoFim:r.situacaoFim||'',
    situacaoMotivo:r.situacaoMotivo||'',
    estabModo:r.estabModo||'informar',
    estabValorInformado:r.estabValorInformado||0,
    // Snapshot dos valores calculados
    calc:o,
    status: fechar?'fechada':(existing?.status||'aberta'),
    fechadoEm: fechar?new Date().toISOString():(existing?.fechadoEm||''),
    updatedAt:new Date().toISOString(),
    createdAt:existing?existing.createdAt:new Date().toISOString()
  };
  const btn=document.querySelector('#modal-rescisao .btn-primary');
  setBtnLoading(btn,true,'');
  try {
    await DB.save('rescisoes', _sanitizeForFirestore(rec));
    // Ao fechar: marca o colaborador como inativo e grava a data de demissão
    if(fechar){
      const emp=State.employees.find(e=>e.id===empId);
      if(emp){
        await DB.save('employees', _sanitizeForFirestore({...emp, status:'inativo', dataDemissao}));
      }
    }
    const empNome=(State.employees.find(e=>e.id===empId)||{}).nome||'—';
    Auth.log(fechar?'RESCISAO_FECHADA':(existing?'RESCISAO_UPDATED':'RESCISAO_CREATED'), null, `${empNome} — ${RESCISAO_TIPOS[r.tipo]?.label||''}`);
    toast(fechar?'Rescisão fechada! Colaborador marcado como inativo.':'Rescisão salva.');
    closeModal('modal-rescisao');
  } catch(e){
    console.error('saveRescisao erro:',e);
    toast('Erro ao salvar rescisão: '+(e?.message||e),'error');
  } finally {
    setBtnLoading(btn,false,'<i class="fa-solid fa-floppy-disk"></i> Salvar');
  }
}

function fecharRescisao(){
  const empId=val('resc-employee');
  if(!empId||!val('resc-data-demissao')){ toast('Preencha colaborador e data de demissão.','error'); return; }
  document.getElementById('confirm-message').innerHTML=
    'Fechar esta rescisão? O cálculo será <strong>travado</strong> e o colaborador marcado como <strong>inativo</strong>.<br><br>Você poderá reabrir depois, se necessário.';
  const btn=document.getElementById('confirm-ok-btn');
  btn.innerHTML='<i class="fa-solid fa-lock"></i> Fechar Rescisão';
  btn.onclick=()=>{ closeModal('modal-confirm'); saveRescisao(true); };
  document.getElementById('modal-confirm').classList.remove('hidden');
}

function reabrirRescisao(){
  const id=val('resc-id'); const r=State.rescisoes.find(x=>x.id===id); if(!r) return;
  document.getElementById('confirm-message').textContent='Reabrir esta rescisão para edição?';
  const btn=document.getElementById('confirm-ok-btn');
  btn.innerHTML='<i class="fa-solid fa-lock-open"></i> Reabrir';
  btn.onclick=async()=>{
    try {
      await DB.save('rescisoes', _sanitizeForFirestore({...r, status:'aberta', updatedAt:new Date().toISOString()}));
      Auth.log('RESCISAO_REABERTA', null, (State.employees.find(e=>e.id===r.employeeId)||{}).nome||'—');
      closeModal('modal-confirm');
      _toggleRescisaoLock(false);
      toast('Rescisão reaberta para edição.','warning');
    } catch(e){ toast('Erro ao reabrir.','error'); }
  };
  document.getElementById('modal-confirm').classList.remove('hidden');
}

function confirmDeleteRescisao(event,id){
  if(event) event.stopPropagation();
  const r=State.rescisoes.find(x=>x.id===id); if(!r) return;
  const nome=(State.employees.find(e=>e.id===r.employeeId)||{}).nome||'—';
  document.getElementById('confirm-message').textContent=`Excluir a rescisão de ${nome}?`;
  const btn=document.getElementById('confirm-ok-btn');
  btn.innerHTML='<i class="fa-solid fa-trash"></i> Excluir';
  btn.onclick=async()=>{
    try { await DB.remove('rescisoes',id); } catch(e){}
    Auth.log('RESCISAO_DELETED', null, nome);
    closeModal('modal-confirm');
    toast('Rescisão excluída.','warning');
  };
  document.getElementById('modal-confirm').classList.remove('hidden');
}

function renderRescisoes(){
  const tbody=document.getElementById('rescisoes-tbody');
  if(!tbody) return;
  const lista=(State.rescisoes||[]).slice().sort((a,b)=>(b.dataDemissao||'').localeCompare(a.dataDemissao||''));
  if(!lista.length){
    tbody.innerHTML='<tr><td colspan="7"><div class="empty-state small"><i class="fa-solid fa-file-circle-xmark"></i><p>Nenhuma rescisão registrada</p></div></td></tr>';
    return;
  }
  tbody.innerHTML=lista.map(r=>{
    const emp=State.employees.find(e=>e.id===r.employeeId)||{};
    const tipo=RESCISAO_TIPOS[r.tipo]?.label||r.tipo||'—';
    const liq=r.calc?.liquido||0;
    const fechada=r.status==='fechada';
    const badge=fechada
      ? '<span style="background:#FFEBEE;color:#C62828;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600">Fechada</span>'
      : '<span style="background:#E8F5E9;color:#1B5E20;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600">Aberta</span>';
    const pago=r.pago?' <i class="fa-solid fa-circle-check" style="color:#2E7D32" title="Verbas pagas"></i>':'';
    return `<tr style="cursor:pointer" onclick="openRescisaoModal('${r.id}')">
      <td>${emp.nome||'—'}</td>
      <td>${tipo}</td>
      <td>${r.dataDemissao?formatDateBr(r.dataDemissao):'—'}</td>
      <td style="font-weight:600">${fmtMoney(liq)}${pago}</td>
      <td>${badge}</td>
      <td onclick="event.stopPropagation()">
        <button class="btn-icon" onclick="printTRCT('${r.id}')" title="Imprimir TRCT"><i class="fa-solid fa-print" style="color:var(--primary)"></i></button>
        <button class="btn-icon" onclick="confirmDeleteRescisao(event,'${r.id}')" title="Excluir"><i class="fa-solid fa-trash" style="color:#C62828"></i></button>
      </td>
    </tr>`;
  }).join('');
}

// Impressão do TRCT
// Monta o endereço completo da empresa em uma linha
function _empEnderecoTxt(e){
  let s=[e.endereco,e.numero].filter(Boolean).join(', ');
  if(e.complemento) s+=(s?' - ':'')+e.complemento;
  if(e.bairro)      s+=(s?' — ':'')+e.bairro;
  if(e.cidade)      s+=(s?', ':'')+e.cidade+(e.uf?'/'+e.uf:'');
  else if(e.uf)     s+=(s?' ':'')+e.uf;
  if(e.cep)         s+=(s?' — CEP ':'CEP ')+e.cep;
  return s||'—';
}

function _trctHtml(r, emp, o){
  const e=State.empresa||{};
  const tipoLabel=RESCISAO_TIPOS[r.tipo]?.label||r.tipo||'';
  const _m=v=>fmtMoney(v||0);
  const _d=iso=>iso?formatDateBr(iso):'';
  const itensVerbas=Array.isArray(r.outrasVerbas)?r.outrasVerbas:[];
  const itensDesc=Array.isArray(r.outrosDescontos)?r.outrosDescontos:[];
  // O cálculo guarda férias venc/prop já com o 1/3 — separa base e terço para o formulário
  const fVencBase=o.feriasVenc*3/4, fPropBase=o.feriasProp*3/4;
  const tercoFerias=(o.feriasVenc+o.feriasProp)/4;
  const endEmp=[e.endereco,e.numero,e.complemento].filter(Boolean).join(' ');
  const endTrab=[emp.endereco,emp.numero,emp.complemento].filter(Boolean).join(' ');
  const fld=(num,label,val,cs)=>`<td colspan="${cs}"><div class="n">${num} ${label}</div><div class="v">${(val===0||val)?val:'&nbsp;'}</div></td>`;
  const rb=(label,val)=>`<td colspan="5" class="rb">${label||'&nbsp;'}</td><td colspan="3" class="rbv">${(val!=null&&val!=='')?_m(val):'&nbsp;'}</td>`;
  const verbas=[
    {label:'50 Saldo de 30/dias de Salário', val:o.saldoSalario},
    {label:'51 Comissões', val:''},
    {label:'52 Gratificação', val:''},
    {label:'53 Adicional de Insalubridade', val:''},
    {label:'54 Adicional de Periculosidade', val:''},
    {label:'55 Adicional Noturno', val:''},
    {label:'56.1 Horas Extras', val:''},
    {label:'57 Gorjetas', val:''},
    {label:'58 Descanso Semanal Remunerado', val:''},
    {label:'59 Reflexo do DSR s/ Salário Variável', val:''},
    {label:'60 Multa Art. 477, §8º CLT', val:''},
    {label:'61 Multa Art. 479 CLT', val:''},
    {label:'62 Salário-Família', val:''},
    {label:`63 13º Salário Proporcional ${o.decimoAvos||0}/12 avos`, val:o.decimo||''},
    {label:'64.1 13º Salário Exercício /12 avos', val:''},
    {label:`65 Férias Proporcionais ${o.feriasPropAvos||0}/12 avos`, val:fPropBase||''},
    {label:'66.1 Férias Vencidas — Período Aquisitivo', val:fVencBase||''},
    {label:'68 Terço Constitucional de Férias', val:tercoFerias||''},
    {label:'69 Aviso Prévio Indenizado', val:o.avisoValor||''},
    {label:'70 13º Salário (Aviso-Prévio Indenizado)', val:''},
    {label:'71 Férias (Aviso-Prévio Indenizado)', val:''},
    {label:'95.4 Hora Atividade', val:''},
    {label:'95.27 Aviso Prévio — Lei 12.506/11', val:''},
    {label:'95.30 13º Indenizado — Lei 12.506/11', val:''},
    {label:'95.32 Férias Prop. Ind. — Lei 12.506/11', val:''},
    {label:'95.99 Garantia semestral de salários', val:''}
  ];
  if(o.indenizAdic>0) verbas.push({label:'Indenização adicional — Lei 7.238/84', val:o.indenizAdic});
  if(o.indenizArt479>0) verbas.push({label:`Indenização Art. 479 — rescisão antecipada (${o.indenizArt479Dias} dia(s) × 50%)`, val:o.indenizArt479});
  if(o.indenizEstabilidade>0) verbas.push({label:'Indenização do período de estabilidade', val:o.indenizEstabilidade});
  itensVerbas.forEach(it=>verbas.push({label:it.descricao||'Outras verbas', val:it.valor}));
  const descontos=[
    {label:'100 Pensão Alimentícia', val:o.pensao||''},
    {label:'101 Adiantamento Salarial', val:o.adiantamentos||''},
    {label:'102 Adiantamento de 13º Salário', val:''},
    {label:'103 Aviso-Prévio Indenizado', val:o.avisoDescontado||''},
    {label:'104 Indenização Art. 480 CLT', val:''},
    {label:'105 Empréstimo em Consignação', val:''},
    {label:'112.1 Previdência Social', val:o.inssSaldo||''},
    {label:'112.2 Previdência Social — 13º Salário', val:o.inss13||''},
    {label:'114.1 IRRF', val:o.irrfSaldo||''},
    {label:'114.2 IRRF sobre 13º Salário', val:o.irrf13||''},
    {label:'115.25 Mensalidade Sindical', val:''}
  ];
  itensDesc.forEach(it=>descontos.push({label:it.descricao||'Outros descontos', val:it.valor}));
  const chunk=arr=>{
    let h='';
    for(let i=0;i<arr.length;i+=3){
      const c=arr.slice(i,i+3);
      while(c.length<3) c.push({label:'',val:''});
      h+=`<tr>${c.map(x=>rb(x.label,x.val)).join('')}</tr>`;
    }
    return h;
  };
  const tipoContrato = (r.tipo==='fim_contrato' || r.tipo==='experiencia_antecipada')
    ? '2 - Contrato de trabalho por prazo determinado'
    : '1 - Contrato de trabalho por prazo indeterminado';
  return `<!DOCTYPE html><html><head><meta charset="utf-8"><title>TRCT — ${emp.nome||''}</title>
  <style>
    *{box-sizing:border-box}
    body{font-family:Arial,Helvetica,sans-serif;font-size:9px;color:#000;margin:0;padding:8mm}
    table.f{width:100%;border-collapse:collapse;table-layout:fixed}
    table.f td{border:1px solid #000;padding:1px 4px 3px;vertical-align:top;word-wrap:break-word}
    .title{text-align:center;font-weight:bold;font-size:12px;text-transform:uppercase;letter-spacing:.4px;background:#cfcfcf}
    .band{text-align:center;font-weight:bold;font-size:9px;background:#cfcfcf}
    .n{font-size:7px;line-height:1.15;color:#000}
    .v{font-size:9.5px;font-weight:bold;line-height:1.25;min-height:11px;padding-top:1px}
    .rb{font-size:7.6px;line-height:1.2}
    .rbv{font-size:9px;font-weight:bold;text-align:right}
    .hdr td{background:#ededed;font-weight:bold;font-size:7.5px;text-align:center}
    .tot td{background:#e6e6e6;font-weight:bold;font-size:9.5px}
    .liq td{background:#cfcfcf;font-weight:bold;font-size:11px}
    .ass{margin-top:34px;display:flex;justify-content:space-between;gap:34px}
    .ass div{flex:1;border-top:1px solid #000;text-align:center;padding-top:3px;font-size:8px}
    .note{font-size:8px;color:#333;margin-top:7px}
    .foot{font-size:7.5px;color:#666;margin-top:12px;text-align:center}
  </style></head><body>
  <table class="f">
    <colgroup>${'<col>'.repeat(24)}</colgroup>
    <tr><td colspan="24" class="title">Termo de Rescisão do Contrato de Trabalho</td></tr>
    <tr><td colspan="24" class="band">IDENTIFICAÇÃO DO EMPREGADOR</td></tr>
    <tr>${fld('01','CNPJ/CEI',e.cnpj,8)}${fld('02','Razão Social/Nome',e.razaoSocial||e.nomeEmpresa,16)}</tr>
    <tr>${fld('03','Endereço (logradouro, nº, andar, apartamento)',endEmp,18)}${fld('04','Bairro',e.bairro,6)}</tr>
    <tr>${fld('05','Município',e.cidade,6)}${fld('06','UF',e.uf,2)}${fld('07','CEP',e.cep,4)}${fld('08','CNAE',e.cnae,6)}${fld('09','CNPJ/CEI Tomador/Obra','',6)}</tr>
    <tr><td colspan="24" class="band">IDENTIFICAÇÃO DO TRABALHADOR</td></tr>
    <tr>${fld('10','PIS/PASEP',emp.pisNit,8)}${fld('11','Nome',emp.nome,16)}</tr>
    <tr>${fld('12','Endereço (logradouro, nº, andar, apartamento)',endTrab,18)}${fld('13','Bairro',emp.bairro,6)}</tr>
    <tr>${fld('14','Município',emp.cidade,6)}${fld('15','UF',emp.estado,2)}${fld('16','CEP',emp.cep,4)}${fld('17','CTPS (nº, série, UF)',[emp.ctpsNumero,emp.ctpsSerie,emp.estado].filter(Boolean).join(' / '),6)}${fld('18','CPF',emp.cpf,6)}</tr>
    <tr>${fld('19','Data de Nascimento',_d(emp.dataNascimento),6)}${fld('20','Nome da Mãe',emp.nomeMae,18)}</tr>
    <tr><td colspan="24" class="band">DADOS DO CONTRATO</td></tr>
    <tr>${fld('21','Tipo de Contrato',tipoContrato,24)}</tr>
    <tr>${fld('22','Causa do Afastamento',tipoLabel,24)}</tr>
    <tr>${fld('23','Remuneração Mês Ant.',_m(emp.salarioBase),6)}${fld('24','Data de Admissão',_d(emp.dataAdmissao),6)}${fld('25','Data do Aviso Prévio',_d(r.dataDemissao),4)}${fld('26','Data de Afastamento',_d(o.dataAfastamentoProj||r.dataDemissao),4)}${fld('27','Cód. Afast.','',4)}</tr>
    <tr>${fld('28','Pensão Alim. (%) TRCT','',6)}${fld('29','Pensão Alim. (%) FGTS','',6)}${fld('30','Categoria do Trabalhador','01 - Empregado',12)}</tr>
    <tr>${fld('31','Código Sindical','',6)}${fld('32','CNPJ e Nome da Entidade Sindical Laboral','',18)}</tr>
    <tr><td colspan="24" class="band">DISCRIMINAÇÃO DAS VERBAS RESCISÓRIAS</td></tr>
    <tr class="hdr"><td colspan="5">Rubrica</td><td colspan="3">Valor</td><td colspan="5">Rubrica</td><td colspan="3">Valor</td><td colspan="5">Rubrica</td><td colspan="3">Valor</td></tr>
    ${chunk(verbas)}
    <tr class="tot"><td colspan="18">TOTAL BRUTO</td><td colspan="6" class="rbv">${_m(o.totalVerbas)}</td></tr>
    <tr><td colspan="24" class="band">DEDUÇÕES</td></tr>
    <tr class="hdr"><td colspan="5">Desconto</td><td colspan="3">Valor</td><td colspan="5">Desconto</td><td colspan="3">Valor</td><td colspan="5">Desconto</td><td colspan="3">Valor</td></tr>
    ${chunk(descontos)}
    <tr class="tot"><td colspan="18">TOTAL DEDUÇÕES</td><td colspan="6" class="rbv">${_m(o.totalDescontos)}</td></tr>
    <tr class="liq"><td colspan="18">VALOR LÍQUIDO</td><td colspan="6" class="rbv">${_m(o.liquido)}</td></tr>
  </table>
  <div class="note"><strong>FGTS:</strong> depósito sobre as verbas do mês ${_m(o.fgtsMes)} &middot; multa rescisória ${o.multaFgts>0?_m(o.multaFgts)+' ('+o.multaPct+'%)':'não se aplica'} — creditada/sacada na conta vinculada do trabalhador, não integra o valor líquido em espécie.</div>
  <div class="note">Prazo de pagamento das verbas rescisórias (CLT art. 477, §6º): até <strong>${o.prazoPagamento||'—'}</strong>. Tempo de serviço: ${o.tempoServico||'—'}.</div>
  ${r.observacoes?`<div class="note"><strong>Observações:</strong> ${r.observacoes}</div>`:''}
  <div class="ass">
    <div>${e.razaoSocial||e.nomeEmpresa||'Empregador'}<br>Assinatura do Empregador</div>
    <div>${emp.nome||'Trabalhador'}<br>Assinatura do Trabalhador</div>
  </div>
  <div class="foot">Documento gerado por ${APP_VERSION} em ${new Date().toLocaleDateString('pt-BR')} — demonstrativo de conferência, não substitui o eSocial.</div>
  </body></html>`;
}

function printTRCT(id){
  const r=State.rescisoes.find(x=>x.id===id);
  if(!r){ toast('Rescisão não encontrada.','error'); return; }
  const emp=State.employees.find(e=>e.id===r.employeeId)||{};
  const o=r.calc||_calcRescisao({...r, emp});
  const nome=(emp.nome||'colaborador').replace(/\s+/g,'_');
  _abrirJanelaExport(_trctHtml(r,emp,o), 'print', `TRCT_${nome}`);
}

// Gera o TRCT a partir dos dados atuais do modal — formato: 'imprimir' | 'pdf' | 'excel'
function exportarTRCT(formato){
  const r=_rescisaoFromModal();
  if(!r.employeeId){ toast('Selecione um colaborador.','error'); return; }
  if(!r.dataDemissao){ toast('Informe a data de demissão.','error'); return; }
  const emp=r.emp||State.employees.find(e=>e.id===r.employeeId)||{};
  const o=_calcRescisao({...r, emp});
  const nome=(emp.nome||'colaborador').replace(/\s+/g,'_');
  _abrirJanelaExport(_trctHtml(r,emp,o), formato==='imprimir'?'print':formato, `TRCT_${nome}`);
}

// ============================================
// CONTRATOS
// ============================================
let _contratoTab = 'ativos';

function switchContratoTab(tab){
  _contratoTab = tab;
  document.querySelectorAll('.contrato-tab').forEach(b=>b.classList.remove('active'));
  const el = document.getElementById('tab-contratos-'+tab);
  if(el) el.classList.add('active');
  renderContratosTable();
}

// ============================================
// MÓDULO ADMINISTRAÇÃO (master only)
// ============================================
let _admTenants = [];

function _admTenantRef(id) {
  return DB.fs.collection('operator').doc('tenants').collection('lista').doc(id);
}
function _admTenantsCol() {
  return DB.fs.collection('operator').doc('tenants').collection('lista');
}

// ── Troca de abas ────────────────────────────────────────────────────────────
function switchAdminTab(tab) {
  ['tenants','faturamento','contratos'].forEach(t => {
    const content = document.getElementById(`adm-tab-${t}`);
    const btn     = document.getElementById(`adm-tab-btn-${t}`);
    if (content) content.style.display = t === tab ? '' : 'none';
    if (btn) btn.classList.toggle('active', t === tab);
  });
  if (tab === 'faturamento') renderAdminFaturamento();
  if (tab === 'contratos')   renderContratosTable();
}

// ── Carrega tenants do Firestore ─────────────────────────────────────────────
async function loadAdminTenants() {
  if (!DB.fs) return;
  try {
    const snap = await _admTenantsCol().get();
    _admTenants = snap.docs.map(d => d.data());
    _admTenants.sort((a,b) => (b.criadoEm||'') > (a.criadoEm||'') ? 1 : -1);
  } catch(e) {
    console.warn('Admin tenants:', e);
    _admTenants = [];
  }
  renderAdminStats();
  renderAdminTenants();
  _populateAdmFatSelect();
}

// ── Stats ────────────────────────────────────────────────────────────────────
function renderAdminStats() {
  const el = document.getElementById('adm-stats'); if (!el) return;
  const total   = _admTenants.length;
  const ativos  = _admTenants.filter(t => t.status === 'ativo').length;
  const trials  = _admTenants.filter(t => t.status === 'trial').length;
  const bloq    = _admTenants.filter(t => t.status === 'bloqueado').length;
  const receita = _admTenants.filter(t => t.status === 'ativo')
                             .reduce((s,t) => s + (parseFloat(t.mensalidade)||0), 0);
  el.innerHTML = `
    <div class="stat-card"><div class="stat-icon" style="background:rgba(27,94,32,.1)"><i class="fa-solid fa-server" style="color:var(--success)"></i></div>
      <div class="stat-info"><div class="stat-label">Total Clientes</div><div class="stat-value">${total}</div></div></div>
    <div class="stat-card"><div class="stat-icon" style="background:rgba(27,94,32,.1)"><i class="fa-solid fa-circle-check" style="color:var(--success)"></i></div>
      <div class="stat-info"><div class="stat-label">Ativos</div><div class="stat-value" style="color:var(--success)">${ativos}</div></div></div>
    <div class="stat-card"><div class="stat-icon" style="background:rgba(230,81,0,.1)"><i class="fa-solid fa-clock" style="color:#E65100"></i></div>
      <div class="stat-info"><div class="stat-label">Em Trial</div><div class="stat-value" style="color:#E65100">${trials}</div></div></div>
    <div class="stat-card"><div class="stat-icon" style="background:rgba(198,40,40,.1)"><i class="fa-solid fa-ban" style="color:#c62828"></i></div>
      <div class="stat-info"><div class="stat-label">Bloqueados</div><div class="stat-value" style="color:#c62828">${bloq}</div></div></div>
    <div class="stat-card"><div class="stat-icon" style="background:rgba(27,94,32,.1)"><i class="fa-solid fa-sack-dollar" style="color:var(--success)"></i></div>
      <div class="stat-info"><div class="stat-label">Receita Mensal</div><div class="stat-value" style="color:var(--success);font-size:16px">${fmtMoney(receita)}</div></div></div>`;
}

// ── Tabela de tenants ─────────────────────────────────────────────────────────
function renderAdminTenants() {
  const tbody = document.getElementById('adm-tbody'); if (!tbody) return;
  const q     = (document.getElementById('adm-busca')?.value || '').toLowerCase();
  let lista   = _admTenants;
  if (q) lista = lista.filter(t =>
    (t.nome||'').toLowerCase().includes(q) || (t.cnpj||'').includes(q));

  const title = document.getElementById('adm-tenant-title');
  if (title) title.innerHTML = `<i class="fa-solid fa-list"></i> Clientes <small style="font-weight:400;font-size:12px;color:#888">(${lista.length})</small>`;

  if (!lista.length) {
    tbody.innerHTML = `<tr><td colspan="6" class="empty-row">Nenhum cliente cadastrado.</td></tr>`;
    return;
  }

  const hoje = new Date().toISOString().split('T')[0];
  tbody.innerHTML = lista.map(t => {
    const statusBadge =
      t.status==='ativo'      ? `<span class="badge badge-success">✓ Ativo</span>` :
      t.status==='trial'      ? `<span class="badge badge-warning">⏳ Trial</span>` :
      t.status==='bloqueado'  ? `<span class="badge badge-danger">✗ Bloqueado</span>` :
                                `<span class="badge">Arquivado</span>`;
    const venc = t.validade || null;
    let vencLabel = '—';
    if (venc) {
      const diff = Math.floor((new Date(venc) - new Date()) / 86400000);
      const cor  = diff < 0 ? '#c62828' : diff <= 7 ? '#e65100' : 'inherit';
      const suf  = diff < 0 ? ` (${Math.abs(diff)}d vencido)` : diff <= 7 ? ` (em ${diff}d)` : '';
      vencLabel  = `<span style="color:${cor}">${venc.split('-').reverse().join('/')}${suf}</span>`;
    }
    const mens = t.mensalidade > 0 ? fmtMoney(t.mensalidade) : '—';
    return `<tr>
      <td><strong>${t.nome||'—'}</strong><br><span style="font-size:11px;color:#aaa">${t.cnpj||''}</span></td>
      <td style="font-size:12px">${t.plano||'—'}</td>
      <td style="font-weight:600">${mens}</td>
      <td style="font-size:12px">${vencLabel}</td>
      <td>${statusBadge}</td>
      <td>
        <div style="display:flex;gap:4px;flex-wrap:wrap">
          <button class="btn-icon" onclick="openAdmManageTenant('${t.id}')" title="Editar"><i class="fa-solid fa-gear" style="color:var(--primary)"></i></button>
          <button class="btn-icon" onclick="openAdmCobranca('${t.id}')" title="Gerar cobrança"><i class="fa-solid fa-bolt" style="color:#2e7d32"></i></button>
          <button class="btn-icon" onclick="admOperateTenant('${t.id}')" title="Operar como este tenant"><i class="fa-solid fa-arrow-right-to-bracket" style="color:#1565C0"></i></button>
        </div>
      </td>
    </tr>`;
  }).join('');
}

// ── CRUD Tenant ───────────────────────────────────────────────────────────────
function openAdmAddTenant() {
  document.getElementById('adm-tenant-modal-title').innerHTML = '<i class="fa-solid fa-plus"></i> Novo Cliente';
  ['adm-mt-id','adm-mt-nome','adm-mt-cnpj','adm-mt-mensalidade','adm-mt-tel','adm-mt-email','adm-mt-obs'].forEach(id => setVal(id,''));
  setVal('adm-mt-plano','trial'); setVal('adm-mt-status','trial');
  const d = new Date(); d.setDate(d.getDate()+30);
  setVal('adm-mt-validade', d.toISOString().split('T')[0]);
  document.getElementById('modal-adm-tenant').classList.remove('hidden');
}

function openAdmManageTenant(id) {
  const t = _admTenants.find(x => x.id === id); if (!t) return;
  document.getElementById('adm-tenant-modal-title').innerHTML = '<i class="fa-solid fa-gear"></i> Editar Cliente';
  setVal('adm-mt-id',         t.id);
  setVal('adm-mt-nome',       t.nome||'');
  setVal('adm-mt-cnpj',       t.cnpj||'');
  setVal('adm-mt-plano',      t.plano||'trial');
  setVal('adm-mt-status',     t.status||'trial');
  setVal('adm-mt-mensalidade',t.mensalidade||'');
  setVal('adm-mt-validade',   t.validade||'');
  setVal('adm-mt-tel',        t.telefone||'');
  setVal('adm-mt-email',      t.email||'');
  setVal('adm-mt-obs',        t.obs||'');
  document.getElementById('modal-adm-tenant').classList.remove('hidden');
}

async function saveAdmTenant() {
  if(!canEditModule('contratos')){ toast('Seu perfil é somente de visualização.','error'); return; }
  const nome = val('adm-mt-nome').trim();
  const cnpj = val('adm-mt-cnpj').replace(/\D/g,'');
  if (!nome || !cnpj) { toast('Nome e CNPJ são obrigatórios.','error'); return; }
  const existingId = val('adm-mt-id').trim();
  const id = existingId || cnpj;
  const rec = {
    id, nome,
    cnpj:        val('adm-mt-cnpj').trim(),
    plano:       val('adm-mt-plano'),
    status:      val('adm-mt-status'),
    mensalidade: parseFloat(val('adm-mt-mensalidade'))||0,
    validade:    val('adm-mt-validade')||null,
    telefone:    val('adm-mt-tel').trim()||null,
    email:       val('adm-mt-email').trim()||null,
    obs:         val('adm-mt-obs').trim()||null,
    updatedAt:   new Date().toISOString(),
    criadoEm:    existingId ? (_admTenants.find(t=>t.id===existingId)?.criadoEm || new Date().toISOString()) : new Date().toISOString(),
  };
  try {
    await _admTenantRef(id).set(rec, {merge:true});
    const idx = _admTenants.findIndex(t => t.id === id);
    if (idx >= 0) _admTenants[idx] = {..._admTenants[idx], ...rec};
    else _admTenants.unshift(rec);
    closeModal('modal-adm-tenant');
    renderAdminStats(); renderAdminTenants(); _populateAdmFatSelect();
    toast('Cliente salvo!', 'success');
  } catch(e) { toast('Erro ao salvar: ' + (e.message||e), 'error'); }
}

function admOperateTenant(id) {
  localStorage.setItem('drg_tenant', id);
  window.open(`index.html?tenant=${id}`, '_blank');
}

// ── Faturamento ───────────────────────────────────────────────────────────────
function _populateAdmFatSelect() {
  const sel = document.getElementById('adm-fat-tenant'); if (!sel) return;
  const cur = sel.value;
  sel.innerHTML = '<option value="">— Todos os clientes —</option>';
  _admTenants.forEach(t => {
    sel.innerHTML += `<option value="${t.id}">${t.nome}</option>`;
  });
  if (cur) sel.value = cur;
}

function renderAdminFaturamento() {
  const tenantFilt = val('adm-fat-tenant') || '';
  const tbody = document.getElementById('adm-fat-tbody'); if (!tbody) return;
  let rows = [];
  const lista = tenantFilt ? _admTenants.filter(t => t.id === tenantFilt) : _admTenants;
  lista.forEach(t => {
    (t.cobrancas || []).forEach(c => {
      rows.push({...c, tenantNome: t.nome, tenantId: t.id});
    });
  });
  rows.sort((a,b) => (b.criadoEm||'') > (a.criadoEm||'') ? 1 : -1);
  if (!rows.length) {
    tbody.innerHTML = '<tr><td colspan="7" class="empty-row">Nenhuma cobrança registrada.</td></tr>';
    return;
  }
  tbody.innerHTML = rows.slice(0,100).map(r => {
    const cor = r.status==='RECEIVED'||r.status==='CONFIRMED' ? '#2e7d32' : r.status==='OVERDUE' ? '#c62828' : r.status==='CANCELLED' ? '#888' : '#e65100';
    const link = r.invoiceUrl || r.bankSlipUrl || '';
    const cancellable = ['PENDING','OVERDUE'].includes(r.status);
    const cobId = (r.id||'').replace(/'/g,'');
    const modo  = (r.modo||'avulsa').replace(/'/g,'');
    const tId   = (r.tenantId||'').replace(/'/g,'');
    return `<tr>
      <td style="font-size:12px"><strong>${r.tenantNome}</strong></td>
      <td style="font-size:12px">${r.descricao||'—'}</td>
      <td style="font-weight:700">${fmtMoney(r.valor||0)}</td>
      <td style="font-size:12px">${(r.vencimento||'').split('-').reverse().join('/')}</td>
      <td style="font-size:11px">${r.modo==='recorrente'?'♻ Recorrente':r.tipo||'—'}</td>
      <td style="color:${cor};font-weight:600;font-size:12px">${r.status||'?'}</td>
      <td>
        <div style="display:flex;gap:4px">
          <button class="btn-icon" onclick="openAdmCobranca('${tId}')" title="Nova cobrança"><i class="fa-solid fa-bolt" style="color:#2e7d32"></i></button>
          ${link ? `<a href="${link}" target="_blank" class="btn-icon" title="Abrir link de pagamento"><i class="fa-solid fa-external-link-alt" style="color:var(--primary)"></i></a>` : ''}
          ${cancellable ? `<button class="btn-icon" onclick="cancelarAdmCobranca('${tId}','${cobId}','${modo}')" title="Cancelar cobrança"><i class="fa-solid fa-ban" style="color:#c62828"></i></button>` : ''}
        </div>
      </td>
    </tr>`;
  }).join('');
}

async function cancelarAdmCobranca(tenantId, cobId, modo) {
  if (!cobId) { toast('ID da cobrança não encontrado.','warning'); return; }
  if (!confirm('Cancelar esta cobrança? A ação não pode ser desfeita.')) return;
  try {
    if (modo === 'recorrente') {
      await _asaasReq('DELETE', `/subscriptions/${cobId}`);
    } else {
      await _asaasReq('POST', `/payments/${cobId}/cancel`);
    }
    // Atualiza status no Firestore
    const t = _admTenants.find(x => x.id === tenantId);
    if (t) {
      const cobrancas = (t.cobrancas || []).map(c => c.id === cobId ? {...c, status:'CANCELLED'} : c);
      await _admTenantRef(tenantId).set({ cobrancas }, {merge:true});
      t.cobrancas = cobrancas;
    }
    toast('Cobrança cancelada.','success');
    renderAdminFaturamento();
  } catch(e) {
    toast('Erro ao cancelar: ' + e.message,'error');
  }
}

function openAdmCobrancaRapida() {
  // Abre seletor de tenant primeiro se não houver filtro
  const tenantFilt = val('adm-fat-tenant');
  if (!tenantFilt) { toast('Selecione um cliente no filtro primeiro.','warning'); return; }
  openAdmCobranca(tenantFilt);
}

function openAdmCobranca(tenantId) {
  const t = _admTenants.find(x => x.id === tenantId); if (!t) return;
  setVal('adm-mc-tenant-id', tenantId);
  setEl('adm-mc-tenant-nome', t.nome);
  setEl('adm-mc-tenant-cnpj', t.cnpj || tenantId);
  setVal('adm-mc-valor',   t.mensalidade || '');
  setVal('adm-mc-email',   t.email || '');
  setVal('adm-mc-tipo',    'PIX');
  const d = new Date(); d.setMonth(d.getMonth()+1); d.setDate(10);
  setVal('adm-mc-vencimento', d.toISOString().split('T')[0]);
  const mesNome = new Date().toLocaleDateString('pt-BR', {month:'long', year:'numeric'});
  setVal('adm-mc-descricao', `Mensalidade DRG-Kronos — ${mesNome}`);
  document.getElementById('adm-mc-resultado').style.display = 'none';
  document.getElementById('adm-mc-resultado').innerHTML = '';
  const btn = document.getElementById('adm-btn-gerar-cobranca');
  btn.style.display='inline-flex'; btn.disabled=false;
  btn.innerHTML = '<i class="fa-solid fa-bolt"></i> Gerar Cobrança';
  // Histórico
  const hist = t.cobrancas || [];
  const histEl = document.getElementById('adm-mc-historico');
  histEl.innerHTML = hist.length === 0
    ? '<p style="color:#aaa;text-align:center;padding:6px">Nenhuma cobrança ainda.</p>'
    : hist.slice(0,5).map(c => {
        const cor = c.status==='RECEIVED'||c.status==='CONFIRMED' ? '#2e7d32' : c.status==='OVERDUE' ? '#c62828' : '#e65100';
        return `<div style="display:flex;justify-content:space-between;padding:5px 0;border-bottom:1px solid #f0f0f0;font-size:12px">
          <span><strong>${fmtMoney(c.valor||0)}</strong> <span style="color:#888">${(c.vencimento||'').split('-').reverse().join('/')}</span></span>
          <span style="color:${cor};font-weight:600">${c.status||'?'}</span>
        </div>`;
      }).join('');
  document.getElementById('modal-adm-cobranca').classList.remove('hidden');
}

function setAdmCobrancaTipo(modo) {
  setVal('adm-mc-modo', modo);
  const btnA = document.getElementById('adm-mc-btn-avulsa');
  const btnR = document.getElementById('adm-mc-btn-recorrente');
  if (btnA) { btnA.style.background = modo==='avulsa' ? '#1a3a6b' : '#f4f6fa'; btnA.style.color = modo==='avulsa' ? '#fff' : '#555'; }
  if (btnR) { btnR.style.background = modo==='recorrente' ? '#2e7d32' : '#f4f6fa'; btnR.style.color = modo==='recorrente' ? '#fff' : '#555'; }
  const cicloRow = document.getElementById('adm-mc-ciclo-row');
  if (cicloRow) cicloRow.style.display = modo==='recorrente' ? '' : 'none';
  const vencLabel = document.getElementById('adm-mc-venc-label');
  if (vencLabel) vencLabel.textContent = modo==='recorrente' ? '1ª cobrança em *' : 'Vencimento *';
}

async function executarAdmCobranca() {
  const tenantId  = val('adm-mc-tenant-id');
  const t         = _admTenants.find(x => x.id === tenantId);
  const valor     = parseFloat(val('adm-mc-valor')) || 0;
  const venc      = val('adm-mc-vencimento');
  const descricao = val('adm-mc-descricao').trim();
  const tipo      = val('adm-mc-tipo');
  const email     = val('adm-mc-email').trim();
  const modo      = val('adm-mc-modo') || 'avulsa';
  const ciclo     = val('adm-mc-ciclo') || 'MONTHLY';

  if (!valor || !venc) { toast('Preencha valor e vencimento.','warning'); return; }

  const btn = document.getElementById('adm-btn-gerar-cobranca');
  btn.disabled = true; btn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Gerando...';

  try {
    // 1. Criar/buscar cliente Asaas
    let customerId = t?.asaasCustomerId;
    if (!customerId) {
      const cnpj = (t?.cnpj || tenantId).replace(/\D/g,'');
      const busca = await _asaasReq('GET', `/customers?cpfCnpj=${cnpj}`);
      customerId = busca.data?.[0]?.id;
      if (!customerId) {
        const cli = await _asaasPost('/customers', {
          name: t.nome, cpfCnpj: cnpj,
          email: email || undefined,
          phone: t.telefone ? t.telefone.replace(/\D/g,'') : undefined,
          notificationDisabled: !email,
        });
        customerId = cli.id;
      }
      await _admTenantRef(tenantId).set({ asaasCustomerId: customerId }, {merge:true});
      if (t) t.asaasCustomerId = customerId;
    }
    // Atualiza e-mail do cliente na Asaas (garante notificação automática)
    if (email) {
      await _admTenantRef(tenantId).set({ email }, {merge:true});
      if (t) t.email = email;
      try { await _asaasReq('PUT', `/customers/${customerId}`, { email, notificationDisabled: false }); } catch(_){}
    }

    // 2. Criar cobrança avulsa (/payments) ou assinatura recorrente (/subscriptions)
    let cob;
    if (modo === 'recorrente') {
      cob = await _asaasPost('/subscriptions', {
        customer: customerId, billingType: tipo,
        value: valor, nextDueDate: venc,
        cycle: ciclo,
        description: descricao, externalReference: tenantId,
      });
    } else {
      cob = await _asaasPost('/payments', {
        customer: customerId, billingType: tipo,
        value: valor, dueDate: venc,
        description: descricao, externalReference: tenantId,
      });
    }

    const cobId     = cob.id;
    const cobStatus = cob.status;
    const link      = cob.invoiceUrl || cob.bankSlipUrl || '';

    // Dispara notificação por e-mail via Asaas (avulsa apenas)
    if (email && modo !== 'recorrente' && cobId) {
      try { await _asaasPost(`/payments/${cobId}/sendNotification`); } catch(_){}
    }

    // 3. Registrar histórico
    const cobrancas = [...(t?.cobrancas || [])];
    cobrancas.unshift({
      id: cobId, valor, vencimento: venc, descricao, tipo,
      status: cobStatus, criadoEm: new Date().toISOString(),
      modo, ...(modo==='recorrente' ? {ciclo} : {}),
      invoiceUrl: cob.invoiceUrl || null, bankSlipUrl: cob.bankSlipUrl || null,
    });
    await _admTenantRef(tenantId).set({ cobrancas: cobrancas.slice(0,50) }, {merge:true});
    if (t) t.cobrancas = cobrancas;

    // 4. Resultado
    const cicloLabels = { MONTHLY:'Mensal', QUARTERLY:'Trimestral', SEMIANNUALLY:'Semestral', YEARLY:'Anual' };
    const wNum = (t?.telefone || '').replace(/\D/g,'');
    const wMsg = encodeURIComponent(`Olá ${t?.nome}!\n\nLink de pagamento DRG-Kronos:\n${link}\n\nValor: ${fmtMoney(valor)} | Venc.: ${venc.split('-').reverse().join('/')}\n\nObrigado!`);
    const whatsUrl = wNum ? `https://wa.me/55${wNum}?text=${wMsg}` : `https://wa.me/?text=${wMsg}`;

    const resEl = document.getElementById('adm-mc-resultado');
    resEl.style.display = 'block';
    resEl.innerHTML = `<div style="background:#e8f5e9;border:1px solid #a5d6a7;border-radius:9px;padding:14px;font-size:13px">
      <strong style="color:#2e7d32"><i class="fa-solid fa-circle-check"></i> ${modo==='recorrente' ? 'Assinatura criada!' : 'Cobrança gerada!'}</strong><br>
      <span style="color:#555">ID: <code>${cobId}</code> | Status: ${cobStatus}${modo==='recorrente' ? ` | ${cicloLabels[ciclo]||ciclo}` : ''}</span>
      ${email ? `<br><span style="color:#1a73e8;font-size:12px"><i class="fa-solid fa-envelope"></i> E-mail enviado para <strong>${email}</strong></span>` : ''}
      ${link ? `<br><input type="text" value="${link}" readonly style="width:100%;margin-top:8px;padding:6px 10px;border:1px solid #ccc;border-radius:6px;font-size:12px;font-family:monospace" onclick="this.select()">` : ''}
      <div style="display:flex;gap:8px;margin-top:10px;flex-wrap:wrap">
        ${link ? `<button onclick="navigator.clipboard.writeText('${link}').then(()=>toast('Link copiado!','success'))" class="btn btn-primary btn-sm"><i class="fa-solid fa-copy"></i> Copiar Link</button>` : ''}
        <button onclick="window.open('${whatsUrl}','_blank')" class="btn btn-sm" style="background:#25D366;color:#fff;border:none"><i class="fa-brands fa-whatsapp"></i> WhatsApp</button>
      </div>
    </div>`;
    btn.style.display = 'none';
    renderAdminFaturamento();
    toast(modo==='recorrente' ? 'Assinatura criada com sucesso!' : 'Cobrança gerada com sucesso!', 'success');

  } catch(e) {
    const resEl = document.getElementById('adm-mc-resultado');
    resEl.style.display = 'block';
    resEl.innerHTML = `<div style="background:#fce4e4;border:1px solid #ef9a9a;border-radius:9px;padding:12px;font-size:13px;color:#c62828"><i class="fa-solid fa-triangle-exclamation"></i> ${e.message}</div>`;
    btn.disabled = false; btn.innerHTML = '<i class="fa-solid fa-bolt"></i> Tentar Novamente';
  }
}

function renderContratosTable(){
  const q=(val('contratos-search')||'').toLowerCase();
  const tbody=document.getElementById('contratos-tbody'); if(!tbody) return;
  // Auto-inativar contratos com data de fim passada
  const hoje=new Date(); hoje.setHours(0,0,0,0);
  let lista=State.contratos.filter(c=>{
    const inativo = c.status==='inativo' || (c.dataFim && new Date(c.dataFim+'T00:00:00')<=hoje);
    return _contratoTab==='ativos' ? !inativo : inativo;
  });
  if(q) lista=lista.filter(c=>
    (c.postoNome||'').toLowerCase().includes(q)||
    (c.objeto||'').toLowerCase().includes(q)
  );
  // Atualizar contagens nas abas
  const totalAtivos=State.contratos.filter(c=>!(c.status==='inativo'||(c.dataFim&&new Date(c.dataFim+'T00:00:00')<=hoje))).length;
  const totalInativos=State.contratos.length-totalAtivos;
  const ca=document.getElementById('count-contratos-ativos'); if(ca) ca.textContent=totalAtivos;
  const ci=document.getElementById('count-contratos-inativos'); if(ci) ci.textContent=totalInativos;
  if(lista.length===0){
    tbody.innerHTML=`<tr><td colspan="8" class="empty-row"><i class="fa-solid fa-file-signature"></i> Nenhum contrato ${_contratoTab==='ativos'?'ativo':'inativo'}</td></tr>`;
    return;
  }
  tbody.innerHTML=lista.map(c=>{
    // Calcular dias para reajuste
    let reajusteBadge='—';
    if(c.dataReajuste){
      const reaj=new Date(c.dataReajuste+'T00:00:00');
      const reajEste=new Date(hoje.getFullYear(),reaj.getMonth(),reaj.getDate());
      const dataRef=reajEste>=hoje?reajEste:new Date(hoje.getFullYear()+1,reaj.getMonth(),reaj.getDate());
      const diff=Math.round((dataRef-hoje)/(1000*60*60*24));
      const cor=diff<=7?'#C62828':diff<=30?'#E65100':'var(--success)';
      const label=diff===0?'Hoje':diff<=30?`${diff}d`:formatDateBr(c.dataReajuste);
      reajusteBadge=`<span style="color:${cor};font-weight:600;font-size:12px">${label}</span>`;
    }
    const arquivoBtn=c.arquivoUrl
      ?`<a href="${c.arquivoUrl}" target="_blank" class="btn-action btn-edit" title="Ver contrato"><i class="fa-solid fa-file-pdf"></i></a>`
      :`<span style="color:var(--text-muted);font-size:12px">—</span>`;
    return `<tr>
      <td><strong>${c.postoNome||'—'}</strong></td>
      <td style="font-size:12px;max-width:200px">${c.objeto||'—'}</td>
      <td style="font-weight:600;color:var(--success)">${c.valorMensal?fmtMoney(c.valorMensal):'—'}</td>
      <td style="font-size:12px">${formatDateBr(c.dataInicio)}</td>
      <td style="font-size:12px">${reajusteBadge}</td>
      <td style="font-size:12px">${c.dataFim?formatDateBr(c.dataFim):'<span style="color:var(--text-muted)">Indeterminado</span>'}</td>
      <td>${arquivoBtn}</td>
      <td>
        <button class="btn-action btn-edit" onclick="openContratoModal('${c.id}')" title="Editar"><i class="fa-solid fa-pen"></i></button>
        <button class="btn-action btn-danger" onclick="confirmDeleteContrato('${c.id}')" title="Excluir"><i class="fa-solid fa-trash"></i></button>
      </td>
    </tr>`;
  }).join('');
}

function populateContratoPostoSelect(){
  const sel=document.getElementById('contrato-posto'); if(!sel) return;
  const cur=sel.value;
  sel.innerHTML='<option value="">— Selecione o posto —</option>';
  [...State.postos].sort((a,b)=>(a.razaoSocial||'').localeCompare(b.razaoSocial||'')).forEach(p=>{
    const opt=document.createElement('option');
    opt.value=p.id;
    opt.textContent=p.nomeFantasia||p.razaoSocial;
    sel.appendChild(opt);
  });
  if(cur) sel.value=cur;
}

function openContratoModal(id=null){
  populateContratoPostoSelect();
  document.getElementById('modal-contrato').classList.remove('hidden');
  const titleEl=document.getElementById('modal-contrato-title');
  const uploadStatus=document.getElementById('contrato-upload-status');
  if(uploadStatus) uploadStatus.classList.add('hidden');
  if(id){
    const c=State.contratos.find(x=>x.id===id); if(!c) return;
    titleEl.innerHTML='<i class="fa-solid fa-file-signature"></i> Editar Contrato';
    setVal('contrato-id',c.id);
    // Dados do cliente
    setVal('contrato-cnpj',          c.cnpj||'');
    setVal('contrato-razao',         c.razaoSocial||'');
    setVal('contrato-endereco',      c.endereco||'');
    setVal('contrato-email',         c.email||'');
    setVal('contrato-responsavel',   c.responsavel||'');
    setVal('contrato-cpf-responsavel', c.cpfResponsavel||'');
    // Dados do contrato
    const posto=State.postos.find(p=>(p.nomeFantasia||p.razaoSocial)===c.postoNome||p.id===c.postoId);
    setVal('contrato-posto', posto?posto.id:'');
    setVal('contrato-valor', c.valorMensal||'');
    setVal('contrato-objeto', c.objeto||'');
    setVal('contrato-inicio', c.dataInicio||'');
    setVal('contrato-reajuste', c.dataReajuste||'');
    setVal('contrato-fim', c.dataFim||'');
    setVal('contrato-obs', c.observacoes||'');
    // Limpar status CNPJ
    const cnpjSt=document.getElementById('contrato-cnpj-status');
    if(cnpjSt) cnpjSt.style.display='none';
    setVal('contrato-arquivo-url', c.arquivoUrl||'');
    setVal('contrato-arquivo-nome', c.arquivoNome||'');
    // Mostrar arquivo atual se existir
    const atualDiv=document.getElementById('contrato-arquivo-atual');
    const nomeExib=document.getElementById('contrato-arquivo-nome-exib');
    const link=document.getElementById('contrato-arquivo-link');
    if(c.arquivoUrl && atualDiv && nomeExib && link){
      atualDiv.classList.remove('hidden'); atualDiv.style.display='flex';
      nomeExib.textContent=c.arquivoNome||'Contrato anexado';
      link.href=c.arquivoUrl;
    } else if(atualDiv){
      atualDiv.classList.add('hidden'); atualDiv.style.display='none';
    }
  } else {
    titleEl.innerHTML='<i class="fa-solid fa-file-signature"></i> Novo Contrato';
    ['contrato-id','contrato-cnpj','contrato-razao','contrato-endereco','contrato-email',
     'contrato-responsavel','contrato-cpf-responsavel',
     'contrato-posto','contrato-valor','contrato-objeto','contrato-inicio',
     'contrato-reajuste','contrato-fim','contrato-obs','contrato-arquivo-url','contrato-arquivo-nome']
      .forEach(id=>setVal(id,''));
    const cnpjSt=document.getElementById('contrato-cnpj-status');
    if(cnpjSt) cnpjSt.style.display='none';
    const atualDiv=document.getElementById('contrato-arquivo-atual');
    if(atualDiv){ atualDiv.classList.add('hidden'); atualDiv.style.display='none'; }
  }
}

function removerArquivoContrato(){
  setVal('contrato-arquivo-url','');
  setVal('contrato-arquivo-nome','');
  const atualDiv=document.getElementById('contrato-arquivo-atual');
  if(atualDiv){ atualDiv.classList.add('hidden'); atualDiv.style.display='none'; }
}

async function onContratoArquivoChange(event){
  const file=event.target.files[0]; if(!file) return;
  const statusEl=document.getElementById('contrato-upload-status');
  if(statusEl){ statusEl.classList.remove('hidden'); statusEl.innerHTML='<i class="fa-solid fa-circle-notch fa-spin"></i> Enviando arquivo...'; }
  try {
    const contratoId=val('contrato-id')||genId();
    setVal('contrato-id', contratoId);
    const ext=file.name.split('.').pop();
    const path=`contratos/${contratoId}/contrato_${Date.now()}.${ext}`;
    const ref=firebase.storage().ref(path);
    await ref.put(file);
    const url=await ref.getDownloadURL();
    setVal('contrato-arquivo-url', url);
    setVal('contrato-arquivo-nome', file.name);
    const atualDiv=document.getElementById('contrato-arquivo-atual');
    const nomeExib=document.getElementById('contrato-arquivo-nome-exib');
    const link=document.getElementById('contrato-arquivo-link');
    if(atualDiv&&nomeExib&&link){
      atualDiv.classList.remove('hidden'); atualDiv.style.display='flex';
      nomeExib.textContent=file.name; link.href=url;
    }
    if(statusEl){ statusEl.innerHTML='<i class="fa-solid fa-circle-check" style="color:var(--success)"></i> Arquivo enviado com sucesso!'; }
    setTimeout(()=>{ if(statusEl) statusEl.classList.add('hidden'); }, 3000);
  } catch(e){
    if(statusEl){ statusEl.innerHTML='<i class="fa-solid fa-triangle-exclamation" style="color:var(--danger)"></i> Erro ao enviar arquivo.'; }
  }
}

async function saveContrato(){
  const razao=val('contrato-razao').trim();
  const objeto=val('contrato-objeto').trim();
  const inicio=val('contrato-inicio');
  if(!razao){ toast('Informe a Razão Social do cliente.','error'); return; }
  if(!objeto){ toast('Informe o objeto do contrato.','error'); return; }
  if(!inicio){ toast('Informe a data de início.','error'); return; }
  const existingContratoId=val('contrato-id');
  const postoId=val('contrato-posto');
  const posto=postoId?State.postos.find(p=>p.id===postoId):null;
  const hoje=new Date(); hoje.setHours(0,0,0,0);
  const dataFim=val('contrato-fim');
  const inativo=!!(dataFim && new Date(dataFim+'T00:00:00')<=hoje);
  const id=val('contrato-id')||genId();
  const record={
    id,
    // Dados do cliente
    cnpj:           val('contrato-cnpj').trim(),
    razaoSocial:    razao,
    endereco:       val('contrato-endereco').trim(),
    email:          val('contrato-email').trim(),
    responsavel:    val('contrato-responsavel').trim(),
    cpfResponsavel: val('contrato-cpf-responsavel').trim(),
    // Dados do contrato
    postoId:        postoId||'',
    postoNome:      posto?(posto.nomeFantasia||posto.razaoSocial):razao,
    objeto,
    valorMensal:    numVal('contrato-valor'),
    dataInicio:     inicio,
    dataReajuste:   val('contrato-reajuste')||'',
    dataFim:        dataFim||'',
    observacoes:    val('contrato-obs').trim(),
    arquivoUrl:     val('contrato-arquivo-url')||'',
    arquivoNome:    val('contrato-arquivo-nome')||'',
    status:         inativo?'inativo':'ativo',
    updatedAt:      new Date().toISOString()
  };
  try {
    await DB.save('contratos', record);
    Auth.log(existingContratoId?'CONTRATO_UPDATED':'CONTRATO_CREATED', null, `${razao} — ${objeto.substring(0,60)}`);
    toast(existingContratoId?'Contrato atualizado!':'Contrato cadastrado!');
    closeModal('modal-contrato');
  } catch(e){ toast('Erro ao salvar contrato.','error'); }
}

function confirmDeleteContrato(id){
  if(!confirm('Excluir este contrato? Esta ação não pode ser desfeita.')) return;
  const c=State.contratos.find(x=>x.id===id);
  DB.remove('contratos', id).then(()=>{
    if(c) Auth.log('CONTRATO_DELETED', null, c.razaoSocial||id);
    toast('Contrato excluído.');
  }).catch(()=>toast('Erro ao excluir.','error'));
}

