// Lupa de busca na tabela do relatorio — filtra linhas client-side.
// Insere um campo de busca no topo da tabela e oculta linhas que nao casam.
function _ativarBuscaRelatorio(){
  const area = document.getElementById('report-body-area');
  if(!area) return;
  const table = area.querySelector('#report-main-table');
  if(!table) return;
  // Remove busca anterior (se existir) para nao duplicar
  const old = area.querySelector('.report-busca-wrap');
  if(old) old.remove();
  const wrap = document.createElement('div');
  wrap.className = 'report-busca-wrap';
  wrap.style.cssText = 'margin-bottom:10px;display:flex;gap:8px;align-items:center';
  wrap.innerHTML = `
    <div style="position:relative;flex:1;max-width:380px">
      <i class="fa-solid fa-magnifying-glass" style="position:absolute;left:11px;top:50%;transform:translateY(-50%);color:#94a3b8;font-size:13px"></i>
      <input type="text" id="report-busca-input" placeholder="Buscar por nome, matrícula, CPF, posto..." style="width:100%;padding:9px 9px 9px 32px;border:1px solid var(--border);border-radius:8px;font-size:13px">
    </div>
    <span id="report-busca-cnt" style="font-size:12px;color:#666"></span>
  `;
  area.insertBefore(wrap, table.closest('.table-responsive') || table);
  const input = document.getElementById('report-busca-input');
  const cnt   = document.getElementById('report-busca-cnt');
  const totalLinhas = table.querySelectorAll('tbody tr').length;
  const atualizar = () => {
    const q = (input.value||'').trim().toLowerCase();
    let vis = 0;
    table.querySelectorAll('tbody tr').forEach(tr => {
      const txt = tr.textContent.toLowerCase();
      const mostra = !q || txt.includes(q);
      tr.style.display = mostra ? '' : 'none';
      if(mostra) vis++;
    });
    cnt.textContent = q
      ? `${vis} de ${totalLinhas} encontrado(s)`
      : `${totalLinhas} colaborador(es)`;
  };
  input.addEventListener('input', atualizar);
  atualizar();
}

function generateReportNew(){
  const type=_currentReportType;
  if(type==='financeiro')      _reportFinanceiro();
  else if(type==='beneficios') _reportBeneficios();
  else if(type==='cadastral')  _reportCadastral();
  else if(type==='contatos')   _reportContatos();
  else if(type==='ferias-marcadas')  _reportFeriasMarcadas();
  else if(type==='ferias-pendentes') _reportFeriasPendentes();
  else if(type==='afastados')   _reportAfastados();
  else if(type==='licenca-mat') _reportLicencaMaternidade();
  else if(type==='setor')           _reportSetor();
  else if(type==='posto')           _reportPosto();
  else if(type==='individual')      _reportIndividual();
  else if(type==='postos-cadastro') _reportPostosCadastro();
  else if(type==='contratos-rel')   _reportContratos();
  else if(type==='comunicacoes')    _reportComunicacoes();
}

// Relatório de Mensagens (Auditoria) — log completo da coleção comunicacoes,
// com nome, matrícula, CPF, assunto, corpo, datas de envio e leitura.
async function _reportComunicacoes(){
  _reportHeader('Relatório de Mensagens (Auditoria)', 'Carregando...');
  document.getElementById('report-body-area').innerHTML =
    '<div style="text-align:center;padding:30px;color:#666"><i class="fa-solid fa-spinner fa-spin"></i> Carregando mensagens do banco...</div>';
  let lista = [];
  try{
    const snap = await DB.col('comunicacoes').get();
    lista = snap.docs.map(d => ({ id:d.id, ...d.data() }));
  }catch(e){
    toast('Erro ao carregar mensagens: '+(e.message||e), 'error');
    document.getElementById('report-body-area').innerHTML =
      `<div style="text-align:center;padding:20px;color:#c62828">Erro ao carregar mensagens.</div>`;
    return;
  }
  lista.sort((a,b) => (b.criadoEm||'').localeCompare(a.criadoEm||''));
  _reportHeader('Relatório de Mensagens (Auditoria)', `${lista.length} mensagem(ns) registrada(s)`);
  const totLidas    = lista.filter(m=>m.lida).length;
  const totNaoLidas = lista.length - totLidas;
  document.getElementById('report-summary').innerHTML = `
    <div class="r-stat-card"><div class="r-stat-value">${lista.length}</div><div class="r-stat-label">Total de mensagens</div></div>
    <div class="r-stat-card"><div class="r-stat-value" style="color:#16a34a">${totLidas}</div><div class="r-stat-label">Visualizadas</div></div>
    <div class="r-stat-card"><div class="r-stat-value" style="color:#94a3b8">${totNaoLidas}</div><div class="r-stat-label">Não visualizadas</div></div>
  `;
  const cols = ['#','Colaborador','Matrícula','CPF','Assunto','Mensagem','Anexo','Autor','Enviada em','Visualizada em','Status'];
  const rows = lista.length===0
    ? `<tr><td colspan="11" style="text-align:center;padding:24px;color:var(--text-muted)">Nenhuma mensagem registrada</td></tr>`
    : lista.map((m,i)=>{
        const emp = State.employees.find(e=>e.id===m.employeeId);
        const nome = (emp && emp.nome) || m.employeeNome || '—';
        const matricula = (emp && emp.registro) ? String(emp.registro).padStart(4,'0') : '—';
        const cpf  = (emp && emp.cpf) || '—';
        const enviadaEm = m.criadoEm ? new Date(m.criadoEm).toLocaleString('pt-BR') : '—';
        const lidaEm    = (m.lida && m.lidaEm) ? new Date(m.lidaEm).toLocaleString('pt-BR') : '—';
        const status    = m.lida
          ? `<span style="color:#16a34a;font-weight:600">✓✓ visualizada</span>`
          : `<span style="color:#94a3b8">✓ enviada</span>`;
        const anexoTxt = m.anexoUrl
          ? `<a href="${m.anexoUrl}" target="_blank" rel="noopener" style="color:var(--primary)">📎 ${m.anexoNome||'anexo'}</a>`
          : '—';
        const corpoTxt = (m.corpo||'').length > 250 ? (m.corpo||'').substring(0,250)+'...' : (m.corpo||'');
        const corpoEsc = corpoTxt.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
        const asEsc    = (m.assunto||'(sem assunto)').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        const editadoStr = m.editadoEm ? `<br><em style="font-size:10px;color:#94a3b8">editado ${new Date(m.editadoEm).toLocaleString('pt-BR')}</em>` : '';
        return `<tr>
          <td>${i+1}</td>
          <td><strong>${nome}</strong></td>
          <td>${matricula}</td>
          <td>${cpf}</td>
          <td>${asEsc}${editadoStr}</td>
          <td style="font-size:11px;max-width:300px">${corpoEsc}</td>
          <td>${anexoTxt}</td>
          <td>${m.origemUserNome||'—'}</td>
          <td>${enviadaEm}</td>
          <td>${lidaEm}</td>
          <td>${status}</td>
        </tr>`;
      }).join('');
  document.getElementById('report-body-area').innerHTML = _empTable(cols, rows);
}

// Relatorio de comunicacoes de UM colaborador — alimentado pelo botao "Gerar
// relatorio PDF deste colaborador" no fim da aba "Comunicacoes" do cadastro.
// Igual ao relatorio geral, mas filtrado por employeeId e sem repetir o
// nome/matricula/CPF em cada linha (vai pro cabecalho).
async function _reportComunicacoesIndividual(empId){
  const emp     = State.employees.find(e=>e.id===empId);
  const nomeEmp = (emp && emp.nome) || '—';
  const reg     = (emp && emp.registro) ? String(emp.registro).padStart(4,'0') : '—';
  const cpf     = (emp && emp.cpf) || '—';

  _reportHeader(`Comunicações — ${nomeEmp}`, 'Carregando...');
  document.getElementById('report-body-area').innerHTML =
    '<div style="text-align:center;padding:30px;color:#666"><i class="fa-solid fa-spinner fa-spin"></i> Carregando mensagens do colaborador...</div>';

  let lista = [];
  try{
    const snap = await firebase.firestore().collection('comunicacoes').where('employeeId','==',empId).get();
    lista = snap.docs.map(d => ({ id:d.id, ...d.data() }));
  }catch(e){
    toast('Erro ao carregar mensagens: '+(e.message||e), 'error');
    document.getElementById('report-body-area').innerHTML =
      `<div style="text-align:center;padding:20px;color:#c62828">Erro ao carregar mensagens.</div>`;
    return;
  }
  lista.sort((a,b) => (b.criadoEm||'').localeCompare(a.criadoEm||''));
  _reportHeader(`Comunicações — ${nomeEmp}`,
    `${lista.length} mensagem(ns) registrada(s) · Matrícula ${reg} · CPF ${cpf}`);
  const totLidas    = lista.filter(m=>m.lida).length;
  const totNaoLidas = lista.length - totLidas;
  document.getElementById('report-summary').innerHTML = `
    <div class="r-stat-card"><div class="r-stat-value">${lista.length}</div><div class="r-stat-label">Total de mensagens</div></div>
    <div class="r-stat-card"><div class="r-stat-value" style="color:#16a34a">${totLidas}</div><div class="r-stat-label">Visualizadas</div></div>
    <div class="r-stat-card"><div class="r-stat-value" style="color:#94a3b8">${totNaoLidas}</div><div class="r-stat-label">Não visualizadas</div></div>
  `;
  const cols = ['#','Assunto','Mensagem','Anexo','Autor','Enviada em','Visualizada em','Status'];
  const rows = lista.length===0
    ? `<tr><td colspan="8" style="text-align:center;padding:24px;color:var(--text-muted)">Nenhuma mensagem registrada para este colaborador</td></tr>`
    : lista.map((m,i)=>{
        const enviadaEm = m.criadoEm ? new Date(m.criadoEm).toLocaleString('pt-BR') : '—';
        const lidaEm    = (m.lida && m.lidaEm) ? new Date(m.lidaEm).toLocaleString('pt-BR') : '—';
        const status    = m.lida
          ? `<span style="color:#16a34a;font-weight:600">✓✓ visualizada</span>`
          : `<span style="color:#94a3b8">✓ enviada</span>`;
        const anexoTxt = m.anexoUrl
          ? `<a href="${m.anexoUrl}" target="_blank" rel="noopener" style="color:var(--primary)">📎 ${m.anexoNome||'anexo'}</a>`
          : '—';
        const corpoTxt = (m.corpo||'').length > 400 ? (m.corpo||'').substring(0,400)+'...' : (m.corpo||'');
        const corpoEsc = corpoTxt.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>');
        const asEsc    = (m.assunto||'(sem assunto)').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        const editadoStr = m.editadoEm ? `<br><em style="font-size:10px;color:#94a3b8">editado ${new Date(m.editadoEm).toLocaleString('pt-BR')}</em>` : '';
        return `<tr>
          <td>${i+1}</td>
          <td>${asEsc}${editadoStr}</td>
          <td style="font-size:11px;max-width:340px">${corpoEsc}</td>
          <td>${anexoTxt}</td>
          <td>${m.origemUserNome||'—'}</td>
          <td>${enviadaEm}</td>
          <td>${lidaEm}</td>
          <td>${status}</td>
        </tr>`;
      }).join('');
  document.getElementById('report-body-area').innerHTML = _empTable(cols, rows);
}

// Abre o modal universal de relatorios em "modo dedicado" (sem o grid de tipos
// e sem os filtros) e renderiza direto o log de mensagens deste colaborador.
// Chamado pelo botao "Gerar relatorio PDF deste colaborador" na aba Comunicacoes.
async function gerarRelatorioComunicacoesIndividual(empId){
  if(!empId){ toast('Salve o colaborador primeiro.','warning'); return; }
  closeModal('modal-employee');
  // Pequeno delay para o modal do colaborador fechar antes de abrir o de relatorios
  await new Promise(r => setTimeout(r, 120));
  const modal = document.getElementById('modal-reports');
  if(!modal) return;
  // Esconde grid de tipos e area de filtros — entramos em modo dedicado.
  // O openReportsModal restaura essa visibilidade quando for chamado normal.
  const gridParent = document.getElementById('report-type-grid')?.parentElement;
  if(gridParent) gridParent.style.display = 'none';
  const filtersArea = document.getElementById('report-filters-area');
  if(filtersArea) filtersArea.style.display = 'none';
  // Define o tipo para o printReport saber que e' landscape
  window._currentReportType = 'comunicacoes';
  // Titulo do modal
  const titleEl = document.getElementById('modal-reports-title');
  const emp = State.employees.find(e=>e.id===empId);
  if(titleEl){
    titleEl.innerHTML = `<i class="fa-solid fa-envelope"></i> Comunicações — ${(emp&&emp.nome)||'Colaborador'}`;
  }
  modal.classList.remove('hidden');
  await _reportComunicacoesIndividual(empId);
}

// ===========================================================================
// SECAO "COMUNICACAO" — centro de mensagens do menu lateral
// ===========================================================================
// State dos filtros da secao (mantido entre re-renders).
let _comuSecaoFiltros = { busca:'', status:'todas', periodo:'30', somenteAnexo:false };
let _comuSecaoCache   = null;   // array das mensagens do banco
let _comuSecaoCarregando = false;

async function renderComunicacaoSection(){
  const box = document.getElementById('comunicacao-content');
  if(!box) return;
  // 1a vez: carrega do banco. Demais: usa cache (o usuario pode "Atualizar" se quiser).
  if(!_comuSecaoCache && !_comuSecaoCarregando){
    _comuSecaoCarregando = true;
    box.innerHTML = '<div style="text-align:center;padding:40px;color:#666"><i class="fa-solid fa-spinner fa-spin"></i> Carregando mensagens do banco...</div>';
    try{
      const snap = await DB.col('comunicacoes').get();
      _comuSecaoCache = snap.docs.map(d => ({ id:d.id, ...d.data() }));
    }catch(e){
      console.error('comunicacao:fetch', e);
      _comuSecaoCache = [];
      toast('Erro ao carregar mensagens: '+(e.message||e),'error');
    }
    _comuSecaoCarregando = false;
  }
  _renderComunicacaoUI();
}

// Forca recarga do banco — chamado pelo botao "Atualizar"
async function atualizarComunicacaoSection(){
  _comuSecaoCache = null;
  await renderComunicacaoSection();
  toast('Lista atualizada.','success');
}

function _comuSecaoSetFiltro(key, valor){
  _comuSecaoFiltros[key] = valor;
  _renderComunicacaoUI();
}

function _renderComunicacaoUI(){
  const box = document.getElementById('comunicacao-content');
  if(!box) return;
  const todas = _comuSecaoCache || [];
  // aplica filtros
  const D = 86400000;
  const agora = Date.now();
  const dias = parseInt(_comuSecaoFiltros.periodo||'30',10);
  const busca = (_comuSecaoFiltros.busca||'').trim().toLowerCase();
  const filtradas = todas.filter(m => {
    if(dias>0 && m.criadoEm){
      const dt = new Date(m.criadoEm).getTime();
      if(isFinite(dt) && (agora - dt) > dias*D) return false;
    }
    if(_comuSecaoFiltros.status==='lidas'    && !m.lida) return false;
    if(_comuSecaoFiltros.status==='naoLidas' && m.lida)  return false;
    if(_comuSecaoFiltros.somenteAnexo && !m.anexoUrl)    return false;
    if(busca){
      const blob = `${m.assunto||''} ${m.corpo||''} ${m.employeeNome||''} ${m.origemUserNome||''}`.toLowerCase();
      if(!blob.includes(busca)) return false;
    }
    return true;
  });
  filtradas.sort((a,b) => (b.criadoEm||'').localeCompare(a.criadoEm||''));
  // stats — sobre o filtro corrente
  const totLidas    = filtradas.filter(m=>m.lida).length;
  const totNaoLidas = filtradas.length - totLidas;
  const totAnexo    = filtradas.filter(m=>m.anexoUrl).length;
  // monta UI
  const fmtDt = iso => { const d=iso?new Date(iso):null; if(!d||isNaN(d.getTime())) return '—'; return d.toLocaleDateString('pt-BR') + ' ' + d.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}); };
  const podeApagar = !!getUserModules(Auth.currentUser).comunicacoesApagar || Auth.currentUser?.role==='master';
  // popula o cache de mensagens (reutilizado por editarMensagem/reenviarMensagem/apagarComunicacao)
  filtradas.forEach(m => { _comuMensagensCache[m.id] = m; });
  // header (botoes)
  const headerHtml = `
    <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:18px">
      <div>
        <h2 style="margin:0;font-size:20px;color:var(--text)"><i class="fa-solid fa-comments" style="color:#1976D2"></i> Centro de Mensagens</h2>
        <div style="font-size:12px;color:#888;margin-top:4px">Envie mensagens individualmente ou em massa para colaboradores. Tudo fica registrado para auditoria.</div>
      </div>
      <div style="display:flex;gap:8px;flex-wrap:wrap">
        <button class="btn btn-primary" onclick="openComunicarModal()"><i class="fa-solid fa-paper-plane"></i> Nova mensagem</button>
        <button class="btn btn-outline" onclick="atualizarComunicacaoSection()" title="Recarregar do banco"><i class="fa-solid fa-rotate"></i> Atualizar</button>
        <button class="btn btn-outline" onclick="abrirRelatorioComunicacoesGeral()" title="Gerar relatorio PDF com auditoria de todas as mensagens"><i class="fa-solid fa-file-pdf"></i> Relatório (auditoria)</button>
      </div>
    </div>`;
  // stats cards (alinhados ao padrao do sistema) — clicaveis, abrem drill-down
  const _cardStyle = `background:#fff;border:1px solid var(--border);border-radius:10px;padding:14px;text-align:center;cursor:pointer;transition:transform .15s ease,box-shadow .15s ease,border-color .15s ease`;
  const _cardHover = `onmouseover="this.style.transform='translateY(-2px)';this.style.boxShadow='0 6px 14px rgba(0,0,0,.08)';" onmouseout="this.style.transform='';this.style.boxShadow='';"`;
  const statsHtml = `
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(160px,1fr));gap:12px;margin-bottom:18px">
      <div style="${_cardStyle};border-top:3px solid #1976D2" ${_cardHover} onclick="_comuDrillDown('todas')" title="Ver todas (filtro atual)">
        <div style="font-size:24px;font-weight:700;color:#1976D2">${filtradas.length}</div>
        <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:.4px">Mensagens (filtro)</div>
      </div>
      <div style="${_cardStyle};border-top:3px solid #16a34a" ${_cardHover} onclick="_comuDrillDown('lidas')" title="Ver so as visualizadas">
        <div style="font-size:24px;font-weight:700;color:#16a34a">${totLidas}</div>
        <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:.4px">Visualizadas</div>
      </div>
      <div style="${_cardStyle};border-top:3px solid #94a3b8" ${_cardHover} onclick="_comuDrillDown('naoLidas')" title="Ver so as nao visualizadas">
        <div style="font-size:24px;font-weight:700;color:#94a3b8">${totNaoLidas}</div>
        <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:.4px">Não visualizadas</div>
      </div>
      <div style="${_cardStyle};border-top:3px solid #E65100" ${_cardHover} onclick="_comuDrillDown('anexo')" title="Ver so com anexo">
        <div style="font-size:24px;font-weight:700;color:#E65100">${totAnexo}</div>
        <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:.4px">Com anexo</div>
      </div>
    </div>`;
  // filtros
  const filtrosHtml = `
    <div style="background:#f8fafc;border:1px solid var(--border);border-radius:10px;padding:14px;margin-bottom:18px">
      <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;align-items:end">
        <div>
          <label style="font-size:12px;color:#475569;display:block;margin-bottom:4px">Buscar</label>
          <input type="text" id="comu-sec-busca" placeholder="Nome, assunto, corpo..." value="${(_comuSecaoFiltros.busca||'').replace(/"/g,'&quot;')}" oninput="_comuSecaoSetFiltro('busca', this.value)" style="width:100%;padding:8px;border:1px solid var(--border);border-radius:6px;font-size:13px">
        </div>
        <div>
          <label style="font-size:12px;color:#475569;display:block;margin-bottom:4px">Status leitura</label>
          <select onchange="_comuSecaoSetFiltro('status', this.value)" style="width:100%;padding:8px;border:1px solid var(--border);border-radius:6px;font-size:13px">
            <option value="todas"    ${_comuSecaoFiltros.status==='todas'?'selected':''}>Todas</option>
            <option value="lidas"    ${_comuSecaoFiltros.status==='lidas'?'selected':''}>Visualizadas</option>
            <option value="naoLidas" ${_comuSecaoFiltros.status==='naoLidas'?'selected':''}>Não visualizadas</option>
          </select>
        </div>
        <div>
          <label style="font-size:12px;color:#475569;display:block;margin-bottom:4px">Período</label>
          <select onchange="_comuSecaoSetFiltro('periodo', this.value)" style="width:100%;padding:8px;border:1px solid var(--border);border-radius:6px;font-size:13px">
            <option value="7"   ${_comuSecaoFiltros.periodo==='7'?'selected':''}>Últimos 7 dias</option>
            <option value="30"  ${_comuSecaoFiltros.periodo==='30'?'selected':''}>Últimos 30 dias</option>
            <option value="90"  ${_comuSecaoFiltros.periodo==='90'?'selected':''}>Últimos 90 dias</option>
            <option value="365" ${_comuSecaoFiltros.periodo==='365'?'selected':''}>Último ano</option>
            <option value="0"   ${_comuSecaoFiltros.periodo==='0'?'selected':''}>Todas</option>
          </select>
        </div>
        <div style="display:flex;align-items:center;gap:6px;padding-top:18px">
          <input type="checkbox" id="comu-sec-anexo" ${_comuSecaoFiltros.somenteAnexo?'checked':''} onchange="_comuSecaoSetFiltro('somenteAnexo', this.checked)">
          <label for="comu-sec-anexo" style="font-size:13px;color:#475569;cursor:pointer">Somente com anexo</label>
        </div>
      </div>
    </div>`;
  // lista de mensagens (cards)
  let listaHtml;
  if(!filtradas.length){
    listaHtml = `<div class="empty-state"><i class="fa-solid fa-envelope-open"></i><p>Nenhuma mensagem encontrada com este filtro.</p></div>`;
  } else {
    listaHtml = filtradas.map(m => {
      const dtTxt = fmtDt(m.criadoEm);
      const empCad = State.employees.find(e=>e.id===m.employeeId);
      const nomeLink = empCad
        ? `<a href="javascript:void(0)" onclick="openEmployeeModal('${m.employeeId}')" style="color:var(--primary);text-decoration:none;border-bottom:1px dotted var(--primary)">${m.employeeNome||empCad.nome||'—'}</a>`
        : (m.employeeNome||'—');
      const anexo = m.anexoUrl ? `<div style="margin-top:6px;font-size:12px"><a href="${m.anexoUrl}" target="_blank" rel="noopener" style="color:var(--primary)"><i class="fa-solid fa-paperclip"></i> ${m.anexoNome||'anexo'}</a></div>` : '';
      const statusBadge = m.lida
        ? `<span style="background:#dcfce7;color:#166534;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600">✓✓ Visualizada${m.lidaEm?' '+fmtDt(m.lidaEm):''}</span>`
        : `<span style="background:#f1f5f9;color:#475569;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600">✓ Não visualizada</span>`;
      return `<div style="background:#fff;border:1px solid var(--border);border-radius:10px;padding:14px;margin-bottom:10px">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:10px;margin-bottom:6px">
          <div>
            <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:.4px;margin-bottom:2px">Para</div>
            <div style="font-weight:600;font-size:14px;color:var(--text)">${nomeLink}</div>
          </div>
          <div style="text-align:right;font-size:11px;color:#999">${dtTxt}</div>
        </div>
        <div style="font-weight:700;font-size:14px;color:var(--text);margin-top:8px">${(m.assunto||'(sem assunto)').replace(/</g,'&lt;')}</div>
        <div style="font-size:13px;color:#555;margin-top:4px;white-space:pre-wrap;line-height:1.45">${(m.corpo||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}</div>
        ${anexo}
        <div style="margin-top:10px;padding-top:8px;border-top:1px dashed var(--border);display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px">
          <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">
            ${statusBadge}
            <span style="font-size:11px;color:#888">Enviada por ${m.origemUserNome||'—'}${m.editadoEm?` · <em>editada</em>`:''}</span>
          </div>
          <div style="display:flex;gap:6px;flex-wrap:wrap">
            <button type="button" onclick="editarMensagem('${m.id}')" class="btn btn-sm btn-outline" style="font-size:11px;padding:4px 10px;color:#E65100;border-color:#FFCC80"><i class="fa-solid fa-pen"></i> Editar</button>
            <button type="button" onclick="reenviarMensagem('${m.id}')" class="btn btn-sm btn-outline" style="font-size:11px;padding:4px 10px;color:#1976D2;border-color:#1976D2"><i class="fa-solid fa-rotate-right"></i> Reenviar</button>
            ${podeApagar?`<button type="button" onclick="_apagarComuSecao('${m.id}')" class="btn btn-sm btn-outline" style="font-size:11px;padding:4px 10px;color:#c62828;border-color:#ef9a9a"><i class="fa-solid fa-trash"></i> Apagar</button>`:''}
          </div>
        </div>
      </div>`;
    }).join('');
  }
  box.innerHTML = headerHtml + statsHtml + filtrosHtml + listaHtml;
  // reposiciona o cursor no campo de busca (perdido pelo innerHTML)
  if(_comuSecaoFiltros.busca){
    const el = document.getElementById('comu-sec-busca');
    if(el){ el.focus(); el.setSelectionRange(el.value.length, el.value.length); }
  }
}

// Apagar mensagem na secao Comunicacao + atualizar a UI local sem refetch.
async function _apagarComuSecao(msgId){
  await apagarComunicacao(msgId);
  // remove do cache local e re-renderiza
  if(Array.isArray(_comuSecaoCache)){
    _comuSecaoCache = _comuSecaoCache.filter(m=>m.id!==msgId);
  }
  _renderComunicacaoUI();
}

// Atalho para o relatorio geral (mesmo do menu de Relatorios → "Mensagens (Auditoria)")
function abrirRelatorioComunicacoesGeral(){
  openReportsModal(['comunicacoes'], 'Mensagens (Auditoria)');
}

// Drill-down dos cards estatisticos — combina o filtro atual da secao com
// o stat clicado e abre lista enxuta em modal flutuante. Cada linha leva
// ao cadastro do colaborador na aba Comunicacoes.
function _comuDrillDown(stat){
  const todas = _comuSecaoCache || [];
  // 1) aplica os MESMOS filtros que ja estao ativos na tela
  const D = 86400000;
  const agora = Date.now();
  const dias = parseInt(_comuSecaoFiltros.periodo||'30',10);
  const busca = (_comuSecaoFiltros.busca||'').trim().toLowerCase();
  let lista = todas.filter(m => {
    if(dias>0 && m.criadoEm){
      const dt = new Date(m.criadoEm).getTime();
      if(isFinite(dt) && (agora - dt) > dias*D) return false;
    }
    if(_comuSecaoFiltros.status==='lidas'    && !m.lida) return false;
    if(_comuSecaoFiltros.status==='naoLidas' && m.lida)  return false;
    if(_comuSecaoFiltros.somenteAnexo && !m.anexoUrl)    return false;
    if(busca){
      const blob = `${m.assunto||''} ${m.corpo||''} ${m.employeeNome||''} ${m.origemUserNome||''}`.toLowerCase();
      if(!blob.includes(busca)) return false;
    }
    return true;
  });
  // 2) aplica o filtro do card clicado (alem do que ja' tinha)
  let titulo = 'Mensagens (filtro atual)';
  let cor    = '#1976D2';
  if(stat==='lidas'){
    lista = lista.filter(m => m.lida);
    titulo = 'Mensagens visualizadas pelo colaborador';
    cor = '#16a34a';
  } else if(stat==='naoLidas'){
    lista = lista.filter(m => !m.lida);
    titulo = 'Mensagens não visualizadas ainda';
    cor = '#94a3b8';
  } else if(stat==='anexo'){
    lista = lista.filter(m => m.anexoUrl);
    titulo = 'Mensagens com anexo';
    cor = '#E65100';
  }
  // Define qual data e' relevante para o card clicado:
  // - "lidas" → ordena e mostra LIDA EM (quando o colaborador viu)
  // - demais → ordena e mostra ENVIADA EM (criadoEm)
  const usarLidaEm = (stat==='lidas');
  const campoData  = usarLidaEm ? 'lidaEm' : 'criadoEm';
  const rotuloData = usarLidaEm ? 'Lida em' : 'Enviada em';
  lista.sort((a,b) => (b[campoData]||b.criadoEm||'').localeCompare(a[campoData]||a.criadoEm||''));
  // 3) monta lista enxuta — clicar leva ao cadastro do colaborador
  const fmtDt = iso => { const d=iso?new Date(iso):null; if(!d||isNaN(d.getTime())) return '—'; return d.toLocaleDateString('pt-BR') + ' ' + d.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}); };
  const linhasHtml = lista.length === 0
    ? `<div style="text-align:center;padding:30px;color:#94a3b8"><i class="fa-solid fa-folder-open"></i><div style="margin-top:6px">Nenhum registro com este filtro</div></div>`
    : lista.map(m => {
        const emp = State.employees.find(e=>e.id===m.employeeId);
        const nomeEmp = (emp && emp.nome) || m.employeeNome || '—';
        const reg = (emp && emp.registro) ? String(emp.registro).padStart(4,'0') : '—';
        const ico = m.anexoUrl ? `<i class="fa-solid fa-paperclip" style="color:#E65100;margin-left:4px" title="Tem anexo"></i>` : '';
        const stat = m.lida
          ? `<span style="color:#16a34a;font-weight:600;font-size:11px">✓✓</span>`
          : `<span style="color:#94a3b8;font-size:11px">✓</span>`;
        // Data principal varia: se for card "Visualizadas", mostra LIDA EM
        const dtPrincipal = usarLidaEm ? m.lidaEm : m.criadoEm;
        return `<div onclick="_comuAbrirRegistroDoCard('${m.employeeId}')" style="display:flex;align-items:center;gap:10px;padding:10px 12px;border-bottom:1px solid #f1f5f9;cursor:pointer;transition:background .15s" onmouseover="this.style.background='#f8fafc'" onmouseout="this.style.background=''">
          <div style="flex:1;min-width:0">
            <div style="font-weight:600;font-size:13px;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${nomeEmp} ${ico}</div>
            <div style="font-size:11px;color:#94a3b8">Reg. ${reg} · ${m.origemUserNome||'—'}</div>
            <div style="font-size:12px;color:#475569;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;margin-top:2px">${(m.assunto||'(sem assunto)').replace(/</g,'&lt;')}</div>
          </div>
          <div style="text-align:right;flex-shrink:0">
            <div style="font-size:10px;color:${usarLidaEm?'#16a34a':'#94a3b8'};text-transform:uppercase;letter-spacing:.4px;font-weight:600">${rotuloData}</div>
            <div style="font-size:11px;color:#666;white-space:nowrap">${fmtDt(dtPrincipal)}</div>
            ${usarLidaEm ? `<div style="font-size:10px;color:#94a3b8;margin-top:2px" title="Enviada em">env. ${fmtDt(m.criadoEm)}</div>` : ''}
            <div style="margin-top:2px">${stat}</div>
          </div>
          <i class="fa-solid fa-chevron-right" style="color:#cbd5e1;font-size:11px;margin-left:4px"></i>
        </div>`;
      }).join('');
  const headerHtml = `
    <div style="padding:14px 18px;border-bottom:1px solid #f1f5f9;background:linear-gradient(0deg, #fff 0%, ${cor}11 100%)">
      <div style="font-size:12px;color:${cor};font-weight:700;letter-spacing:.5px;text-transform:uppercase">${titulo}</div>
      <div style="font-size:24px;font-weight:700;color:${cor};margin-top:2px">${lista.length}</div>
      <div style="font-size:11px;color:#888;margin-top:2px">Clique em qualquer linha para abrir o cadastro do colaborador</div>
    </div>`;
  const html = `${headerHtml}<div style="max-height:60vh;overflow-y:auto">${linhasHtml}</div>`;
  _showFloatingModal('Mensagens', html);
}

// Clicar em linha do drill-down: fecha o modal flutuante e abre o cadastro
// do colaborador, ja' na aba "Comunicacoes".
function _comuAbrirRegistroDoCard(empId){
  const float = document.getElementById('modal-floating-disc');
  if(float) float.remove();
  if(!empId){ toast('Colaborador não identificado.','warning'); return; }
  openEmployeeModal(empId);
  // Espera o modal abrir e ja' alterna para a aba de Comunicacoes
  setTimeout(() => { try{ switchTab('tab-comunicacoes'); }catch(_){} }, 250);
}

// ===========================================================================
// AUTORIZACOES DE PONTO — historico de pedidos (Bloco D)
// ===========================================================================
// Espelha o padrao da secao Comunicacao: cards stats clicaveis + filtros +
// lista enxuta. Carrega de "autorizacoesPonto" e mostra com filtros.
let _autzCache    = null;
let _autzFiltros  = { busca:'', status:'todos', periodo:'30' };
let _autzCarregando = false;

async function renderAutorizacoesSection(){
  const box = document.getElementById('autorizacoes-content');
  if(!box) return;
  if(!_autzCache && !_autzCarregando){
    _autzCarregando = true;
    box.innerHTML = '<div style="text-align:center;padding:40px;color:#666"><i class="fa-solid fa-spinner fa-spin"></i> Carregando autorizações...</div>';
    try{
      const snap = await DB.col('autorizacoesPonto').get();
      _autzCache = snap.docs.map(d => ({ id:d.id, ...d.data() }));
    }catch(e){
      console.error('autz:fetch', e);
      _autzCache = [];
      toast('Erro ao carregar: '+(e.message||e),'error');
    }
    _autzCarregando = false;
  }
  _renderAutzUI();
}

async function atualizarAutorizacoesSection(){
  _autzCache = null;
  await renderAutorizacoesSection();
  toast('Lista atualizada.','success');
}

function _autzSetFiltro(key, val){
  _autzFiltros[key] = val;
  _renderAutzUI();
}

function _renderAutzUI(){
  const box = document.getElementById('autorizacoes-content');
  if(!box) return;
  const todos = _autzCache || [];
  const D = 86400000;
  const agora = Date.now();
  const dias  = parseInt(_autzFiltros.periodo||'30',10);
  const busca = (_autzFiltros.busca||'').trim().toLowerCase();
  // Escopo: supervisor com postosResponsavel só vê pedidos de colaboradores dos
  // postos dele. Master / sem restrição vê tudo.
  const escopo = _postosDoUsuario(Auth.currentUser);
  const empIdsNoEscopo = escopo
    ? new Set(_filtrarEmpsPorEscopo(State.employees).map(e=>e.id))
    : null;
  const filtradas = todos.filter(p => {
    if(empIdsNoEscopo && !empIdsNoEscopo.has(p.employeeId)) return false;
    if(dias > 0 && p.tentativaEm){
      const dt = new Date(p.tentativaEm).getTime();
      if(isFinite(dt) && (agora-dt) > dias*D) return false;
    }
    if(_autzFiltros.status !== 'todos' && p.status !== _autzFiltros.status) return false;
    if(busca){
      const blob = `${p.employeeNome||''} ${p.employeeRegistro||''} ${p.autorizadoPorNome||''} ${p.motivo||''}`.toLowerCase();
      if(!blob.includes(busca)) return false;
    }
    return true;
  });
  filtradas.sort((a,b) => (b.tentativaEm||'').localeCompare(a.tentativaEm||''));
  // Stats
  const cnt = {
    todos: filtradas.length,
    pendente: filtradas.filter(p=>p.status==='pendente').length,
    autorizada: filtradas.filter(p=>p.status==='autorizada').length,
    recusada: filtradas.filter(p=>p.status==='recusada').length,
    expirada: filtradas.filter(p=>p.status==='expirada' || p.status==='cancelada').length,
  };
  const fmtDt = iso => { const d=iso?new Date(iso):null; if(!d||isNaN(d.getTime())) return '—'; return d.toLocaleDateString('pt-BR') + ' ' + d.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'}); };
  const NOMES = {entrada:'Entrada', intIni:'Início intervalo', intFim:'Fim intervalo', saida:'Saída'};
  // Header
  const headerHtml = `
    <div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:10px;margin-bottom:18px">
      <div>
        <h2 style="margin:0;font-size:20px;color:var(--text)"><i class="fa-solid fa-user-shield" style="color:#1976D2"></i> Autorizações de Ponto</h2>
        <div style="font-size:12px;color:#888;margin-top:4px">Histórico de pedidos de batida fora do horário previsto. Auditoria completa.</div>
      </div>
      <div style="display:flex;gap:8px;flex-wrap:wrap">
        <button class="btn btn-outline" onclick="atualizarAutorizacoesSection()" title="Recarregar do banco"><i class="fa-solid fa-rotate"></i> Atualizar</button>
        <button class="btn btn-outline" onclick="_autzImprimir()" title="Imprimir / salvar PDF do filtro atual"><i class="fa-solid fa-file-pdf"></i> Gerar PDF</button>
      </div>
    </div>`;
  // Cards stats — clicaveis (filtram por status)
  const _cardStyle = `background:#fff;border:1px solid var(--border);border-radius:10px;padding:14px;text-align:center;cursor:pointer;transition:transform .15s ease,box-shadow .15s ease`;
  const _cardHover = `onmouseover="this.style.transform='translateY(-2px)';this.style.boxShadow='0 6px 14px rgba(0,0,0,.08)';" onmouseout="this.style.transform='';this.style.boxShadow='';"`;
  const cardClick = st => `onclick="_autzSetFiltro('status','${st}')"`;
  const ativo = (st) => _autzFiltros.status===st ? `outline:3px solid var(--primary);outline-offset:-3px;` : '';
  const statsHtml = `
    <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(150px,1fr));gap:12px;margin-bottom:18px">
      <div style="${_cardStyle};border-top:3px solid #1976D2;${ativo('todos')}" ${_cardHover} ${cardClick('todos')}>
        <div style="font-size:24px;font-weight:700;color:#1976D2">${cnt.todos}</div>
        <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:.4px">Todos (filtro)</div>
      </div>
      <div style="${_cardStyle};border-top:3px solid #E65100;${ativo('pendente')}" ${_cardHover} ${cardClick('pendente')}>
        <div style="font-size:24px;font-weight:700;color:#E65100">${cnt.pendente}</div>
        <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:.4px">Pendentes</div>
      </div>
      <div style="${_cardStyle};border-top:3px solid #16a34a;${ativo('autorizada')}" ${_cardHover} ${cardClick('autorizada')}>
        <div style="font-size:24px;font-weight:700;color:#16a34a">${cnt.autorizada}</div>
        <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:.4px">Autorizadas</div>
      </div>
      <div style="${_cardStyle};border-top:3px solid #c62828;${ativo('recusada')}" ${_cardHover} ${cardClick('recusada')}>
        <div style="font-size:24px;font-weight:700;color:#c62828">${cnt.recusada}</div>
        <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:.4px">Recusadas</div>
      </div>
      <div style="${_cardStyle};border-top:3px solid #94a3b8;${ativo('expirada')}" ${_cardHover} ${cardClick('expirada')}>
        <div style="font-size:24px;font-weight:700;color:#94a3b8">${cnt.expirada}</div>
        <div style="font-size:11px;color:#888;text-transform:uppercase;letter-spacing:.4px">Expiradas/Canceladas</div>
      </div>
    </div>`;
  // Filtros
  const filtrosHtml = `
    <div style="background:#f8fafc;border:1px solid var(--border);border-radius:10px;padding:14px;margin-bottom:18px">
      <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(200px,1fr));gap:12px;align-items:end">
        <div>
          <label style="font-size:12px;color:#475569;display:block;margin-bottom:4px">Buscar</label>
          <input type="text" id="autz-busca" placeholder="Colaborador, matrícula, supervisor, motivo..." value="${(_autzFiltros.busca||'').replace(/"/g,'&quot;')}" oninput="_autzSetFiltro('busca', this.value)" style="width:100%;padding:8px;border:1px solid var(--border);border-radius:6px;font-size:13px">
        </div>
        <div>
          <label style="font-size:12px;color:#475569;display:block;margin-bottom:4px">Período</label>
          <select onchange="_autzSetFiltro('periodo', this.value)" style="width:100%;padding:8px;border:1px solid var(--border);border-radius:6px;font-size:13px">
            <option value="7"   ${_autzFiltros.periodo==='7'?'selected':''}>Últimos 7 dias</option>
            <option value="30"  ${_autzFiltros.periodo==='30'?'selected':''}>Últimos 30 dias</option>
            <option value="90"  ${_autzFiltros.periodo==='90'?'selected':''}>Últimos 90 dias</option>
            <option value="365" ${_autzFiltros.periodo==='365'?'selected':''}>Último ano</option>
            <option value="0"   ${_autzFiltros.periodo==='0'?'selected':''}>Tudo</option>
          </select>
        </div>
      </div>
    </div>`;
  // Lista
  let listaHtml;
  if(!filtradas.length){
    listaHtml = `<div class="empty-state"><i class="fa-solid fa-shield-halved"></i><p>Nenhuma autorização com este filtro.</p></div>`;
  } else {
    listaHtml = filtradas.map(p => {
      const corStatus = p.status==='pendente'   ? '#E65100'
                      : p.status==='autorizada' ? '#16a34a'
                      : p.status==='recusada'   ? '#c62828'
                      : '#94a3b8';
      const lblStatus = p.status==='pendente'  ? 'PENDENTE'
                      : p.status==='autorizada'? 'AUTORIZADA'
                      : p.status==='recusada'  ? 'RECUSADA'
                      : p.status==='expirada'  ? 'EXPIRADA'
                      : 'CANCELADA';
      const diff = p.diferencaMinutos || 0;
      const diffTxt = diff===0 ? '' :
        diff > 0 ? `+${diff} min` : `${diff} min`;
      const empCad = State.employees.find(e => e.id === p.employeeId);
      const nomeLink = empCad
        ? `<a href="javascript:void(0)" onclick="openEmployeeModal('${p.employeeId}')" style="color:var(--primary);text-decoration:none;border-bottom:1px dotted var(--primary)">${(p.employeeNome||'—').replace(/</g,'&lt;')}</a>`
        : ((p.employeeNome||'—').replace(/</g,'&lt;'));
      const matr = p.employeeRegistro ? String(p.employeeRegistro).padStart(4,'0') : '—';
      const motivoBox = p.motivo
        ? `<div style="background:#fffbeb;border:1px solid #fde68a;border-radius:6px;padding:7px 9px;margin-top:7px;font-size:12px;color:#713f12"><strong>📝 Motivo do colaborador:</strong> ${(p.motivo||'').replace(/</g,'&lt;')}</div>`
        : '';
      const recusaBox = (p.status==='recusada' && p.motivoRecusa)
        ? `<div style="background:#fee2e2;border:1px solid #fca5a5;border-radius:6px;padding:7px 9px;margin-top:7px;font-size:12px;color:#7f1d1d"><strong>❌ Motivo da recusa:</strong> ${(p.motivoRecusa||'').replace(/</g,'&lt;')}</div>`
        : '';
      const supBox = (p.autorizadoPorNome)
        ? `<div style="font-size:11px;color:#666;margin-top:6px">${p.status==='autorizada'?'✅ Autorizado':'❌ Recusado'} por <strong>${p.autorizadoPorNome}</strong>${p.autorizadoEm?' em '+fmtDt(p.autorizadoEm):''}</div>`
        : '';
      return `<div style="background:#fff;border:1px solid var(--border);border-left:4px solid ${corStatus};border-radius:8px;padding:12px 14px;margin-bottom:10px">
        <div style="display:flex;justify-content:space-between;align-items:flex-start;flex-wrap:wrap;gap:10px">
          <div style="flex:1;min-width:0">
            <div style="font-weight:700;font-size:14px;color:var(--text)">${nomeLink}</div>
            <div style="font-size:11px;color:#888;margin-top:2px">Matrícula ${matr}${p.employeeCpf?' · CPF '+p.employeeCpf:''}</div>
          </div>
          <span style="background:${corStatus};color:#fff;padding:3px 10px;border-radius:12px;font-size:10px;font-weight:700;letter-spacing:.4px">${lblStatus}</span>
        </div>
        <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(120px,1fr));gap:8px;margin-top:8px;background:#f8fafc;border-radius:6px;padding:9px">
          <div><div style="font-size:10px;color:#94a3b8;text-transform:uppercase;letter-spacing:.4px;font-weight:600">Batida</div><div style="font-size:13px;color:var(--text);font-weight:600">${NOMES[p.tipoBatida]||p.tipoBatida||'—'}</div></div>
          <div><div style="font-size:10px;color:#94a3b8;text-transform:uppercase;letter-spacing:.4px;font-weight:600">Hora real</div><div style="font-size:13px;color:var(--text);font-weight:600">${p.horarioReal||'—'}</div></div>
          ${p.horarioPrevisto ? `<div><div style="font-size:10px;color:#94a3b8;text-transform:uppercase;letter-spacing:.4px;font-weight:600">Previsto</div><div style="font-size:13px;color:var(--text);font-weight:600">${p.horarioPrevisto}</div></div>` : ''}
          ${diffTxt ? `<div><div style="font-size:10px;color:#94a3b8;text-transform:uppercase;letter-spacing:.4px;font-weight:600">Diferença</div><div style="font-size:13px;font-weight:600;color:${diff>0?'#c62828':'#1976D2'}">${diffTxt}</div></div>` : ''}
          ${p.ehFolga ? `<div><div style="font-size:10px;color:#94a3b8;text-transform:uppercase;letter-spacing:.4px;font-weight:600">Folga</div><div style="font-size:13px;font-weight:600;color:#7e22ce">SIM</div></div>` : ''}
        </div>
        ${motivoBox}
        ${recusaBox}
        ${supBox}
        <div style="font-size:11px;color:#888;margin-top:6px">⏱ Solicitado em ${fmtDt(p.tentativaEm)}</div>
      </div>`;
    }).join('');
  }
  box.innerHTML = headerHtml + statsHtml + filtrosHtml + listaHtml;
  // mantem foco no input de busca (perdido pelo innerHTML)
  if(_autzFiltros.busca){
    const el = document.getElementById('autz-busca');
    if(el){ el.focus(); el.setSelectionRange(el.value.length, el.value.length); }
  }
}

// Imprime/salva PDF do filtro atual — abre janela nova em paisagem
function _autzImprimir(){
  const box = document.getElementById('autorizacoes-content');
  if(!box) return;
  const cont = box.innerHTML;
  const empresa = _e('nomeEmpresa');
  const data = new Date().toLocaleString('pt-BR');
  const html = `<!DOCTYPE html><html lang="pt-BR"><head>
<meta charset="UTF-8"><title>Autorizações de Ponto</title>
<style>
  @page{size:A4 landscape;margin:12mm 14mm}
  *{box-sizing:border-box;margin:0;padding:0}
  body{font-family:Arial,sans-serif;font-size:11px;color:#222}
  .ph{display:flex;align-items:center;gap:12px;border-bottom:2px solid #1976D2;padding-bottom:8px;margin-bottom:12px}
  .ph img{width:44px;height:44px;border-radius:50%}
  .ph h2{color:#1976D2;font-size:14px;font-weight:700}
  .ph p{color:#666;font-size:10px;margin-top:2px}
  .pm{margin-left:auto;text-align:right;font-size:9px;color:#888}
  /* Esconde botoes e elementos interativos no print */
  button,input,select,a[onclick]{display:none !important}
  .empty-state{text-align:center;padding:30px;color:#94a3b8}
</style></head><body>
<div class="ph">
  <img src="logo.png" alt="">
  <div><h2>${empresa.replace(/</g,'&lt;')}</h2><p>Autorizações de Ponto — Gerado em ${data}</p></div>
</div>
${cont}
</body></html>`;
  const win = window.open('','_blank');
  if(!win){ toast('Permita pop-ups para imprimir.','warning'); return; }
  win.document.write(html + '<scr'+'ipt>window.onload=function(){window.print();window.onafterprint=function(){window.close();}}<\/scr'+'ipt>');
  win.document.close();
}

// 1. Financeiro Mensal
function _reportFinanceiro(){
  const mes=parseInt(val('report-mes')), ano=parseInt(val('report-ano'));
  if(!mes||!ano){ toast('Selecione mês e ano.','error'); return; }
  const statusFilter=val('report-status-filter')||'all';
  // Escopo de postos (supervisor): mantém só payrolls dos colaboradores no escopo
  const empIdsNoEscopo=new Set(_filtrarEmpsPorEscopo(State.employees).map(e=>e.id));
  let records=State.payrolls.filter(p=>p.mes===mes&&p.ano===ano && empIdsNoEscopo.has(p.employeeId));
  if(statusFilter!=='all') records=records.filter(p=>{
    const emp=State.employees.find(e=>e.id===p.employeeId);
    return emp&&(emp.status||'ativo')===statusFilter;
  });
  _reportHeader('Relatório Financeiro Mensal', `${MESES[mes]} / ${ano}`);
  const tR=records.reduce((s,p)=>s+(p.remuneracao||0),0);
  const tVT=records.reduce((s,p)=>s+(p.valeTransporte||0),0);
  const tVR=records.reduce((s,p)=>s+(p.valeRefeicao||0),0);
  const tVA=records.reduce((s,p)=>s+(p.valeAlimentacaoLiquido||0),0);
  const tAN=records.reduce((s,p)=>s+(p.adNoturno||0),0);
  const tB=records.reduce((s,p)=>s+(p.bonificacao||0),0);
  const tTotal=tR+tVT+tVR+tVA+tAN+tB;
  document.getElementById('report-summary').innerHTML=`
    <div class="r-stat-card"><div class="r-stat-value">${records.length}</div><div class="r-stat-label">Colaboradores</div></div>
    <div class="r-stat-card"><div class="r-stat-value">${fmtMoney(tR)}</div><div class="r-stat-label">Remuneração</div></div>
    <div class="r-stat-card"><div class="r-stat-value">${fmtMoney(tVT)}</div><div class="r-stat-label">Vale Transporte</div></div>
    <div class="r-stat-card"><div class="r-stat-value">${fmtMoney(tVR)}</div><div class="r-stat-label">Vale Refeição</div></div>
    <div class="r-stat-card"><div class="r-stat-value">${fmtMoney(tVA)}</div><div class="r-stat-label">Vale Alimentação</div></div>
    <div class="r-stat-card" style="border-color:var(--primary)"><div class="r-stat-value" style="color:var(--primary)">${fmtMoney(tTotal)}</div><div class="r-stat-label">Total Geral</div></div>`;
  const cols=['#','Colaborador','Setor','Escala','Dias','Faltas','Remuneração','VT','VR','VA Líq.','Ad. Noturno','Bonificação','Chave PIX'];
  const rows=records.length===0?`<tr><td colspan="13" style="text-align:center;padding:24px;color:var(--text-muted)">Nenhum lançamento neste período</td></tr>`:
    records.map((p,i)=>{
      const emp=State.employees.find(e=>e.id===p.employeeId);
      const nome=emp?emp.nome:'(removido)', pix=emp?(emp.chavePix||'—'):'—';
      const escala=emp?escalaLabel(emp.escala||'5x2A'):'—', setor=emp?(emp.setor||'—'):'—';
      const totalFaltas='faltasJustificadas' in p?(p.faltasJustificadas||0)+(p.faltasInjustificadas||0):(p.faltas||0);
      return `<tr><td>${i+1}</td><td><strong>${nome}</strong></td><td>${setor}</td><td>${escala}</td>
        <td>${p.diasTrabalhados}</td><td>${totalFaltas}</td><td>${fmtMoney(p.remuneracao)}</td>
        <td>${fmtMoney(p.valeTransporte)}</td><td>${fmtMoney(p.valeRefeicao)}</td>
        <td>${fmtMoney(p.valeAlimentacaoLiquido||0)}</td><td>${fmtMoney(p.adNoturno||0)}</td>
        <td>${fmtMoney(p.bonificacao||0)}</td><td>${pix}</td></tr>`;
    }).join('');
  const tfoot=`<tr><td colspan="6">TOTAIS</td><td>${fmtMoney(tR)}</td><td>${fmtMoney(tVT)}</td><td>${fmtMoney(tVR)}</td><td>${fmtMoney(tVA)}</td><td>${fmtMoney(tAN)}</td><td>${fmtMoney(tB)}</td><td></td></tr>`;
  document.getElementById('report-body-area').innerHTML=_empTable(cols,rows,tfoot);
}

// 1b. Folha de Benefícios — VT, VR, VA e Bonificação por colaborador.
// Todos os valores vêm de dados já alimentados no sistema (Folha de Ponto).
function _reportBeneficios(){
  const mes=parseInt(val('report-benef-mes')), ano=parseInt(val('report-benef-ano'));
  if(!mes||!ano){ toast('Selecione mês e ano.','error'); return; }
  const folha=val('report-benef-folha')||'consolidado';
  const statusFilter=val('report-benef-status')||'ativo';

  let emps=_filtrarEmpsPorEscopo(State.employees).slice();
  if(statusFilter!=='all') emps=emps.filter(e=>(e.status||'ativo')===statusFilter);
  emps.sort((a,b)=>(a.nome||'').localeCompare(b.nome||'','pt-BR'));

  // Cruza cada colaborador com a folha de pagamento lançada do mês/ano.
  const linhas=emps.map(e=>{
    const p=State.payrolls.find(r=>r.employeeId===e.id&&r.mes===mes&&r.ano===ano);
    return {
      emp:e, temFolha:!!p,
      vt:p?(p.valeTransporte||0):0,
      vr:p?(p.valeRefeicao||0):0,
      va:p?(p.valeAlimentacaoLiquido||0):0,
      bon:p?(p.bonificacao||0):0
    };
  });

  const FOLHAS={
    consolidado:'Consolidada — Todos os Benefícios',
    vales:'Vales — VT + VR + VA',
    vt:'Vale-Transporte (VT)',
    vr:'Vale-Refeição (VR)',
    va:'Vale-Alimentação (VA)',
    bonificacao:'Bonificação'
  };
  _reportHeader(`Folha de Benefícios — ${FOLHAS[folha]||FOLHAS.consolidado}`, `${MESES[mes]} / ${ano}`);

  const tVT=linhas.reduce((s,l)=>s+l.vt,0);
  const tVR=linhas.reduce((s,l)=>s+l.vr,0);
  const tVA=linhas.reduce((s,l)=>s+l.va,0);
  const tBon=linhas.reduce((s,l)=>s+l.bon,0);
  const semFolha=linhas.filter(l=>!l.temFolha).length;

  // Total da folha selecionada
  let totFolha;
  if(folha==='vt') totFolha=tVT;
  else if(folha==='vr') totFolha=tVR;
  else if(folha==='va') totFolha=tVA;
  else if(folha==='bonificacao') totFolha=tBon;
  else if(folha==='vales') totFolha=tVT+tVR+tVA;
  else totFolha=tVT+tVR+tVA+tBon;

  // Cartões-resumo
  let cards=`<div class="r-stat-card"><div class="r-stat-value">${linhas.length}</div><div class="r-stat-label">Colaboradores</div></div>`;
  if(folha==='consolidado'||folha==='vales'||folha==='vt')
    cards+=`<div class="r-stat-card"><div class="r-stat-value">${fmtMoney(tVT)}</div><div class="r-stat-label">Vale Transporte</div></div>`;
  if(folha==='consolidado'||folha==='vales'||folha==='vr')
    cards+=`<div class="r-stat-card"><div class="r-stat-value">${fmtMoney(tVR)}</div><div class="r-stat-label">Vale Refeição</div></div>`;
  if(folha==='consolidado'||folha==='vales'||folha==='va')
    cards+=`<div class="r-stat-card"><div class="r-stat-value">${fmtMoney(tVA)}</div><div class="r-stat-label">Vale Alimentação</div></div>`;
  if(folha==='consolidado'||folha==='bonificacao')
    cards+=`<div class="r-stat-card"><div class="r-stat-value">${fmtMoney(tBon)}</div><div class="r-stat-label">Bonificação</div></div>`;
  cards+=`<div class="r-stat-card" style="border-color:var(--primary)"><div class="r-stat-value" style="color:var(--primary)">${fmtMoney(totFolha)}</div><div class="r-stat-label">Total da Folha</div></div>`;
  if(semFolha>0)
    cards+=`<div class="r-stat-card" style="border-color:#e65100"><div class="r-stat-value" style="color:#e65100">${semFolha}</div><div class="r-stat-label">Sem folha lançada</div></div>`;
  document.getElementById('report-summary').innerHTML=cards;

  // Tabela conforme a folha selecionada
  const muted='<span style="color:#94a3b8">—</span>';
  const cellVal=(l,v)=>l.temFolha?fmtMoney(v):muted;
  const nomeCell=l=>`<strong>${l.emp.nome||'—'}</strong>`+
    (l.temFolha?'':' <span style="color:#e65100;font-size:11px;font-weight:600">• folha não lançada</span>');
  const setorTd=l=>`<td>${l.emp.setor||'—'}</td>`;
  const postoTd=l=>`<td style="font-size:11px">${l.emp.posto||'—'}</td>`;
  let cols, rows, tfoot, moneyFrom;

  if(folha==='consolidado'){
    cols=['#','Colaborador','Setor','Posto','VT','VR','VA','Bonificação','Total'];
    moneyFrom=6;
    rows=linhas.length? linhas.map((l,i)=>{
      const tot=l.vt+l.vr+l.va+l.bon;
      return `<tr><td>${i+1}</td><td>${nomeCell(l)}</td>${setorTd(l)}${postoTd(l)}<td>${cellVal(l,l.vt)}</td><td>${cellVal(l,l.vr)}</td><td>${cellVal(l,l.va)}</td><td>${cellVal(l,l.bon)}</td><td><strong>${l.temFolha?fmtMoney(tot):muted}</strong></td></tr>`;
    }).join('') : `<tr><td colspan="9" style="text-align:center;padding:24px;color:var(--text-muted)">Nenhum colaborador encontrado</td></tr>`;
    tfoot=`<tr><td></td><td></td><td><strong>TOTAIS</strong></td><td></td><td></td><td>${fmtMoney(tVT)}</td><td>${fmtMoney(tVR)}</td><td>${fmtMoney(tVA)}</td><td>${fmtMoney(tBon)}</td><td><strong>${fmtMoney(tVT+tVR+tVA+tBon)}</strong></td></tr>`;
  } else if(folha==='vales'){
    cols=['#','Colaborador','Setor','Posto','VT','VR','VA','Total Vales'];
    moneyFrom=6;
    rows=linhas.length? linhas.map((l,i)=>{
      const tot=l.vt+l.vr+l.va;
      return `<tr><td>${i+1}</td><td>${nomeCell(l)}</td>${setorTd(l)}${postoTd(l)}<td>${cellVal(l,l.vt)}</td><td>${cellVal(l,l.vr)}</td><td>${cellVal(l,l.va)}</td><td><strong>${l.temFolha?fmtMoney(tot):muted}</strong></td></tr>`;
    }).join('') : `<tr><td colspan="8" style="text-align:center;padding:24px;color:var(--text-muted)">Nenhum colaborador encontrado</td></tr>`;
    tfoot=`<tr><td></td><td></td><td><strong>TOTAIS</strong></td><td></td><td></td><td>${fmtMoney(tVT)}</td><td>${fmtMoney(tVR)}</td><td>${fmtMoney(tVA)}</td><td><strong>${fmtMoney(tVT+tVR+tVA)}</strong></td></tr>`;
  } else {
    const cfg={
      vt:{lbl:'Vale-Transporte', pick:l=>l.vt},
      vr:{lbl:'Vale-Refeição',   pick:l=>l.vr},
      va:{lbl:'Vale-Alimentação',pick:l=>l.va},
      bonificacao:{lbl:'Bonificação', pick:l=>l.bon}
    }[folha];
    const quinta = folha==='bonificacao' ? 'Chave PIX' : 'Escala';
    cols=['#','Colaborador','Setor','Posto',quinta,cfg.lbl];
    moneyFrom=7;
    let tot=0;
    rows=linhas.length? linhas.map((l,i)=>{
      const v=cfg.pick(l); tot+=v;
      const q = folha==='bonificacao' ? (l.emp.chavePix||'—') : escalaLabel(l.emp.escala||'5x2A');
      return `<tr><td>${i+1}</td><td>${nomeCell(l)}</td>${setorTd(l)}${postoTd(l)}<td>${q}</td><td><strong>${cellVal(l,v)}</strong></td></tr>`;
    }).join('') : `<tr><td colspan="6" style="text-align:center;padding:24px;color:var(--text-muted)">Nenhum colaborador encontrado</td></tr>`;
    tfoot=`<tr><td></td><td></td><td><strong>TOTAL</strong></td><td></td><td></td><td></td><td><strong>${fmtMoney(tot)}</strong></td></tr>`;
  }
  // Alinhamento: coluna # centralizada e colunas de valores à direita —
  // aplica-se ao cabeçalho, ao corpo e à linha de totais (tudo alinhado).
  const alinha=`<style>#report-main-table td:nth-child(2),#report-main-table th:nth-child(2){text-align:center}`+
    `#report-main-table td:nth-child(n+${moneyFrom}),#report-main-table th:nth-child(n+${moneyFrom}){text-align:right;white-space:nowrap}</style>`;
  // Repete a barra de cabeçalho no rodapé, logo acima da linha de totais,
  // para o usuário identificar a qual benefício cada total se refere.
  const headRepeat=`<tr>${['',...cols].map(c=>`<th>${c}</th>`).join('')}</tr>`;
  document.getElementById('report-body-area').innerHTML=alinha+_empTable(cols,rows,headRepeat+tfoot);
}

